enum FieldDataTypes {
  "boolean" = "boolean",
  "text" = "text",
  "percent" = "percent",
  "date" = "date",
  "numeric" = "numeric",
}

export const getLogicalExpressionFunc = (
  fieldRecord: DdxField,
  comparisonOperator: string,
  value: string | string[] | null,
  value2: string | null,
  valueType: string
) => {
  console.log(
    `1 -- > ${comparisonOperator} --> ${isPassThroughCode(comparisonOperator)}`
  );
  if (value) {
    if (
      isPassThroughCode(
        Array.isArray(value) ? value[0].toString() : value.toString()
      )
    ) {
      value = Array.isArray(value) ? value[0].toString() : value.toString();
      if (isRangeOperator(comparisonOperator) && value2) {
        value += " AND " + value2.toString();
      }
      if (isMultiValueOperator(comparisonOperator)) {
        value = "(" + value + ")";
      }
    } else {
      if (valueType === "F") {
        if (isRangeOperator(comparisonOperator) && value2) {
          value = "[" + value + "] AND [" + value2 + "]";
        } else {
          value = "[" + value + "]";
        }
      } else {
        switch (fieldRecord?.data_type?.toLowerCase()) {
          case FieldDataTypes.boolean:
            value = value.toString();
            if (isRangeOperator(comparisonOperator) && value2) {
              value2 = value2.toString();
            }
            break;
          case FieldDataTypes.percent:
            value = value.toString();
            if (isRangeOperator(comparisonOperator) && value2) {
              value2 = value2.toString();
            }
            break;
          case FieldDataTypes.text:
            // put qoutes only for plain text fields, lookup ones already carry single qoutes
            if (!isMultiValueOperator(comparisonOperator)) {
              value = WrapWithInvisibleDelimiter(value);
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = WrapWithInvisibleDelimiter(value2);
              }
            } else {
              value = Array.isArray(value)
                ? value.map((item: string) => WrapWithInvisibleDelimiter(item))
                : WrapWithInvisibleDelimiter(value);
            }
            break;
          case FieldDataTypes.date:
            if (!isMultiValueOperator(comparisonOperator)) {
              value = WrapWithInvisibleDelimiter(
                new Date(value.toString()).toLocaleDateString()
              );
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = WrapWithInvisibleDelimiter(
                  new Date(value2.toString()).toLocaleDateString()
                );
              }
            }
            break;
          case FieldDataTypes.numeric:
            if (!isMultiValueOperator(comparisonOperator)) {
              value = value.toString();
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = value2.toString();
              }
            }
            break;
          default:
            if (fieldRecord?.lookup_type == null) {
              value = WrapWithInvisibleDelimiter(value);
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = WrapWithInvisibleDelimiter(value2);
              }
            }
        }
        if (isRangeOperator(comparisonOperator) && value2) {
          value = value + " AND " + value2;
        }
        // in case of multiple values, put the values inside ()
        if (isMultiValueOperator(comparisonOperator)) {
          value = "(" + value + ")";
        }
      }
    }
  }

  console.log(
    !isPassThroughCode(comparisonOperator)
      ? comparisonOperatorList.filter(
          (x: ConditionOperatorOptions) =>
            x.value === comparisonOperator?.trim()
        )[0]?.value
      : comparisonOperator
  );
  return (
    "[" +
    fieldRecord?.display_name +
    "]" +
    " " +
    (!isPassThroughCode(comparisonOperator)
      ? comparisonOperatorList.filter(
          (x: ConditionOperatorOptions) =>
            x.value === comparisonOperator?.trim()
        )[0]?.value
      : comparisonOperator) +
    " " +
    (value && !isNullCheckOperator(comparisonOperator) ? value : "")
  );
};

export const getValue = (
  comparisonOperator: string,
  value: string | string[] | null
) => {
  return value
    ? isMultiValueOperator(comparisonOperator) && typeof value === "object"
      ? value?.map((x) => WrapWithInvisibleDelimiter(x)).toString()
      : value?.toString()
    : null;
};

export const getFriendlyDescription = (expressions: Expression[]) => {
  return expressions
    .map((item) => ({
      ddx:
        item.logical_operator +
        " " +
        (item.open_parenthesis
          ? openParenthesisOptions?.filter(
              (x) => x.value === item.open_parenthesis.toString()
            )[0]?.displayText
          : "") +
        item.logical_expression +
        (item.close_parenthesis
          ? closeParenthesisOptions?.filter(
              (x) => x.value === item.close_parenthesis.toString()
            )[0]?.displayText
          : ""),
    }))
    .map((u) => u.ddx)
    .join(" ");
};

