                            label={"View Editor"}
                            sx={{ flex: "1 1 0px" }}
                            control={<Checkbox checked={isEditorEnabled} />}
                            onClick={(e) => {
                              e.preventDefault();
                              toggleEditor(setValues);
                              if (!isEditorEnabled) {
