import { FunctionComponent } from "react";
import {
  DataGridActionExportPDF,
  DataGridActionExportCSV,
  DataGridActionExportSpreadsheet,
  ActionMenu,
} from "@textile/biz-components";
import { DownloadIcon } from "@textile/common";
import { DataGridActionPopoverMenu } from "../data-grid-action-popover-menu.component";

export interface DownloadActionMenuProps {
  isPopover?: boolean;
}

export const DownloadActionMenu: FunctionComponent<DownloadActionMenuProps> = ({
  isPopover,
}) => {
  return isPopover ? (
    //should be wrapped in ActionMenu in the parent component to have action menu context
    <DataGridActionPopoverMenu label="Download">
      <DownloadActions />
    </DataGridActionPopoverMenu>
  ) : (
    <ActionMenu ariaLabel="Download Actions" icon={<DownloadIcon size={24} />}>
      <DownloadActions />
    </ActionMenu>
  );
};

export const DownloadActions: FunctionComponent = () => {
  return (
    <>
      <DataGridActionExportPDF type="menuitem" />
      <DataGridActionExportCSV type="menuitem" />
      <DataGridActionExportSpreadsheet
        type="menuitem"
        getExportOptions={() => {
          return {
            sheetName: "Sheet1",
          };
        }}
      ></DataGridActionExportSpreadsheet>
    </>
  );
};

