import { Box, SxProps, Theme, useTheme } from "@textile/mui";
import * as monaco from "monaco-editor";
import { FunctionComponent, useEffect, useMemo, useRef } from "react";
import { format } from "sql-formatter";

import { ddxConfig, ddxLanguage } from "./ddx";
import { DdxTranslationError } from "../../solvasam-bizcomponents";

const applyFormatRules = (value: string) => {
  return value
    ?.replace(/\(\n\s*/g, "(")
    ?.replace(/\n\s*\)/g, ")")
    ?.replace(/\s+(AND|OR|AND NOT|OR NOT)\s+/g, "\n$1 ");
};

export const ddxFormatter = {
  format: (value: string) => {
    try {
      return applyFormatRules(
        format(value, {
          language: "transactsql",
          keywordCase: "preserve",
          denseOperators: true,
        })
      );
    } catch (err) {
      return applyFormatRules(value);
    }
  },
};

// eslint-disable-next-line @typescript-eslint/ban-ts-comment
// @ts-ignore
self.MonacoEnvironment = {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unused-vars
  getWorkerUrl: function () {
    return "/solvasam-bizcomponents/editor.worker.js";
  },
};

monaco.languages.register({ id: "ddx" });

monaco.languages.setLanguageConfiguration("ddx", ddxConfig);

monaco.languages.setMonarchTokensProvider("ddx", ddxLanguage);

monaco.editor.defineTheme("ddxTheme", {
  base: "vs",
  inherit: true,
  rules: [
    { token: "logicalOperator", foreground: "9E7331" },
    {
      token: "ddxField",
      foreground: "007CB0",
    },
    { token: "ddxRule", foreground: "a31515" },
    { token: "comparisonOperator", foreground: "000000" },
    { token: "invisibleDelimiterToken", foreground: "846cfc" },
    { token: "parameterPlaceholder", foreground: "2E7D32" },
    { token: "number", foreground: "846cfc" },
  ],
  colors: {
    "editor.foreground": "#000000",
  },
});

monaco.editor.setTheme("ddxTheme");

monaco.languages.registerDocumentFormattingEditProvider("ddx", {
  provideDocumentFormattingEdits(model) {
    const formatted = ddxFormatter.format(model.getValue());
    return [
      {
        range: model.getFullModelRange(),
        text: formatted,
      },
    ];
  },
});

monaco.languages.registerDocumentRangeFormattingEditProvider("ddx", {
  provideDocumentRangeFormattingEdits(model, range) {
    const formatted = ddxFormatter.format(model.getValueInRange(range));
    return [
      {
        range: range,
        text: formatted,
      },
    ];
  },
});

export interface MonacoEditorProps {
  initialValue?: string;
  monacoEditorOptions?: monaco.editor.IStandaloneEditorConstructionOptions;
  sx?: SxProps<Theme>;
  ddxTranslationErrors?: DdxTranslationError[];
  onChange?: (value: string) => void;
  getEditorRef?: (editorRef: monaco.editor.IStandaloneCodeEditor) => void;
}

export const MonacoEditor: FunctionComponent<MonacoEditorProps> = ({
  initialValue: value,
  sx,
  monacoEditorOptions,
  ddxTranslationErrors,
  onChange,
  getEditorRef,
}) => {
  const divEl = useRef<HTMLDivElement>(null);
  const editor = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const editorModel = useRef<monaco.editor.ITextModel | undefined>();
  const monacoChangeEvent = useRef<monaco.IDisposable>();
  const theme = useTheme();

  const monacoEditorSx = useMemo(
    () => ({
      maxWidth: "100%",
      backgroundColor: "#ffffff",
      ...sx,
    }),
    [sx]
  );

  const setErrors = (errors: DdxTranslationError[]) => {
    if (editor.current) {
      const model = editorModel.current;

      const markers: monaco.editor.IMarkerData[] = [];
      if (model && errors) {
        if (errors.length > 0) {
          for (let index = 0; index < errors.length; index++) {
            const error = errors[index];

            if (
              error.line &&
              error.line >= 0 &&
              error.char_position_in_line &&
              error.char_position_in_line >= 0
            ) {
              markers.push({
                message: error.message
                  ? `${error.message_code}:${error.message}`
                  : "",
                severity: monaco.MarkerSeverity.Error,
                startLineNumber: error.line,
                startColumn: error.char_position_in_line + 1,
                endLineNumber: error.line,
                endColumn:
                  error.char_position_in_line +
                  1 +
                  (error?.offending_symbol_text?.length ?? 3),
              });
            }
          }
          if (markers.length > 0) {
            monaco.editor.setModelMarkers(model, "owner", markers);
          }
        } else {
          monaco.editor.setModelMarkers(model, "owner", []);
        }
      }
    }
  };

  useEffect(() => {
    if (divEl.current) {
      const model: monaco.editor.IModel =
        !editorModel.current || editorModel.current?.isDisposed()
          ? monaco.editor.createModel(value ?? "", "ddx")
          : editorModel.current;

      editor.current = !editor.current
        ? monaco.editor.create(divEl.current, {
            model,
            fontFamily: theme.typography.fontFamily,
            guides: {
              indentation: false,
            },
            unicodeHighlight: { invisibleCharacters: false },
            ...monacoEditorOptions,
          })
        : editor.current;
      editorModel.current = model;
      model?.setValue(value ?? "");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [monacoEditorOptions, value]);

  useEffect(() => {
    if (onChange) {
      monacoChangeEvent.current = editor.current?.onDidChangeModelContent(
        () => {
          if (editor.current) {
            onChange(editor.current.getValue());
          }
        }
      );
    }
    if (getEditorRef && editor.current) {
      getEditorRef(editor.current);
    }

    return () => {
      monacoChangeEvent.current?.dispose();
    };
  }, [getEditorRef, onChange]);

  useEffect(() => {
    if (ddxTranslationErrors && ddxTranslationErrors?.length >= 0) {
      setErrors(ddxTranslationErrors);
    }
  }, [ddxTranslationErrors]);

  return <Box sx={monacoEditorSx} id="container" ref={divEl}></Box>;
};

