import * as monaco from "monaco-editor";
import { Button, Box, Paper, FormGroup, Typography } from "@textile/mui";
import { useState, useCallback, useRef } from "react";
import {
  DdxData,
  DdxTranslationError,
  ModelExpression,
  MonacoDdxEditor,
  RuleDisplayComponent,
  ddxFormatter,
  useExpressionValidator,
} from "../../solvasam-bizcomponents";

export const DdxEditorDetails = (props: {
  getFriendlyDescription: () => string;
  ddxProps: DdxData;
  getEditorRef: (editor: monaco.editor.IStandaloneCodeEditor) => void;
  isFormula?: boolean;
  errors?: DdxTranslationError[];
  exprDesc?: React.MutableRefObject<string>;
  onDdxToDetailsRef?: React.MutableRefObject<(() => void) | null>;
}) => {
  const {
    getFriendlyDescription,
    ddxProps,
    getEditorRef,
    isFormula,
    errors,
    exprDesc,
    onDdxToDetailsRef,
  } = props;

  const [showDetails, setShowDetails] = useState(false);

  const [modelExpr, setModelExpr] = useState<Partial<ModelExpression>>({
    friendly_description_expanded: null,
    ddx_expanded: null,
    raw_description: null,
    raw_description_expanded: null,
  });

  const { fetchHydrateExpression } = useExpressionValidator();

  const onDdxToDetails = async () => {
    setModelExpr({
      friendly_description_expanded: "",
      ddx_expanded: "",
      raw_description: "",
      raw_description_expanded: "",
    });
    //setShowDetailsCheck(true);
    const editorVal = edRef.current?.getValue() ?? "";
    if (exprDesc) {
      exprDesc.current = editorVal;
    }
    try {
      edRef?.current?.setValue(editorVal);
      const modelExpression = await fetchHydrateExpression(
        isFormula ? "FIELD_FORMULA" : "FILTER_EXPRESSION",
        editorVal,
        isFormula ? "value" : "bool"
      );
      setModelExpr(modelExpression);
      setShowDetails(true);

      if (modelExpression?.ddx_errors?.length) {
        setDdxErrors(modelExpression.ddx_errors);
      } else {
        setDdxErrors([]);
      }
    } catch (error) {
      setDdxErrors([
        { char_position_in_line: 0, line: 0, message: String(error) },
      ]);
    }
  };
  const edRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();

  const handleGetEditorRef = useCallback(
    (editor: monaco.editor.IStandaloneCodeEditor) => {
      edRef.current = editor;
      getEditorRef(editor);
    },

    [getEditorRef]
  );

  const [ddxErrors, setDdxErrors] = useState<DdxTranslationError[] | undefined>(
    errors
  );

  // Expose onDdxToDetails function to parent
  if (onDdxToDetailsRef) {
    onDdxToDetailsRef.current = onDdxToDetails;
  }
  return (
    <Box
      sx={{
        maxHeight: "60vh",
        overflow: "auto",
        pr: 3,
        flex: 1,
      }}
    >
      <Paper
        sx={{
          mt: 2,
          border: "1px groove",
        }}
      >
        <MonacoDdxEditor
          {...ddxProps}
          value={getFriendlyDescription()}
          ddxTranslationErrors={ddxErrors ?? undefined}
          editorOptions={{
            minimap: { enabled: false },
            unicodeHighlight: { invisibleCharacters: false },
          }}
          getEditorRef={handleGetEditorRef}
        />
      </Paper>

      <Box
        sx={{
          display: "flex",
          rowGap: "10px",
          flexDirection: "column",
          margin: "5px",
        }}
      >
        <FormGroup>
          {showDetails && (
            <>
              <Box
                sx={{
                  display: "flex",
                  padding: 2,
                  justifyContent: "space-between",
                }}
              >
                <Typography variant="body1" fontWeight={600}>
                  Details
                </Typography>
                <Button
                  variant="outlined"
                  onClick={() => {
                    setShowDetails((prev) => !prev);
                  }}
                >
                  Close
                </Button>
              </Box>
              <Paper elevation={3} sx={{ padding: 1 }}>
                <Box
                  sx={{
                    display: "grid",
                    gridTemplateColumns: "2fr 4fr",
                    rowGap: 1,
                    ml: 2,
                  }}
                >
                  <Box>Ddx:</Box>
                  <Box>
                    {modelExpr?.ddx && (
                      <RuleDisplayComponent
                        value={ddxFormatter.format(modelExpr?.ddx)}
                      ></RuleDisplayComponent>
                    )}
                  </Box>
                  <Box>Expanded Ddx:</Box>
                  <Box>
                    {modelExpr?.ddx_expanded && (
                      <RuleDisplayComponent
                        value={ddxFormatter.format(modelExpr?.ddx_expanded)}
                      ></RuleDisplayComponent>
                    )}
                  </Box>
                  <Box>Expanded Friendly Description:</Box>
                  <Box>
                    {modelExpr?.friendly_description_expanded && (
                      <RuleDisplayComponent
                        value={ddxFormatter.format(
                          modelExpr?.friendly_description_expanded
                        )}
                      ></RuleDisplayComponent>
                    )}
                  </Box>
                </Box>
              </Paper>
            </>
          )}
        </FormGroup>
      </Box>
    </Box>
  );
};

