import { Box, SxProps } from "@textile/mui";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import * as monaco from "monaco-editor";

import { MonacoEditor } from "../monaco-ddx-editor/monaco-editor.component";

interface RuleDisplayComponentProps {
  value?: string;
}

export const RuleDisplayComponent = (props: RuleDisplayComponentProps) => {
  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const [height, setHeight] = useState<string | null>(null);
  const monacoEditorSx = useMemo<SxProps>(
    () => ({
      minWidth: "100%",
      overflow: "hidden",
      display: "flex",
      height: { height },
      background: "#F4F4F4",
    }),
    [height]
  );

  const handleGetEditorRef = useCallback(
    (editor: monaco.editor.IStandaloneCodeEditor) => {
      editorRef.current = editor;
    },
    []
  );

  useEffect(() => {
    const updateHeight = () => {
      if (editorRef.current) {
        const contentHeight = Math.min(
          1000,
          editorRef.current.getContentHeight()
        );
        setHeight(`${contentHeight}px`);
      }
    };
    editorRef.current?.onDidContentSizeChange(updateHeight);
    updateHeight();
  }, [props.value]);

  editorRef?.current?.setValue(props.value ?? "");

  return (
