import { Box, SxProps } from "@textile/mui";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import * as monaco from "monaco-editor";

import { MonacoEditor } from "../monaco-ddx-editor/monaco-editor.component";
import {
  mapFieldToDdxSuggestion,
  mapFunctionToDdxSuggestion,
  useDdxValues,
} from "../monaco-ddx-editor";
import { MonacoHelper } from "../monaco-ddx-editor/monaco-helper";
import {
  hoverProvider,
  provideCompletionItems,
  signatureHelpProvider,
} from "../monaco-ddx-editor/ddx-helper";

interface RuleDisplayComponentProps {
  value?: string;
}

export const RuleDisplayComponent = (props: RuleDisplayComponentProps) => {
  const ddxData = useDdxValues();
  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const [height, setHeight] = useState<string | null>(null);
  const monacoEditorSx = useMemo<SxProps>(
    () => ({
      minWidth: "100%",
      overflow: "hidden",
      display: "flex",
      height: { height },
      background: "#F4F4F4",
    }),
    [height]
  );

  const handleGetEditorRef = useCallback(
    (editor: monaco.editor.IStandaloneCodeEditor) => {
      editorRef.current = editor;
    },
    []
  );

  useEffect(() => {
    const updateHeight = () => {
      if (editorRef.current) {
        const contentHeight = Math.min(
          1000,
          editorRef.current.getContentHeight()
        );
        setHeight(`${contentHeight}px`);
      }
    };
    editorRef.current?.onDidContentSizeChange(updateHeight);
    updateHeight();
  }, [props.value]);

  useEffect(() => {
    if (ddxData.ddxFields?.length > 0 && ddxData.ddxFunctions?.length > 0) {
      MonacoHelper.register(
        "ddx",
        {
          provideCompletionItems: provideCompletionItems(
            [
              ...ddxData.ddxFields?.map(mapFieldToDdxSuggestion),
              ...ddxData.ddxFunctions?.map(mapFunctionToDdxSuggestion),
            ],
            ddxData.fetchLookupItems,
            ddxData.fetchLookupTypes
          ),
          triggerCharacters: ["[", " ", "<"],
        },
        signatureHelpProvider([
          ...ddxData.ddxFields?.map(mapFieldToDdxSuggestion),
          ...ddxData.ddxFunctions?.map(mapFunctionToDdxSuggestion),
          {},
        ]),
        {
          provideHover: hoverProvider([
            ...ddxData.ddxFields?.map(mapFieldToDdxSuggestion),
            ...ddxData.ddxFunctions?.map(mapFunctionToDdxSuggestion),
          ]),
        }
      );
    }
  }, [ddxData]);

  editorRef?.current?.setValue(props.value ?? "");

  return (
    <Box sx={{ p: 1, flexGrow: 1, overflow: "hidden" }}>
      <MonacoEditor
        sx={monacoEditorSx}
        initialValue={props.value}
        monacoEditorOptions={{
          readOnly: true,
          lineNumbers: "off",
          lineDecorationsWidth: 0,
          lineNumbersMinChars: 0,
          minimap: { enabled: false },
          contextmenu: false,
          automaticLayout: true,
          scrollBeyondLastLine: false,
          wrappingStrategy: "advanced",
          overviewRulerLanes: 0,
          folding: false,
          roundedSelection: false,
          hideCursorInOverviewRuler: true,
          overviewRulerBorder: false,
          renderLineHighlight: "none",
          wordWrap: "on",
          wrappingIndent: "same",
          scrollbar: {
            vertical: "hidden",
            horizontal: "hidden",
            handleMouseWheel: false,
          },
        }}
        getEditorRef={handleGetEditorRef}
      />
    </Box>
  );
};

