                  Expression Builder
                  <Box sx={{ flexGrow: 1 }} />
                  <IconButton
                    sx={(theme) => ({
                      position: "absolute",
                      right: 52,
                      top: 8,
                      color: theme.palette.primary.contrastText,
                    })}
                    aria-label={
                      isFullScreen ? "Exit full screen" : "Enter full screen"
                    }
                    onClick={() => setIsFullScreen((prev) => !prev)}
                    size="small"
                  >
                    {isFullScreen ? <CollapseIcon /> : <ExpandIcon />}
                  </IconButton>
                  <IconButton
                    aria-label="close"
                    onClick={handleClose}
                    sx={(theme) => ({
                      position: "absolute",
                      right: 8,
                      top: 8,
                      color: theme.palette.primary.contrastText,
                    })}
                  >
                    <CloseIcon fontSize="large" />
                  </IconButton>
                </DialogTitle>
                <ProgressOrDivider isLoading={isSubmitting} />
                <ExpressionBuilderContextProvider
                  expression={gridExpression}
                  ddxData={ddxProps}
                  setState={setState}
                  values={values}
                  setValues={setValues}
                >
                  <DialogContent>
                    <Box sx={topBoxSx}>
                      <Box sx={shimBoxSx}></Box>
                      <ToolGroup>
                        <FormControlLabel
                          label={
                            isPassThrough
                              ? "View Editor (Disabled - Complex Rule)"
                              : "View Editor"
                          }
                          sx={{
                            flex: "1 1 0px",
                            opacity: isPassThrough ? 0.5 : 1,
                          }}
                          control={
                            <Checkbox
                              checked={isEditorEnabled}
                              disabled={isPassThrough}
                            />
                          }
                          onClick={(e) => {
                            e.preventDefault();
                            toggleEditor(setValues);
                            if (!isEditorEnabled) {
                              const expressions: Expression[] =
                                fieldValuesToExpressions(
                                  [...gridExpression],
                                  values,
                                  ddxProps
                                );
                              const exprDesc =
                                getFriendlyDescription(expressions);

                              exprDescription.current = exprDesc;
                              isEditorDirty.current = false;
                            }
                          }}
                        />

                        {!isEditorEnabled && !isComplexRule ? (
                          <>
                            <Divider orientation="vertical" flexItem></Divider>
                            {children}
                          </>
                        ) : (
                          <Button
                            variant="outlined"
                            onClick={() => onDdxToDetailsRef.current?.()}
                          >
                            Ddx to Details
                          </Button>
                        )}
                      </ToolGroup>
                    </Box>
                    {isEditorEnabled ? (
                      <>
                        <DdxEditorDetails
                          ddxProps={ddxProps}
                          getFriendlyDescription={getFriendlyDesc}
                          getEditorRef={handleGetEditorRef}
                          errors={ddxErrors}
                          exprDesc={exprDescription}
                          onDdxToDetailsRef={onDdxToDetailsRef}
                        ></DdxEditorDetails>
                      </>
                    ) : (
                      <Box
                        sx={{
                          flex: 1,
                          pb: 5,
                          maxHeight: "60vh",
                          overflow: "auto",
                        }}
                      >
                        <FormControl
                          fullWidth
                          sx={{
                            backgroundColor: theme.palette.primary.main,
                            color: theme.palette.primary.contrastText,
                          }}
                        >
                          <Stack direction="row">
                            <Typography
                              textAlign="center"
                              sx={{
                                display: "flex",
                                flex: "2 1 0",
                                py: 1,
                                pl: 1,
                              }}
                            >
                              S.No.
                            </Typography>
                            <Divider
                              orientation="vertical"
                              flexItem
                              sx={{
                                bgcolor: theme.palette.primary.contrastText,
                              }}
                            ></Divider>
                            <Typography
                              textAlign="center"
                              sx={{
                                display: "flex",
