                                            (item) => {
                                              return (
                                                item.data_type ===
                                                getDdxFieldByDisplayName(
                                                  ddxProps.ddxFields,
                                                  values["field_" + index]
                                                )[0]?.data_type
                                              );
                                            }
                                          )}
                                          required
                                        ></FormDdxFieldsGrid>
                                      ) : (
                                        <FormValueField
                                          id={"value2_" + index}
                                          dataType={
                                            getDdxFieldByDisplayName(
                                              ddxProps.ddxFields,
                                              values["field_" + index]
                                            )[0]?.data_type?.toUpperCase() ?? ""
                                          }
                                          textFieldProps={{
                                            label: "Value2",
                                            required: true,
                                          }}
                                        ></FormValueField>
                                      )
                                    ) : null}
                                  </Stack>
                                </Stack>
                                <Divider orientation="vertical" flexItem />

                                <FormAutocomplete
                                  fieldName={"close_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={closeParenthesisOptions}
                                  sx={{
                                    display: "flex",
                                    flex: "2 1 0",
                                    py: 2,
                                    pr: 1,
                                  }}
                                />
                              </DraggableExpression>
                            ) : (
                              <DraggableExpression index={index}>
                                <Divider orientation="vertical" flexItem />
                                <FormAutocomplete
                                  fieldName={"logical_operator_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  aria-label={"logical_operator_" + index}
                                  textFieldProps={{
                                    required: index !== 0,
                                  }}
                                  options={
                                    index === 0
                                      ? logicalOperatorOptionsFirstRow
                                      : logicalOperatorOptions
                                  }
                                  sx={{
                                    display: "flex",
                                    flex: "3 1 0",
                                    py: 2,
                                  }}
                                />
                                <Divider orientation="vertical" flexItem />
                                <FormAutocomplete
                                  fieldName={"open_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={openParenthesisOptions}
                                  sx={{
                                    display: "flex",
                                    flex: "2 1 0",
                                    py: 2,
                                  }}
                                />
                                <Divider orientation="vertical" flexItem />

                                {expression.logical_expression === "Rule" ? (
                                  <Button
                                    onClick={() => {
                                      setRuleToEdit(expression);
                                      setOpenRuleSelect(true);
                                    }}
                                    aria-label="Rule"
                                    sx={{ display: "flex", flex: "12 1 0" }}
                                  >
                                    {expression.logical_expression}
                                  </Button>
                                ) : (
                                  <Stack
                                    direction="column"
                                    sx={{
                                      display: "flex",
                                      flex: "12 1 0",
                                      py: 2,
                                      p: 1,
                                    }}
                                  >
                                    <Stack direction="row" spacing={1}>
                                      <Typography
                                        alignContent="center"
                                        sx={{
                                          display: "flex",
                                          flex: "20 1 0",
                                          fontWeight: expression.isRule
                                            ? 600
                                            : 400,
                                        }}
                                      >
                                        {expression.isRule
                                          ? ddxProps.ddxFunctions.find(
                                              (func) =>
                                                func.function_name.toLowerCase() ===
                                                expression?.logical_expression
                                                  ?.split("(")[0]
                                                  .toLowerCase()
                                            )?.function_name ?? ""
                                          : expression.logical_expression}
                                      </Typography>

                                      {expression.isRule && (
                                        <IconButton
                                          onClick={() => {
                                            setRuleToEdit(expression);
                                            setValues((prev) => {
                                              prev["expand_" + index] =
                                                "collapsed";

                                              return prev;
                                            });
                                            setOpenRuleSelect(true);
                                          }}
                                          sx={{ height: 2, width: 2 }}
                                          aria-label="edit"
                                        >
                                          <EditIcon fontSize="small"></EditIcon>
                                        </IconButton>
                                      )}
                                      {expression.isRule && (
                                        <IconButton
                                          sx={{ height: 2, width: 2, pl: 2 }}
                                          aria-label="expand"
                                          onClick={async () => {
                                            setValues((prev) => {
                                              prev["expand_" + index] =
                                                prev["expand_" + index] ===
                                                "collapsed"
                                                  ? "expanded"
                                                  : "collapsed";

                                              return prev;
                                            });

                                            if (
                                              !(index in hydratedExpressions)
                                            ) {
                                              const modelExp =
                                                await hydrateRuleExpression(
                                                  expression.logical_expression
                                                );

                                              setHydratedExpressions(
                                                (prev) => ({
                                                  ...prev,
                                                  [index]:
                                                    modelExp.friendly_description_expanded ??
                                                    "",
                                                })
                                              );
                                            }
                                          }}
                                        >
                                          {values["expand_" + index] ===
                                          "collapsed" ? (
                                            <ExpandIcon fontSize="small" />
                                          ) : (
                                            <CollapseIcon fontSize="small" />
                                          )}
                                        </IconButton>
                                      )}
                                    </Stack>
                                    {values["expand_" + index] ===
                                    "expanded" ? (
                                      index in hydratedExpressions ? (
                                        <RuleDisplayComponent
                                          value={
                                            hydratedExpressions[index] || ""
                                          }
                                        />
                                      ) : (
                                        <CircularProgress size={20} />
                                      )
                                    ) : null}
                                  </Stack>
                                )}
                                <Divider orientation="vertical" flexItem />
                                <FormAutocomplete
                                  fieldName={"close_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={closeParenthesisOptions}
                                  sx={{
                                    display: "flex",
                                    flex: "2 1 0",
                                    py: 2,
                                    pr: 1,
                                  }}
                                />
                              </DraggableExpression>
                            );
                          })}
                        </Box>
                      </Box>
                    )}
                  </DialogContent>
                  <SelectRuleDialog
                    open={openRuleSelect}
                    handleOnCloseButtonClick={function (): void {
                      setOpenRuleSelect(false);
                    }}
                    ddxProps={ddxProps}
                    expression={ruleToEdit ? ruleToEdit : undefined}
                    setHydratedExpressions={setHydratedExpressions}
                  ></SelectRuleDialog>
                </ExpressionBuilderContextProvider>
                {failed ? (
                  <Alert
                    severity="error"
                    onClose={() => {
                      setFailed(false);
                    }}
                  >
                    Error: Saving Expression
                  </Alert>
                ) : null}
                <Divider></Divider>
                <DialogActions sx={{ mt: 2 }}>
                  <Button variant="outlined" onClick={handleClose}>
                    Cancel
                  </Button>
                  <Button
                    variant="contained"
                    type="submit"
                    sx={{ width: 70, placeSelf: "end" }}
                  >
                    Save
                  </Button>
                </DialogActions>
              </form>
            </FormValidateField>
          )}
        </Formik>
      </Dialog>
    </Box>
  );
};

const isNumericOrDate = (val: string): boolean => {
  if (!val) return false;

  const trimmed = val.trim();

  const isNumeric = !isNaN(Number(trimmed));

  const isDate = !isNaN(Date.parse(trimmed));

  return isNumeric || isDate;
};

export const fieldValuesToExpressions = (
  expressions: Expression[],
  values: { [x: string]: string },
  ddxData: DdxData
) => {
  expressions.forEach((expression, index) => {
    expression.field = values["field_" + index];
    expression.open_parenthesis = parseInt(values["open_parenthesis_" + index]);
    expression.close_parenthesis = parseInt(
      values["close_parenthesis_" + index]
    );
    expression.comparison_operator = values["comparison_operator_" + index];

    expression.value =
      values["value_type_" + index] === "F" && values["value_" + index]
        ? "[" + values["value_" + index] + "]"
        : isMultiValueOperator(values["comparison_operator_" + index]) &&
          typeof values["value_" + index] === "object"
        ? JSON.parse(JSON.stringify(values["value_" + index]))
            .map((item: string) =>
              isNumericOrDate(item) ? item : WrapWithInvisibleDelimiter(item)
            )
            .join(",")
        : isNumericOrDate(values["value_" + index])
        ? values["value_" + index]
        : WrapWithInvisibleDelimiter(values["value_" + index]);

    expression.value2 =
      values["value_type_" + index] === "F" && values["value2_" + index]
        ? "[" + values["value2_" + index] + "]"
        : WrapWithInvisibleDelimiter(values["value2_" + index]);
    expression.logical_operator = values["logical_operator_" + index] ?? "";
    expression.logical_expression = values["field_" + index]
      ? getLogicalExpressionFunc(
          getDdxFieldByDisplayName(
            ddxData.ddxFields,
            values["field_" + index]
          )[0],
          values["comparison_operator_" + index],
          values["value_" + index],
          values["value2_" + index],
          values["value_type_" + index]
        )
      : expression.logical_expression;
    expression.line_number = index;
  });
  return expressions;
};

export const modelExpressionToExpressions = (
  modelExpression: ModelExpression,
  ddxField: DdxField[],
  ddxFunctions: DdxFunction[]
) => {
  return modelExpression?.logic?.map((item: ModelExpressionLogic) => ({
    line_number: item.line_number,
    logical_operator: item.logical_operator ? item.logical_operator : "",
    open_parenthesis: item.open_parenthesis ? item.open_parenthesis : 0,
    close_parenthesis: item.close_parenthesis ? item.close_parenthesis : 0,
    comparison_operator: item.comparison_operator
      ? item.comparison_operator
      : null,
    friendly_description: item.friendly_description
      ? item.friendly_description
      : null,
    field: item.display_name ?? null,
    isRule: Boolean(
      item.friendly_description &&
        ddxFunctions.find(
          (func) =>
            func.function_name.toLowerCase() ===
            item.friendly_description?.split("(")[0].toLowerCase()
        )?.is_rule
    ),

    value: unwrapValue(item.comparison_operator, item.comparison_value),
    value2: unwrapValue(item.comparison_operator, item.comparison_value2),
    logical_expression: item.field_name
      ? getLogicalExpressionFunc(
          ddxField?.filter((x) => x.field_name === item.field_name)[0],
          item.comparison_operator ? item.comparison_operator : "",
          replaceUniCodeForMultiValues(item.comparison_value),
          replaceUniCodeForSingleValue(item.comparison_value2),
          ""
        )
      : item.friendly_description
          ?.replace(item.logical_operator ?? "", "")
          ?.trim() ?? "",
  }));
};

const replaceSquareBrackets = (value: string | null) => {
  return value?.toString().includes("[")
    ? value.replaceAll("[", "").replaceAll("]", "")
    : value ?? "";
};

export const expressionToFieldValues = (expression: Expression[]) => {
  const fieldValues: { [x: string]: string } = {};
  expression.forEach((exp, index) => {
    fieldValues["order_" + index] = (index + 1).toString() ?? "";
    fieldValues["logical_operator_" + index] = exp.logical_operator ?? "";
    fieldValues["field_" + index] = exp.field ?? "";
    fieldValues["comparison_operator_" + index] = exp.comparison_operator ?? "";
    fieldValues["value_" + index] = replaceSquareBrackets(exp?.value);
    fieldValues["value2_" + index] = replaceSquareBrackets(exp.value2);
    fieldValues["open_parenthesis_" + index] =
      exp.open_parenthesis?.toString() ?? "";
    fieldValues["close_parenthesis_" + index] =
      exp.close_parenthesis?.toString() ?? "";
    fieldValues["logical_expression_" + index] = exp.logical_expression ?? "";
    fieldValues["expand_" + index] = "collapsed";
    fieldValues["value_type_" + index] = exp.value?.toString().includes("[")
      ? "F"
      : "V";
  });
  return fieldValues;
};

