import { AxiosResponse } from "axios";
import * as monaco from "monaco-editor";

import { DdxSuggestion } from "./ddx.types";
import {
  GetLookupItemsResponse,
  GetLookupTypesResponse,
} from "../common.types";
import {
  INVISIBLE_DELIMITER,
  WrapWithInvisibleDelimiter,
  isLikeOperator,
  isMultiValueOperator,
  isRangeOperator,
} from "../helpers";

type completionType = { suggestions: monaco.languages.CompletionItem[] };

const cardinalDataTypes = ["numeric", "date", "currency", "percent"];
const textDataTypes = ["text"];

const alwaysApplicable = () => true;

const cardinalApplicable = (fieldRecord?: DdxSuggestion) => {
  if (fieldRecord?.data_type) {
    return (
      cardinalDataTypes.indexOf(fieldRecord?.data_type?.toLowerCase()) !== -1
    );
  } else {
    return true;
  }
};

const textApplicable = (fieldRecord?: DdxSuggestion) => {
  if (fieldRecord?.data_type) {
    return textDataTypes.indexOf(fieldRecord?.data_type?.toLowerCase()) !== -1;
  } else {
    return true;
  }
};

const lookupApplicable = (fieldRecord?: DdxSuggestion) => {
  if (fieldRecord?.data_type) {
    return (
      textDataTypes.indexOf(fieldRecord.data_type.toLowerCase()) !== -1 &&
      fieldRecord.lookup_type !== null
    );
  } else {
    return true;
  }
};

const compOperatorSuggestions: Partial<
  DdxSuggestion & { applicable: (field?: DdxSuggestion) => boolean }
>[] = [
  {
    label: "Equals",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "=",
    insertText: "Equals",
    lookup_type: null,
    display_name: "=",
    applicable: alwaysApplicable,
  },
  {
    label: "Is Null",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "is null",
    insertText: "Is Null",
    lookup_type: null,
    applicable: alwaysApplicable,
    display_name: "is null",
  },
  {
    label: "Is Not Null",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "is not null",
    insertText: "Is Not Null",
    lookup_type: null,
    applicable: alwaysApplicable,
    display_name: "is not null",
  },
  {
    label: "Is Like",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "is like",
    insertText: "Is Like",
    lookup_type: null,
    applicable: textApplicable,
    display_name: "is like",
  },
  {
    label: "Is Not Like",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "is not like",
    insertText: "Is Not Like",
    lookup_type: null,
    applicable: textApplicable,
    display_name: "is not like",
  },
  {
    label: "Is Not Equal To",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "<>",
    insertText: "Is Not Equal To",
    lookup_type: null,
    applicable: alwaysApplicable,
    display_name: "<>",
  },
  {
    label: "Is Less Than",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "<",
    insertText: "Is Less Than",
    lookup_type: null,
    applicable: cardinalApplicable,
    display_name: "<",
  },
  {
    label: "Is Greater Than",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: ">",
    insertText: "Is Greater Than",
    lookup_type: null,
    applicable: cardinalApplicable,
    display_name: ">",
  },
  {
    label: "Is Less Than Or Equal To",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "<=",
    insertText: "Is Less Than Or Equal To",
    lookup_type: null,
    applicable: cardinalApplicable,
    display_name: "<=",
  },
  {
    label: "Is Greater Than Or Equal To",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: ">=",
    insertText: "Is Greater Than Or Equal To",
    lookup_type: null,
    applicable: cardinalApplicable,
    display_name: ">=",
  },

  {
    label: "Is Between",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "is between",
    insertText: "Is Between",
    lookup_type: null,
    applicable: cardinalApplicable,
    display_name: "is between",
  },
  {
    label: "Is Not Between",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "is not between",
    insertText: "Is Not Between",
    lookup_type: null,
    applicable: cardinalApplicable,
    display_name: "is not between",
  },
  {
    label: "Is One Of",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "in",
    insertText: "Is One Of",
    lookup_type: null,
    applicable: lookupApplicable,
    display_name: "in",
  },
  {
    label: "Is Not One Of",
    kind: monaco.languages.CompletionItemKind.Keyword,
    documentation: "not in",
    insertText: "Is Not One Of",
    lookup_type: null,
    applicable: lookupApplicable,
    display_name: "not in",
  },
];

const getEditorValues = (
  model: monaco.editor.ITextModel,
  position: monaco.IPosition
) => {
  const word = model.getWordUntilPosition(position);
  const range = {
    startLineNumber: position.lineNumber,
    endLineNumber: position.lineNumber,
    startColumn: word.startColumn,
    endColumn: word.endColumn,
    word: word,
  };

  const textValue: string = model.getValue()?.split("\n")[
    position.lineNumber - 1
  ];

  return {
    range,
    textValue,
  };
};

const findRuleChar = (textValue: string, position: number) => {
  if (textValue.indexOf("%") != -1) return "";
  const passthroughStart = textValue.indexOf("<");
  if (passthroughStart >= 0 && passthroughStart === position - 2) return "<";
  else if (textValue.substring(position - 2).indexOf("<") >= 0) {
    return "<";
  }
  return "";
};

const findFieldChar = (textValue: string, position: monaco.IPosition) => {
  const ruleStart = textValue.indexOf("[");
  const ruleEnd = textValue.indexOf("]");
  if (
    (ruleStart != -1 &&
      ruleEnd != -1 &&
      position.column - 2 >= ruleStart &&
      position.column - 2 <= ruleEnd) ||
    (textValue.substring(position.column - 2).indexOf("[") >= 0 &&
      textValue.substring(position.column - 2).indexOf("]") <= 1)
  ) {
    return "]";
  }
  return "";
};

const getCharIndxRange = (
  value: string,
  startChar: string,
  endChar: string,
  cursorPos: number
) => {
  const ruleSubStr = value.substring(cursorPos - 2);
  const substring = ruleSubStr
    ?.substring(0, ruleSubStr.indexOf(endChar) + 2)
    ?.trim();
  if (substring.startsWith(startChar) && substring.endsWith(endChar))
    return {
      subVal: substring,
      currentPos: Math.abs(value.length - substring.length - cursorPos),
    };
  if (substring.endsWith(endChar) && !substring.startsWith(startChar)) {
    for (let index = cursorPos; index <= value.length && index >= 0; index--) {
      const element = value[index];
      if (element === startChar[0]) {
        const result = value.substring(index);
        return {
          subVal: result.substring(0, result.indexOf(endChar) + 2),
          currentPos: Math.abs(value.length - result.length - cursorPos),
        };
      }
    }
  }
  if (substring.startsWith(startChar) && !substring.endsWith(endChar)) {
    return {
      subVal: substring,
      currentPos: Math.abs(value.length - substring.length - cursorPos),
    };
  }
  return;
};

const findCurrentChar = (textValue: string, position: monaco.IPosition) => {
  if (textValue.trim() === "") return "";
  let ruleStartindx = textValue.substring(position.column - 2).indexOf("<%");
  const ruleEnindx = textValue.substring(position.column - 2).indexOf("%>") + 2;
  if (ruleStartindx === -1) {
    ruleStartindx = textValue.substring(position.column - 2).indexOf("<");
  }
  const charRange = getCharIndxRange(textValue, "<%", "%>", position.column);
  let rchar = "";
  const txtVal =
    textValue.substring(position.column - 2).indexOf("%>") != -1
      ? textValue
          .substring(position.column - 2)
          .substring(ruleStartindx, ruleEnindx)
      : textValue.substring(position.column - 2).substring(ruleStartindx);
  const subStrLen = textValue.substring(0, position.column - 2).length;

  rchar = findRuleChar(
    charRange?.subVal ?? txtVal,
    position.column - subStrLen
  );

  const currentChar = rchar === "" ? findFieldChar(textValue, position) : rchar;
  return currentChar;
};

const fieldSuggestionProvider = (
  ddxSuggestions: DdxSuggestion[],
  range: monaco.IRange
): { suggestions: DdxSuggestion[] } => {
  const fieldSuggestions = ddxSuggestions
    .filter((x) => x.kind === monaco.languages.CompletionItemKind.Field)
    .map((s) => ({ ...s, range }));

  return {
    suggestions: fieldSuggestions,
  };
};

const passThroughSuggestionProvider = (
  range: monaco.IRange
): { suggestions: DdxSuggestion[] } => {
  return {
    suggestions: [
      {
        label:
          "<% Parameter Name, Lookup Type, Data Type, Multi Value, Type %>",
        kind: monaco.languages.CompletionItemKind.Interface,
        documentation: "Passthrough Text",
        insertText: "%${0},,,,%>",
        range,
        insertTextRules:
          monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
      },
    ],
  };
};

const defaultSuggestions = (
  ddxSuggestions: DdxSuggestion[],
  range: monaco.IRange
): DdxSuggestion[] => {
  return ddxSuggestions
    .filter(
      (x) =>
        x.kind === monaco.languages.CompletionItemKind.Function ||
        x.kind === monaco.languages.CompletionItemKind.Operator
    )
    .map((s) => ({
      ...s,
      range,
    }))
    .sort((a, b) => Number(a.kind ?? -1) - Number(b.kind ?? -1));
};

const getPassthroughSuggestion = (
  position: number,
  range: monaco.IRange,
  lookUpTypes: Set<{ code: string; name: string }>
) => {
  switch (position) {
    case 1:
      return {
        suggestions: [],
      };
    case 2:
      return {
        suggestions:
          lookUpTypes.size > 0
            ? Array.from(lookUpTypes).map((r) => ({
                label: r.code,
                kind: monaco.languages.CompletionItemKind.Field,
                documentation: r.name,
                insertText: r.code,
                range,
              }))
            : [],
      };
    case 3:
      return {
        suggestions: [
          "TEXT",
          "DATE",
          "NUMERIC",
          "CURRENCY",
          "PERCENT",
          "BOOLEAN",
        ].map((r) => ({
          label: r,
          kind: monaco.languages.CompletionItemKind.Constant,
          documentation: r,
          insertText: r,
          range,
        })),
      };

    case 4:
      return {
        suggestions: ["TRUE", "FALSE"].map((r) => ({
          label: r,
          kind: monaco.languages.CompletionItemKind.Constant,
          documentation: r,
          insertText: r,
          range,
        })),
      };

    case 5:
      return {
        suggestions: ["F", "V"].map((r) => ({
          label: r,
          kind: monaco.languages.CompletionItemKind.Constant,
          documentation: r,
          insertText: r,
          range,
        })),
      };

    default:
      return {
        suggestions: [],
      };
  }
};

const findCurrentParamPositionBetween = (
  value: string,
  startChar: string,
  endChar: string,
  currentPosition: number
) => {
  const startIndex = value.indexOf(startChar);
  const endIndex = value.indexOf(endChar) + 2;
  let itemPosition = 1;
  if (currentPosition >= startIndex && currentPosition <= endIndex) {
    const separatorMap = [];
    let pos = 0;
    let sti = 0;
    let braceCount = 0;
    let squareBraceCount = 0;
    let squareBraceCountRule = 0;
    if (value.indexOf(",") === -1) return itemPosition;
    for (let index = 0; index < value.length; index++) {
      if (value[index] === "{") braceCount++;
      if (value[index] === "}") braceCount--;
      if (value[index] === INVISIBLE_DELIMITER + "[") squareBraceCountRule++;
      if (value[index] === "]" + INVISIBLE_DELIMITER) squareBraceCountRule--;
      if (value[index] === "[") squareBraceCount++;
      if (value[index] === "]") squareBraceCount--;

      if (
        value[index] === "," &&
        braceCount === 0 &&
        squareBraceCount === 0 &&
        squareBraceCountRule === 0
      ) {
        separatorMap.push({ start: sti, end: index - 1, pos: ++pos });
        sti = index;
      }
    }
    if (separatorMap.length > 0) {
      separatorMap.push({ start: sti, end: endIndex, pos: ++pos });
    }
    for (let index = 0; index < separatorMap.length; index++) {
      const element = separatorMap[index];
      if (
        element.start <= currentPosition - 2 &&
        element.end >= currentPosition - 2
      ) {
        itemPosition = element.pos;
        break;
      }
    }
  }
  return itemPosition;
};

const getLookupTypes = (
  ddxSuggestions: Partial<DdxSuggestion>[],
  dataType?: string,
  lookupTypeCode?: string | null
) => {
  return new Set(
    ddxSuggestions
      ?.filter(
        (s: Partial<DdxSuggestion>) =>
          s?.kind === monaco.languages.CompletionItemKind.Field &&
          (!lookupTypeCode ||
            s?.lookup_type?.toLowerCase() ===
              lookupTypeCode?.trim()?.toLowerCase()) &&
          (!dataType ||
            (s.data_type &&
              s.data_type.toLowerCase() === dataType.trim().toLowerCase()))
      )
      .map((s) => ({ code: s.code ?? "", name: s.display_name ?? "" }))
  );
};

export const provideCompletionItems = (
  ddxSuggestions: DdxSuggestion[],
  fetchLookupItems?: (
    lookupKey: string
  ) => Promise<AxiosResponse<GetLookupItemsResponse> | undefined>,
  fetchLookupTypes?: () => Promise<
    AxiosResponse<GetLookupTypesResponse> | undefined
  >
) => {
  return async (
    model: monaco.editor.ITextModel,
    position: monaco.IPosition
  ) => {
    return suggestionProvider(
      ddxSuggestions,
      model,
      position,
      fetchLookupItems,
      fetchLookupTypes
    ) as Promise<completionType>;
  };
};

const passthroughSuggestion = (
  textValue: string,
  position: monaco.IPosition
) => {
  const charRange = getCharIndxRange(textValue, "<%", "%>", position.column);
  return { isPassthrough: charRange && charRange.currentPos, value: charRange };
};

const functionSuggestion = (
  textValue: string,
  position: monaco.IPosition,
  ddxSuggestion: DdxSuggestion | undefined
) => {
  const ruleFnRange = getCharIndxRange(textValue, "(", ")", position.column);
  return {
    isFunction:
      ddxSuggestion &&
      ddxSuggestion.params &&
      ddxSuggestion.is_rule &&
      ruleFnRange &&
      ruleFnRange.currentPos > -1,
    value: ruleFnRange,
  };
};

const TrimLookup = (value: string) => {
  if (value && value?.startsWith("app.")) {
    return value.substring("app.".length);
  } else if (value && value?.startsWith("bc.")) {
    return value.substring("bc.".length);
  }
  return value;
};

const getLookupSuggestion = (
  position: monaco.IPosition,
  textValue: string,
  ddxSuggestions: DdxSuggestion[]
): Partial<DdxSuggestion & { example: string | null }> | undefined => {
  const findSuggestion = (key: string) =>
    ddxSuggestions.find(
      (x) =>
        x.display_name?.toLowerCase() ===
          TrimLookup(key.trim()?.toLowerCase()) ||
        x.label?.toString()?.toLowerCase() ===
          TrimLookup(key.trim()?.toLowerCase())
    );

  const getKey = (indx: number) => {
    let lookupKey = "";

    let reverseStindx = -1;
    for (let index = indx; index < textValue.length; index++) {
      if (textValue[index] === ")") {
        lookupKey = "";
        break;
      }
      if (textValue[index] === "(") {
        reverseStindx = index;
        break;
      }
    }

    for (let index = reverseStindx - 1; index >= 0; index--) {
      if (textValue[index] === " " && index != reverseStindx - 1) break;
      lookupKey = textValue[index] + lookupKey;
    }
    return lookupKey.trim();
  };
  let lookupKey = getKey(position.column - 3);
  let openIndx = -1;
  let closeIndx = -1;
  if (lookupKey.trim() === "") {
    for (let index = position.column; index >= 0; index--) {
      if (textValue[index] === "(") {
        openIndx = index;
        break;
      }
    }

    for (let index = position.column - 1; index < textValue.length; index++) {
      if (textValue[index] === ")") {
        closeIndx = index;
        break;
      }
    }
    if (openIndx > -1 && closeIndx > -1) {
      lookupKey = getKey(openIndx);
    }
  }

  const operator = compOperatorSuggestions.find(
    (s) => s.label === lookupKey.trim()
  );
  if (operator) {
    lookupKey = getField(
      textValue,
      (openIndx > 0 ? openIndx : position.column) - lookupKey.trim().length
    );
  }

  let sugg = findSuggestion(lookupKey);
  if (sugg) return sugg;

  let key = "",
    skipChar = false;
  for (let i = 0; i < position.column; i++) {
    if (textValue[i] === " ") {
      key = !compOperatorSuggestions.some(
        (s) => s.label?.toString()?.toLowerCase() == key.trim()?.toLowerCase()
      )
        ? ""
        : key;
      skipChar = false;
      continue;
    }
    if (textValue[i] === "(") {
      if (!compOperatorSuggestions.some((s) => s.label === key.trim())) {
        lookupKey = key;
      }
      key = "";
      skipChar = true;
      continue;
    }
    if (textValue[i] === ")") {
      skipChar = false;
      continue;
    }
    if (textValue[i] === "[") {
      const subVal = textValue.substring(i, position.column);
      const tempKey = subVal.substring(1, subVal.indexOf("]"));
      if (!compOperatorSuggestions.some((s) => s.label === tempKey.trim())) {
        lookupKey = tempKey;
      }
      key = "";
      i = i + tempKey.length + 2;
      skipChar = false;

      continue;
    }
    if (!skipChar) {
      key = key + textValue[i];
    }
  }
  sugg = findSuggestion(lookupKey);

  if (sugg && sugg?.lookup_type?.trim() != "") {
    let opr = "";
    for (let index = textValue.length - 1; index > -1; index--) {
      if (textValue[index] === "]") break;
      opr = textValue[index] + opr;
    }
    if (isLikeOperator(opr)) {
      return sugg;
    }
  }

  // Handle inside parentheses after multi-value operators
  if (!sugg || !sugg.is_rule) {
    let parenBalance = 0;
    let matchingOpenParen = -1;
    for (let i = position.column - 2; i >= 0; i--) {
      if (textValue[i] === ")") parenBalance++;
      if (textValue[i] === "(") {
        if (parenBalance === 0) {
          matchingOpenParen = i;
          break;
        }
        parenBalance--;
      }
    }

    if (matchingOpenParen > 0) {
      const textBeforeParen = textValue.substring(0, matchingOpenParen).trim();
      const operatorPart =
        textBeforeParen.split(/\]/).pop()?.trim()?.toUpperCase() || "";

      if (isMultiValueOperator(operatorPart)) {
        let closeBracket = -1;
        let openBracket = -1;
        for (let i = matchingOpenParen - 1; i >= 0; i--) {
          if (textValue[i] === "]" && closeBracket === -1) {
            closeBracket = i;
          }
          if (textValue[i] === "[" && closeBracket > -1) {
            openBracket = i;
            break;
          }
        }

        if (openBracket > -1 && closeBracket > -1) {
          const fieldName = textValue.substring(openBracket + 1, closeBracket);
          const fieldSugg = findSuggestion(fieldName);
          if (fieldSugg) return fieldSugg;
        }
      } else if (isLikeOperator(operatorPart)) {
        let closeBracket = -1;
        let openBracket = -1;
        for (let i = matchingOpenParen - 1; i >= 0; i--) {
          if (textValue[i] === "]" && closeBracket === -1) {
            closeBracket = i;
          }
          if (textValue[i] === "[" && closeBracket > -1) {
            openBracket = i;
            break;
          }
        }

        if (openBracket > -1 && closeBracket > -1) {
          const fieldName = textValue.substring(openBracket + 1, closeBracket);
          const fieldSugg = findSuggestion(fieldName);
          if (fieldSugg) return fieldSugg;
        }
      }
    }
  }

  return sugg;
};

const getField = (textValue: string, position: number) => {
  if (textValue[position] === " ") {
    position--;
  }
  let key = "",
    lookupKey = "",
    skipChar = false;
  for (let i = 0; i < position; i++) {
    if (textValue[i] === " ") {
      key = "";
      skipChar = false;
      continue;
    }
    if (textValue[i] === "(") {
      if (!compOperatorSuggestions.some((s) => s.label === key.trim())) {
        lookupKey = key;
      }
      key = "";
      skipChar = true;
    }
    if (textValue[i] === ")") {
      skipChar = false;
      continue;
    }
    if (textValue[i] === "[" && !skipChar) {
      const subVal = textValue.substring(i, position);
      const tempKey = subVal.substring(1, subVal.indexOf("]"));
      if (!compOperatorSuggestions.some((s) => s.label === tempKey.trim())) {
        lookupKey = tempKey;
      }
      key = "";
      i = i + tempKey.length + 2;
      continue;
    }
    if (!skipChar) {
      key = key + textValue[i];
    }
  }
  return lookupKey;
};

const isField = (value: string, position: number) => {
  let startFound = false,
    startFoundIndx = -1;
  let endFound = false,
    endFoundIndx = -1;
  for (
    let stInd = position, endIndx = position;
    stInd > -1 && endIndx < value.length;

  ) {
    if (value[endIndx] === "]") {
      if (endFound && endIndx != endFoundIndx) {
        endFound = false;
        break;
      }
      endFound = true;
      endFoundIndx = endIndx;
    }
    if (value[stInd] === "[") {
      if (startFound && stInd != startFoundIndx) {
        startFound = false;
        break;
      }
      startFound = true;
      startFoundIndx = stInd;
    }
    if (value[stInd] === "]" && value[endIndx] !== "]") {
      startFound = false;
      break;
    }
    if (value[endIndx] === "[" && value[stInd] !== "[") {
      endFound = false;
      break;
    }
    if (startFound && endFound) break;
    if (!endFound) {
      endIndx++;
    }
    if (!startFound) {
      stInd--;
    }
  }
  return {
    isField:
      startFound &&
      endFound &&
      position > startFoundIndx &&
      position <= endFoundIndx,
    startFoundIndx,
    endFoundIndx,
    fieldVal: value.substring(startFoundIndx + 1, endFoundIndx)?.trimStart(),
  };
};

const suggestionProvider = async (
  ddxSuggestions: DdxSuggestion[],
  model: monaco.editor.ITextModel,
  position: monaco.IPosition,
  fetchLookupItems?: (
    lookupKey: string
  ) => Promise<AxiosResponse<GetLookupItemsResponse> | undefined>,
  fetchLookupTypes?: () => Promise<
    AxiosResponse<GetLookupTypesResponse> | undefined
  >
): Promise<{ suggestions: DdxSuggestion[] }> => {
  const { range, textValue } = getEditorValues(model, position);
  const ddxSuggestion = getLookupSuggestion(
    position,
    textValue,
    ddxSuggestions
  );
  const isFld = isField(textValue, position.column - 1);

  if (isFld.isField) {
    return fieldSuggestionProvider(
      ddxSuggestions.filter((s) =>
        (s.label as string)
          ?.toLowerCase()
          ?.includes(isFld.fieldVal?.toLowerCase())
      ),
      {
        ...range,
        startColumn: isFld.startFoundIndx + 2,
        word: {
          ...range.word,
          startColumn: isFld.startFoundIndx + 2,
        },
      } as monaco.IRange
    );
  }
  const currentChar = findCurrentChar(textValue, position);
  if (currentChar === "<") return passThroughSuggestionProvider(range);

  const { isFunction, value: ruleFnRange } = functionSuggestion(
    textValue,
    position,
    ddxSuggestion
  );

  const { isPassthrough, value: charRange } = passthroughSuggestion(
    textValue,
    position
  );
  if (!isPassthrough && !!ddxSuggestion) {
    const { prevField, restVal } = getPrevField(
      position,
      textValue.trim(),
      ddxSuggestion
    );
    if (
      prevField &&
      prevField.lookup_type?.trim() !== "" &&
      currentChar !== "]"
    ) {
      return {
        suggestions: Array.from(
          new Set(
            compOperatorSuggestions
              .filter((s) => s?.applicable && s.applicable(prevField))
              .map((s) => ({
                ...s,
                range,
              }))
          )
        ),
      };
    }

    if (
      ddxSuggestion &&
      compOperatorSuggestions.some(
        (s) =>
          s.label &&
          restVal
            .trim()
            ?.toLowerCase()
            .indexOf(s.label.toString().toLowerCase()) > -1
      )
    ) {
      const { isFunction, value: ruleFnRange } = functionSuggestion(
        textValue,
        position,
        ddxSuggestion.kind === monaco.languages.CompletionItemKind.Field
          ? { ...ddxSuggestion, is_rule: true, params: [] }
          : ddxSuggestion
      );

      if (isFunction) {
        if (!ddxSuggestion.lookup_type && ruleFnRange) {
          if (ddxSuggestion.params) {
            const fnitemPosition = findCurrentParamPositionBetween(
              ruleFnRange.subVal,
              "(",
              ")",
              ruleFnRange.currentPos
            );
            const currentParameter = ddxSuggestion.params[fnitemPosition - 1];

            if (currentParameter && currentParameter?.lookup_type) {
              const lookUpResponse =
                currentParameter.param_type?.trim()?.toLowerCase() === "v" &&
                currentParameter?.lookup_type &&
                currentParameter?.lookup_type?.trim()?.length > 0 &&
                fetchLookupItems
                  ? await fetchLookupItems(
                      currentParameter?.lookup_type?.trim()
                    )
                  : currentParameter.param_type?.trim()?.toLowerCase() ===
                      "f" &&
                    ((currentParameter?.data_type &&
                      currentParameter?.data_type?.length > 0) ||
                      currentParameter?.lookup_type)
                  ? {
                      data: {
                        lookup_items: Array.from(
                          getLookupTypes(
                            ddxSuggestions,
                            currentParameter?.data_type,
                            currentParameter?.lookup_type
                          )
                        ).map((r) => ({
                          description: r.name,
                          code: r.code,
                        })),
                      },
                    }
                  : {
                      data: {
                        lookup_items: [],
                      },
                    };

              const currentLoookups =
                lookUpResponse?.data?.lookup_items &&
                lookUpResponse?.data?.lookup_items?.length > 0
                  ? lookUpResponse?.data?.lookup_items
                  : [];
              let result: DdxSuggestion[] = [];
              if (currentLoookups && currentLoookups.length > 0) {
                result = currentLoookups.map((r) => ({
                  label: `${r.description}`,
                  kind: monaco.languages.CompletionItemKind.Field,
                  documentation: r.code ?? "",

                  insertText:
                    currentParameter.param_type?.trim()?.toLowerCase() === "v"
                      ? WrapWithInvisibleDelimiter(`${r.code}`)
                      : `[${r.description}]`,
                  range,
                }));
              }

              return {
                suggestions:
                  result ?? defaultSuggestions(ddxSuggestions, range),
              };
            }
          }
        } else if (
          ddxSuggestion.lookup_type &&
          ruleFnRange &&
          !isLikeOperator(restVal) &&
          !isRangeOperator(restVal)
        ) {
          const lookUpResponse =
            fetchLookupItems &&
            (await fetchLookupItems(ddxSuggestion?.lookup_type?.trim()));

          const currentLoookups =
            lookUpResponse?.data?.lookup_items &&
            lookUpResponse?.data?.lookup_items?.length > 0
              ? lookUpResponse?.data?.lookup_items
              : [];
          let result: DdxSuggestion[] = [];
          if (currentLoookups && currentLoookups.length > 0) {
            result = currentLoookups.map((r) => ({
              label: `${r.description}`,
              kind: monaco.languages.CompletionItemKind.Field,
              documentation: r.code,
              insertText: WrapWithInvisibleDelimiter(r.description),
              range,
            }));
          }

          return {
            suggestions: result ?? defaultSuggestions(ddxSuggestions, range),
          };
        } else {
          return {
            suggestions: [],
          };
        }
      }
      if (
        [
          "Equals",
          "Is Not Equal To",
          "Is Greater Than",
          "Is Greater Than Or Equal To",
          "Is Less Than Or Equal To",
          "Is Less Than",
        ].includes(restVal.trim()) ||
        (isLikeOperator(restVal.trim()) && ddxSuggestion?.lookup_type)
      ) {
        const lookUpResponse =
          fetchLookupItems && ddxSuggestion?.lookup_type
            ? await fetchLookupItems(ddxSuggestion?.lookup_type?.trim())
            : ddxSuggestion?.data_type &&
              ddxSuggestion?.data_type?.trim()?.toLowerCase() === "boolean"
            ? {
                data: {
                  lookup_items: [
                    {
                      code: "No",
                      description: "No",
                    },
                    {
                      code: "Yes",
                      description: "Yes",
                    },
                  ],
                },
              }
            : {
                data: {
                  lookup_items: [],
                },
              };
        const currentLoookups =
          lookUpResponse?.data?.lookup_items &&
          lookUpResponse?.data?.lookup_items?.length > 0
            ? Array.from(new Set(lookUpResponse?.data?.lookup_items))
            : [];
        let result: DdxSuggestion[] = [];
        if (currentLoookups && currentLoookups.length > 0) {
          result = currentLoookups.map((r) => ({
            label: `${r.description}`,
            kind: monaco.languages.CompletionItemKind.Field,
            documentation: r.code,
            insertText:
              ddxSuggestion?.data_type?.trim()?.toLowerCase() === "boolean"
                ? `${r.description}`
                : `${WrapWithInvisibleDelimiter(r.description)}`,
            range,
          }));
        }

        return {
          suggestions: result ?? defaultSuggestions(ddxSuggestions, range),
        };
      }
    }
  }

  if (isFunction && ruleFnRange && ddxSuggestion?.params) {
    const itemPosition = findCurrentParamPositionBetween(
      ruleFnRange.subVal,
      "(",
      ")",
      ruleFnRange.currentPos
    );
    const currentParam = ddxSuggestion.params[itemPosition - 1];
    if (currentParam) {
      const lookUpResponse =
        currentParam.param_type?.trim()?.toLowerCase() === "v" &&
        currentParam?.lookup_type &&
        currentParam?.lookup_type?.trim()?.length > 0 &&
        fetchLookupItems
          ? await fetchLookupItems(currentParam?.lookup_type?.trim())
          : currentParam.param_type?.trim()?.toLowerCase() === "f" &&
            ((currentParam?.data_type && currentParam?.data_type?.length > 0) ||
              currentParam?.lookup_type)
          ? {
              data: {
                lookup_items: Array.from(
                  getLookupTypes(
                    ddxSuggestions,
                    currentParam?.data_type,
                    currentParam?.lookup_type
                  )
                ).map((r) => ({
                  description: r.name,
                  code: r.code,
                })),
              },
            }
          : {
              data: {
                lookup_items: [],
              },
            };

      const currentLoookups =
        lookUpResponse?.data?.lookup_items &&
        lookUpResponse?.data?.lookup_items?.length > 0
          ? lookUpResponse?.data?.lookup_items
          : [];
      let result: DdxSuggestion[] = [];
      if (currentLoookups && currentLoookups.length > 0) {
        result = currentLoookups.map((r) => ({
          label: `${r.description}`,
          kind: monaco.languages.CompletionItemKind.Field,
          documentation: r.code ?? "",
          insertText:
            currentParam.param_type?.trim()?.toLowerCase() === "v"
              ? `${WrapWithInvisibleDelimiter(r.code)}`
              : `[${r.description}]`,
          range,
        }));
      }

      return {
        suggestions: result ?? defaultSuggestions(ddxSuggestions, range),
      };
    }
    const insideChar = textValue[position.column - 1];

    return insideChar === "[" || (insideChar === "]" && isFld.isField)
      ? fieldSuggestionProvider(
          ddxSuggestions.filter((s) =>
            (s.label as string)
              ?.toLowerCase()
              ?.includes(isFld.fieldVal?.toLowerCase())
          ),
          isFld.isField
            ? ({
                ...range,
                startColumn: isFld.startFoundIndx + 2,
                word: {
                  ...range.word,
                  startColumn: isFld.startFoundIndx + 2,
                },
              } as monaco.IRange)
            : range
        )
      : insideChar === "<"
      ? passThroughSuggestionProvider(range)
      : {
          suggestions: defaultSuggestions(ddxSuggestions, range),
        };
  }
  if (currentChar === "]" && isFld.isField) {
    return fieldSuggestionProvider(
      ddxSuggestions.filter((s) =>
        (s.label as string)
          ?.toLowerCase()
          ?.includes(isFld.fieldVal?.toLowerCase())
      ),
      isFld.isField
        ? ({
            ...range,
            startColumn: isFld.startFoundIndx + 2,
            word: {
              ...range.word,
              startColumn: isFld.startFoundIndx + 2,
            },
          } as monaco.IRange)
        : range
    );
  }

  if (isPassthrough && charRange) {
    const itemPosition = findCurrentParamPositionBetween(
      charRange.subVal,
      "<%",
      "%>",
      charRange.currentPos
    );
    if (itemPosition === 2 && fetchLookupTypes) {
      const lookups = await fetchLookupTypes();
      return getPassthroughSuggestion(
        itemPosition,
        range,
        new Set(
          lookups?.data?.lookup_types?.map((s) => ({
            code: s.code ?? "",
            name: s.description ?? "",
          }))
        )
      );
    } else {
      return getPassthroughSuggestion(itemPosition, range, new Set([]));
    }
  } else {
    if (
      ["in", "not in"].includes(
        ddxSuggestion?.display_name?.toLowerCase() ?? ""
      )
    ) {
      return {
        suggestions: [
          {
            code: "(",
            data_type: "(",
            display_name: "(",
            documentation: "(",
            insertText: "(${1})",
            insertTextRules:
              monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
            kind: 1,
            label: "(",
            lookup_type: null,
            name: "(",
            range,
          },
        ],
      };
    }
    if (isLikeOperator(ddxSuggestion?.display_name ?? "")) {
      return {
        suggestions: [
          {
            code: "%",
            data_type: "%",
            display_name: "%",
            documentation: "%",
            insertText: WrapWithInvisibleDelimiter("%${1}%"),
            insertTextRules:
              monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
            kind: 1,
            label: "%",
            lookup_type: null,
            name: "%",
            range,
          },
        ],
      };
    }
    return {
      suggestions: defaultSuggestions(ddxSuggestions, range),
    };
  }
};

export const hoverProvider = (ddxSuggestions: DdxSuggestion[]) => {
  return (model: monaco.editor.IModel, position: monaco.IPosition) => {
    const { textValue: text } = getEditorValues(model, position);
    const lookupSuggestion = getLookupSuggestion(
      position,
      text,
      ddxSuggestions
    );
    let hoverText = "";
    const textValue: string = model.getValue()?.split("\n")[
      position.lineNumber - 1
    ];
    const ruleStidnx = textValue.indexOf("<%");
    const ruleEnidnx = textValue.indexOf("%>");

    if (position.column > ruleStidnx && position.column < ruleEnidnx) {
      hoverText =
        "<%Parameter Name, Lookup Type, Data Type, Multi Value, Type%>";
    } else if (lookupSuggestion) {
      if (
        lookupSuggestion &&
        lookupSuggestion?.params &&
        lookupSuggestion.params?.length > 0
      ) {
        let params = "";
        for (let index = 0; index < lookupSuggestion.params.length; index++) {
          params =
            params + lookupSuggestion.params[index]?.parameter_name + ",";
        }
        hoverText = `(${params.substring(0, params.length - 1)}) \n\n ${
          lookupSuggestion.documentation ?? ""
        }`;
      } else {
        hoverText = lookupSuggestion.documentation ?? "";
      }
    }
    return {
      range: new monaco.Range(
        position.lineNumber,
        position.column,
        position.lineNumber,
        model.getLineMaxColumn(position.lineNumber)
      ),
      contents: [{ value: hoverText ?? "" }],
    };
  };
};

const getPrevField = (
  position: monaco.IPosition,
  textValue: string,
  ddxSuggestion: DdxSuggestion | null
) => {
  let prevItem = "";
  let fieldFound = false;
  let restVal = "";
  for (let i = position.column; i >= 0 && textValue[i] != "["; i--) {
    if (textValue[i] === "") continue;
    if (textValue[i] === "]") {
      fieldFound = true;
      continue;
    }
    if (!fieldFound && textValue[i]) {
      restVal = textValue[i] + restVal;
    }

    prevItem = fieldFound ? textValue[i] + prevItem : prevItem;
  }
  if (restVal.trim().startsWith("(")) {
    restVal = restVal.slice(1);
  }
  if (restVal.trim().endsWith(")")) {
    restVal = restVal.slice(0, restVal.length - 1);
  }
  const prevField: DdxSuggestion | null =
    restVal.trim().length === 0 ? ddxSuggestion : null;
  return { prevField, restVal };
};

export const signatureHelpProvider = (
  ddxSuggestions: Partial<DdxSuggestion & { example: string }>[]
): monaco.languages.SignatureHelpProvider => {
  const provideSignatureHelp = (
    model: monaco.editor.ITextModel,
    position: monaco.IPosition
  ): monaco.languages.ProviderResult<monaco.languages.SignatureHelpResult> => {
    const { textValue: text } = getEditorValues(model, position);
    const lookupSuggestion = getLookupSuggestion(
      position,
      text,
      ddxSuggestions
    );
    let hoverText = "";
    const functionParams: monaco.languages.ParameterInformation[] = [];
    let paramPos = 0;

    const ruleStidnx = text.indexOf("<%");
    const ruleEnidnx = text.indexOf("%>");

    const getExampleText = (doc?: string, example?: string | null) => {
      return example && example?.trim()?.length > 0
        ? `\n${doc ?? ""} \n Example: \n ${example}`
        : `\n${doc ?? ""} \n`;
    };
    if (
      !lookupSuggestion &&
      position.column > ruleStidnx &&
      position.column <= ruleEnidnx + 2
    ) {
      const passSuggestion = ddxSuggestions.find((d) => "<" === d.label);
      if (passSuggestion) {
        const { isPassthrough, value: charRange } = passthroughSuggestion(
          text,
          position
        );
        hoverText = String(passSuggestion.documentation ?? "");

        if (isPassthrough && charRange) {
          paramPos = findCurrentParamPositionBetween(
            charRange.subVal,
            "<%",
            "%>",
            charRange.currentPos
          );
        }
        let params = "";
        for (
          let index = 0;
          passSuggestion.params && index < passSuggestion.params.length;
          index++
        ) {
          functionParams.push({
            label: `${passSuggestion.params[index]?.parameter_name}`,
            documentation: `${passSuggestion.params[index]?.parameter_name} : ${
              passSuggestion.params[index]?.description
            }
            ${getExampleText(
              passSuggestion.documentation as string,
              passSuggestion.example
            )}`,
          });
          params = params + passSuggestion.params[index]?.parameter_name + ",";
        }
        hoverText = `(${params.substring(0, params.length - 1)})`;
      }
    } else if (lookupSuggestion) {
      if (
        lookupSuggestion &&
        lookupSuggestion?.params &&
        lookupSuggestion.params?.length > 0
      ) {
        let params = "";
        const { isFunction, value: ruleFnRange } = functionSuggestion(
          text,
          position,
          lookupSuggestion.kind === monaco.languages.CompletionItemKind.Field
            ? { ...lookupSuggestion, is_rule: true, params: [] }
            : { ...lookupSuggestion, is_rule: true }
        );

        if (isFunction) {
          if (!lookupSuggestion.lookup_type && ruleFnRange) {
            paramPos = findCurrentParamPositionBetween(
              ruleFnRange.subVal,
              "(",
              ")",
              ruleFnRange.currentPos
            );
          }
        }
        hoverText = String(lookupSuggestion.documentation ?? "");
        for (let index = 0; index < lookupSuggestion.params.length; index++) {
          functionParams.push({
            label: `${lookupSuggestion.params[index]?.parameter_name}`,
            documentation: `${
              lookupSuggestion.params[index]?.parameter_name
            } : ${lookupSuggestion.params[index]?.description}
            ${getExampleText(
              lookupSuggestion.documentation as string,
              lookupSuggestion.example
            )}`,
          });
          params =
            params + lookupSuggestion.params[index]?.parameter_name + ",";
        }
        hoverText = `(${params.substring(0, params.length - 1)})`;
      }
    }

    return {
      dispose: () => ({}),
      value: {
        activeParameter: paramPos - 1,
        activeSignature: 0,
        signatures:
          hoverText?.length === 0
            ? []
            : [
                {
                  label: hoverText,
                  parameters: functionParams,
                },
              ],
      },
    };
  };

  return {
    provideSignatureHelp,
    signatureHelpTriggerCharacters: ["(", "<%", ","],
  };
};

