type DdxContextType = ReturnType<typeof useDdxValues>;

const DdxContext = createContext<DdxContextType | null>(null);

export const DdxProvider = ({ children }: { children: ReactNode }) => {
  const ddxData = useDdxValues();
  return <DdxContext.Provider value={ddxData}>{children}</DdxContext.Provider>;
};

export const useDdxContext = () => {
  const context = useContext(DdxContext);
  if (!context) {
    throw new Error("useDdxContext must be used within DdxProvider");
  }
  return context;
};

