import {
  FormAutocomplete,
  Formik,
  FormValidateField,
  ProgressOrDivider,
} from "@textile/biz-components";
import {
  CloseIcon,
  CollapseIcon,
  Dialog,
  DialogTitle,
  EditIcon,
  ExpandIcon,
  ToolGroup,
  useAxiosFactory,
  useMessageAnnouncer,
} from "@textile/common";
import {
  Alert,
  Box,
  Button,
  Checkbox,
  CircularProgress,
  DialogActions,
  DialogContent,
  Divider,
  FormControlLabel,
  IconButton,
  Stack,
  SxProps,
  TextField,
  Theme,
  ToggleButton,
  ToggleButtonGroup,
  Typography,
  useTheme,
} from "@textile/mui";
import * as monaco from "monaco-editor";
import {
  FunctionComponent,
  ReactNode,
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
} from "react";

import { FormDdxFieldsGrid } from "./ddx-field-grid-component";
import { ExpressionBuilderLookupAutoComplete } from "./expression-builder-lookup-auto-complete.component";
import { SelectRuleDialog } from "./expression-builder-select-rule-dialog.component";
import { RuleDisplayComponent } from "./rule-display.component";
import { FormValueField } from "../form/form-value-selector.component";
import { useExpressionValidator } from "../../hooks/expression-validator.hook";
import {
  DdxData,
  DdxField,
  DdxFunction,
  DdxTranslationError,
  ModelExpression,
  ModelExpressionLogic,
} from "../../solvasam-bizcomponents";
import { DdxEditorDetails } from "../monaco-ddx-editor/ddx-editor-details";
import {
  WrapWithInvisibleDelimiter,
  getDialogResizePaperPropsSx,
  isMultiValueOperator,
  isNullCheckOperator,
  isPassThroughCode,
  isRangeOperator,
  replaceUniCodeForMultiValues,
  replaceUniCodeForSingleValue,
  unwrapValue,
} from "../helpers";
import { FormikErrors } from "formik";
import { DraggableExpression } from "./draggable-expression";

export interface ExpressionBuilderState {
  expression: Expression[];
  ddxData: DdxData;
  setState: (value: React.SetStateAction<Expression[]>) => void;
  values: { [x: string]: string };
  setValues: (
    values: React.SetStateAction<{
      [x: string]: string;
    }>,
    shouldValidate?: boolean
  ) => Promise<void | FormikErrors<{
    [x: string]: string;
  }>>;
}
export interface Expression {
  line_number: number;
  logical_operator: string;
  field: string | null;
  isRule: boolean;
  comparison_operator: string | null;
  value: string | null;
  value2: string | null;
  open_parenthesis: number;
  close_parenthesis: number;
  logical_expression: string;
}
export interface ExpressionBuilderFieldValues {
  [x: string]: string;
}

interface ConditionOperatorOptions {
  displayText: string;
  value: string;
  applicable: (dataType: DdxField) => boolean;
}
export interface ExpressionBuilderProps {
  expression: Expression[];
  sx?: SxProps;
  ddxProps: DdxData;
  open: boolean;
  handleOnCloseButtonClick?: () => void;
  setValue?: (
    value: ModelExpression,
    shouldValidate?: boolean | undefined
  ) => void;
  children?: ReactNode;
  targetKey?: string;
  targetType?: string;
  isComplexRule?: boolean;
}

export const openParenthesisOptions = [
  { value: "1", displayText: "(" },
  { value: "2", displayText: "((" },
  { value: "3", displayText: "(((" },
  { value: "4", displayText: "((((" },
  { value: "5", displayText: "(((((" },
];

const topBoxSx: SxProps<Theme> = {
  py: 1,
  alignItems: "center",
  display: "flex",
  flexDirection: "row",
  minWidth: 1200,
};

const shimBoxSx: SxProps<Theme> = { flexGrow: 1 };
const logicalOperatorOptions = [
  { value: "AND", displayText: "AND" },
  { value: "OR", displayText: "OR" },
  { value: "AND NOT", displayText: "AND NOT" },
  { value: "OR NOT", displayText: "OR NOT" },
];

const booleanOptions = [
  { id: "Yes", value: "Yes" },
  { id: "No", value: "No" },
];

export const logicalOperatorOptionsFirstRow = [
  { value: "NOT", displayText: "NOT" },
];

export const closeParenthesisOptions = [
  { value: "1", displayText: ")" },
  { value: "2", displayText: "))" },
  { value: "3", displayText: ")))" },
  { value: "4", displayText: "))))" },
  { value: "5", displayText: ")))))" },
];

const cardinalDataTypes = ["numeric", "date", "currency", "percent"];
const textDataTypes = ["text"];
const alwaysApplicableFunc = () => true;

const textApplicableFunc = (fieldRecord: DdxField): boolean => {
  // Always applicable for unknown fields
  if (!fieldRecord) return false;
  if (fieldRecord.lookup_type == null) return false;
  return (
    textDataTypes.indexOf(
      fieldRecord.data_type ? fieldRecord.data_type.toLowerCase() : ""
    ) !== -1
  );
};

const lookupApplicableFunc = (fieldRecord: DdxField) => {
  // Always applicable for unknown fields
  if (!fieldRecord) return false;
  return (
    textDataTypes.indexOf(
      fieldRecord.data_type ? fieldRecord.data_type.toLowerCase() : ""
    ) !== -1 && fieldRecord.lookup_type !== null
  );
};

const cardinalApplicableFunc = (fieldRecord: DdxField) => {
  // Always applicable for unknown fields
  if (!fieldRecord) return false;
  return (
    cardinalDataTypes.indexOf(
      fieldRecord.data_type ? fieldRecord.data_type.toLowerCase() : ""
    ) !== -1
  );
};

const comparisonOperatorList: ConditionOperatorOptions[] = [
  { displayText: "Equals", value: "Equals", applicable: alwaysApplicableFunc },
  {
    displayText: "Is Null",
    value: "Is Null",
    applicable: alwaysApplicableFunc,
  },
  {
    displayText: "Is Not Null",
    value: "Is Not Null",
    applicable: alwaysApplicableFunc,
  },
  {
    displayText: "Is Not Equal To",
    value: "Is Not Equal To",
    applicable: alwaysApplicableFunc,
  },
  {
    displayText: "Is Greater Than",
    value: "Is Greater Than",
    applicable: cardinalApplicableFunc,
  },
  {
    displayText: "Is Less Than",
    value: "Is Less Than",
    applicable: cardinalApplicableFunc,
  },
  {
    displayText: "Is Greater Than Or Equal To",
    value: "Is Greater Than Or Equal To",
    applicable: cardinalApplicableFunc,
  },
  {
    displayText: "Is Less Than Or Equal To",
    value: "Is Less Than Or Equal To",
    applicable: cardinalApplicableFunc,
  },
  {
    displayText: "Is Between",
    value: "Is Between",
    applicable: cardinalApplicableFunc,
  },
  {
    displayText: "Is Not Between",
    value: "Is Not Between",
    applicable: cardinalApplicableFunc,
  },
  { displayText: "Is Like", value: "Is Like", applicable: textApplicableFunc },
  {
    displayText: "Is Not Like",
    value: "Is Not Like",
    applicable: textApplicableFunc,
  },
  {
    displayText: "Is One Of",
    value: "Is One Of",
    applicable: lookupApplicableFunc,
  },
  {
    displayText: "Is Not One Of",
    value: "Is Not One Of",
    applicable: lookupApplicableFunc,
  },
];

enum FieldDataTypes {
  "boolean" = "boolean",
  "text" = "text",
  "percent" = "percent",
  "date" = "date",
  "numeric" = "numeric",
}

export const getLogicalExpressionFunc = (
  fieldRecord: DdxField,
  comparisonOperator: string,
  value: string | string[] | null,
  value2: string | null,
  valueType: string
) => {
  if (value) {
    if (
      isPassThroughCode(
        Array.isArray(value) ? value[0].toString() : value.toString()
      )
    ) {
      value = Array.isArray(value) ? value[0].toString() : value.toString();
      if (isRangeOperator(comparisonOperator) && value2) {
        value += " AND " + value2.toString();
      }
      if (isMultiValueOperator(comparisonOperator)) {
        value = "(" + value + ")";
      }
    } else {
      if (valueType === "F") {
        if (isRangeOperator(comparisonOperator) && value2) {
          value = "[" + value + "] AND [" + value2 + "]";
        } else {
          value = "[" + value + "]";
        }
      } else {
        switch (fieldRecord?.data_type?.toLowerCase()) {
          case FieldDataTypes.boolean:
            value = value.toString();
            if (isRangeOperator(comparisonOperator) && value2) {
              value2 = value2.toString();
            }
            break;
          case FieldDataTypes.percent:
            value = value.toString();
            if (isRangeOperator(comparisonOperator) && value2) {
              value2 = value2.toString();
            }
            break;
          case FieldDataTypes.text:
            // put qoutes only for plain text fields, lookup ones already carry single qoutes
            if (!isMultiValueOperator(comparisonOperator)) {
              value = WrapWithInvisibleDelimiter(value);
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = WrapWithInvisibleDelimiter(value2);
              }
            } else {
              value = Array.isArray(value)
                ? value.map((item: string) => WrapWithInvisibleDelimiter(item))
                : WrapWithInvisibleDelimiter(value);
            }
            break;
          case FieldDataTypes.date:
            if (!isMultiValueOperator(comparisonOperator)) {
              value = WrapWithInvisibleDelimiter(
                new Date(value.toString()).toLocaleDateString()
              );
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = WrapWithInvisibleDelimiter(
                  new Date(value2.toString()).toLocaleDateString()
                );
              }
            }
            break;
          case FieldDataTypes.numeric:
            if (!isMultiValueOperator(comparisonOperator)) {
              value = value.toString();
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = value2.toString();
              }
            }
            break;
          default:
            if (fieldRecord?.lookup_type == null) {
              value = WrapWithInvisibleDelimiter(value);
              if (isRangeOperator(comparisonOperator) && value2) {
                value2 = WrapWithInvisibleDelimiter(value2);
              }
            }
        }
        if (isRangeOperator(comparisonOperator) && value2) {
          value = value + " AND " + value2;
        }
        // in case of multiple values, put the values inside ()
        if (isMultiValueOperator(comparisonOperator)) {
          value = "(" + value + ")";
        }
      }
    }
  }

  return (
    "[" +
    fieldRecord?.display_name +
    "]" +
    " " +
    (!isPassThroughCode(comparisonOperator)
      ? comparisonOperatorList.filter(
          (x: ConditionOperatorOptions) =>
            x.value === comparisonOperator?.trim()
        )[0]?.value
      : comparisonOperator) +
    " " +
    (value && !isNullCheckOperator(comparisonOperator) ? value : "")
  );
};

export const getValue = (
  comparisonOperator: string,
  value: string | string[] | null
) => {
  return value
    ? isMultiValueOperator(comparisonOperator) && typeof value === "object"
      ? value?.map((x) => WrapWithInvisibleDelimiter(x)).toString()
      : value?.toString()
    : null;
};

export const getFriendlyDescription = (expressions: Expression[]) => {
  return expressions
    .map((item) => ({
      ddx:
        item.logical_operator +
        " " +
        (item.open_parenthesis
          ? openParenthesisOptions?.filter(
              (x) => x.value === item.open_parenthesis.toString()
            )[0]?.displayText
          : "") +
        item.logical_expression +
        (item.close_parenthesis
          ? closeParenthesisOptions?.filter(
              (x) => x.value === item.close_parenthesis.toString()
            )[0]?.displayText
          : ""),
    }))
    .map((u) => u.ddx)
    .join(" ");
};

export const ExpressionBuilderContext =
  createContext<ExpressionBuilderState | null>(null);

export interface ExpressionBuilderContextProviderProps
  extends ExpressionBuilderState {
  children?: ReactNode;
}

export const ExpressionBuilderContextProvider: FunctionComponent<
  ExpressionBuilderContextProviderProps
> = ({ children, ...props }) => {
  return (
    <ExpressionBuilderContext.Provider value={props}>
      {children}
    </ExpressionBuilderContext.Provider>
  );
};

export const useExpressionBuilderContext = () => {
  const context = useContext(ExpressionBuilderContext);

  if (!context) {
    throw new Error(
      "useExpressionBuilderContext cannot be called outside of a ExpressionBuilderContext"
    );
  }

  return context;
};

const getDdxFieldByDisplayName = (
  ddxFields: DdxField[],
  displayName: string
) => {
  return ddxFields.filter((field) => field.display_name === displayName);
};

const headersx: SxProps = {
  display: "flex",
  py: 0.5,
  px: 1,
};

export const gridTemplateColumns = "8% 1px 10% 1px 10% 1px 56% 1px 10%";

export const ExpressionBuilder: FunctionComponent<ExpressionBuilderProps> = (
  props
) => {
  const theme = useTheme();
  const { fetchHydrateExpression, fetchHydrateRuleExpression } =
    useExpressionValidator();
  const axiosFactory = useAxiosFactory();
  const {
    open,
    expression,
    ddxProps,
    handleOnCloseButtonClick,
    targetType,
    targetKey,
    children,
    setValue,
    isComplexRule,
  } = props;
  const [gridExpression, setState] = useState(expression);
  const [initialValues, setInitialValues] = useState<{ [x: string]: string }>(
    expressionToFieldValues(expression)
  );
  const [isEditorEnabled, setIsEditorEnabled] = useState(false);
  const [openRuleSelect, setOpenRuleSelect] = useState<boolean>(false);
  const [ruleToEdit, setRuleToEdit] = useState<Expression | null>(null);
  const [ddxErrors, setDdxErrors] = useState<
    DdxTranslationError[] | undefined
  >();
  const exprDescription = useRef<string>("");
  const editorVal = useRef<string>("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [failed, setFailed] = useState<boolean>(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isPassThrough, setIsPassThrough] = useState(false);

  const [hydratedExpressions, setHydratedExpressions] = useState<{
    [key: number]: string | null;
  }>({});

  const { error } = useMessageAnnouncer();
  useEffect(() => {
    setState([...expression]);
    setFailed(false);
    return () => {
      if (!isComplexRule) {
        setIsEditorEnabled(false);
      }
      setDdxErrors([]);
    };
  }, [expression, open, isComplexRule]);

  useEffect(() => {
    setInitialValues(expressionToFieldValues([...expression]));
  }, [expression, ddxProps]);

  const compOperator = (
    dataDictionaryFieldName: string,
    valueType: string
  ) => ({
    options: comparisonOperatorList?.filter(function (listItem) {
      const field = {
        ...getDdxFieldByDisplayName(
          ddxProps.ddxFields,
          dataDictionaryFieldName
        )[0],
      };
      field.lookup_type = valueType === "F" ? null : field.lookup_type;
      return listItem.applicable(field);
    }),
  });

  useEffect(() => {
    if (isComplexRule) {
      setIsEditorEnabled(true);
      const exprDesc = getFriendlyDescription(expression);
      exprDescription.current = exprDesc;
      isEditorDirty.current = false;
    }
  }, [isComplexRule]);

  const toggleEditor = async (
    setValues: ExpressionBuilderState["setValues"]
  ) => {
    if (isPassThroughCode(editorRef?.current?.getValue() ?? "")) {
      return;
    }

    if (
      isEditorEnabled &&
      editorRef.current &&
      editorRef?.current?.getValue()?.trim()?.length > 0
    ) {
      const modelExpression = await hydrateExpression(
        editorRef?.current?.getValue()
      );

      if (modelExpression.ddx_errors.length === 0) {
        setDdxErrors([]);
        const expressions = modelExpressionToExpressions(
          modelExpression,
          ddxProps.ddxFields,
          ddxProps.ddxFunctions
        );
        setValues(expressionToFieldValues(expressions));
        setState(expressions);
        setIsEditorEnabled((s) => !s);
      } else {
        setIsEditorEnabled(true);
        setDdxErrors(modelExpression.ddx_errors);
        modelExpression?.ddx_errors?.forEach((err) => {
          error(`${err.message_code}: ${err.message}`);
        });
      }
    } else {
      if (
        isEditorEnabled &&
        editorRef?.current?.getValue()?.trim()?.length === 0
      ) {
        setValues({});
        setState([]);
      }
      setIsEditorEnabled((s) => !s);
    }
  };

  const handleSubmit = useCallback(
    async (values: { [x: string]: string }) => {
      try {
        const expressions: Expression[] = fieldValuesToExpressions(
          [...gridExpression],
          values,
          ddxProps
        );

        setState(expressions);
        const editorValue = editorVal.current;
        exprDescription.current = editorValue ?? exprDescription.current;
        editorRef?.current?.setValue(
          isEditorEnabled
            ? editorValue
            : getFriendlyDescription(expressions) ?? ""
        );
        setIsSubmitting(true);
        const modelExpression = await fetchHydrateExpression(
          "FILTER_EXPRESSION",
          isEditorEnabled ? editorValue : getFriendlyDescription(expressions),
          "bool"
        );

        if (modelExpression.ddx_errors.length === 0) {
          setDdxErrors([]);
          if (setValue) {
            setValue(modelExpression);
          } else {
            const axios = await axiosFactory.createAxiosInstance();
            await axios.put(`/compliance-modeling/v1/expressionput`, {
              target_type: targetType,
              target_key: targetKey,
              ddx: modelExpression.ddx,
            });
          }
          handleOnCloseButtonClick ? handleOnCloseButtonClick() : null;
        } else {
          setDdxErrors(modelExpression.ddx_errors);
          setFailed(true);
        }
        isEditorDirty.current = false;
      } catch (err) {
        error("Error: Saving Expression");
      } finally {
        setIsSubmitting(false);
      }
    },
    [
      axiosFactory,
      ddxProps,
      error,
      fetchHydrateExpression,
      gridExpression,
      handleOnCloseButtonClick,
      isEditorEnabled,
      setValue,
      targetKey,
      targetType,
    ]
  );

  const hydrateExpression = async (friendlyDescription?: string) => {
    return await fetchHydrateExpression(
      "FILTER_EXPRESSION",
      friendlyDescription,
      "bool"
    );
  };

  const hydrateRuleExpression = async (friendlyDescription?: string) => {
    return await fetchHydrateRuleExpression(
      "FILTER_EXPRESSION",
      friendlyDescription,
      "bool"
    );
  };

  const isEditorDirty = useRef(false);

  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const handleGetEditorRef = (editor: monaco.editor.IStandaloneCodeEditor) => {
    editorRef.current = editor;
    editorRef?.current?.onDidChangeModelContent(() => {
      isEditorDirty.current = true;
      setIsPassThrough(isPassThroughCode(editorRef?.current?.getValue() ?? ""));
    });
    // Set initial passthrough state
    setIsPassThrough(isPassThroughCode(editorRef?.current?.getValue() ?? ""));
  };

  const getFriendlyDesc = useCallback(() => {
    editorVal.current = editorRef?.current?.getValue() ?? "";
    if (!isEditorEnabled || isEditorDirty.current) {
      return editorRef?.current?.getValue() ?? "";
    } else {
      return exprDescription.current ?? "";
    }
  }, [isEditorEnabled]);
  const onDdxToDetailsRef = useRef<(() => void) | null>(null);

  const handleClose = useCallback(() => {
    setIsFullScreen(false);
    handleOnCloseButtonClick?.();
  }, [handleOnCloseButtonClick]);

  return (
    <Box>
      <Dialog
        open={open}
        fullWidth
        fullScreen={isFullScreen}
        PaperProps={{
          sx: !isFullScreen ? getDialogResizePaperPropsSx("xl") : {},
        }}
        draggable={true}
      >
        <Formik
          initialValues={initialValues}
          enableReinitialize={true}
          onSubmit={async (values) => {
            handleSubmit(values);
          }}
        >
          {({ handleSubmit, values, setValues }) => (
            <FormValidateField>
              <form onSubmit={handleSubmit}>
                <DialogTitle>
                  <Stack
                    direction="row"
                    alignItems="center"
                    justifyContent="space-between"
                  >
                    Expression Builder
                    <Stack direction="row">
                      <IconButton
                        sx={(theme) => ({
                          color: theme.palette.primary.contrastText,
                          mr: 1,
                        })}
                        aria-label={
                          isFullScreen
                            ? "Exit full screen"
                            : "Enter full screen"
                        }
                        onClick={() => setIsFullScreen((prev) => !prev)}
                      >
                        {isFullScreen ? (
                          <CollapseIcon size={20} />
                        ) : (
                          <ExpandIcon size={20} />
                        )}
                      </IconButton>
                      <IconButton
                        aria-label="close"
                        onClick={handleClose}
                        sx={(theme) => ({
                          color: theme.palette.primary.contrastText,
                        })}
                      >
                        <CloseIcon size={20} />
                      </IconButton>
                    </Stack>
                  </Stack>
                </DialogTitle>
                <ProgressOrDivider isLoading={isSubmitting} />
                <ExpressionBuilderContextProvider
                  expression={gridExpression}
                  ddxData={ddxProps}
                  setState={setState}
                  values={values}
                  setValues={setValues}
                >
                  <DialogContent>
                    <Box sx={topBoxSx}>
                      <Box sx={shimBoxSx}></Box>
                      <ToolGroup sx={{ gap: 1 }}>
                        <FormControlLabel
                          label={
                            isPassThrough
                              ? "View Editor (Disabled - Complex Rule)"
                              : "View Editor"
                          }
                          sx={{
                            flex: "1 1 0px",
                            opacity: isPassThrough ? 0.5 : 1,
                          }}
                          control={
                            <Checkbox
                              checked={isEditorEnabled}
                              disabled={isPassThrough}
                            />
                          }
                          onClick={(e) => {
                            e.preventDefault();
                            toggleEditor(setValues);
                            if (!isEditorEnabled) {
                              const expressions: Expression[] =
                                fieldValuesToExpressions(
                                  [...gridExpression],
                                  values,
                                  ddxProps
                                );
                              const exprDesc =
                                getFriendlyDescription(expressions);

                              exprDescription.current = exprDesc;
                              isEditorDirty.current = false;
                            }
                          }}
                        />

                        {!isEditorEnabled && !isComplexRule ? (
                          <>
                            <Divider orientation="vertical" flexItem></Divider>
                            {children}
                          </>
                        ) : (
                          <Button
                            variant="outlined"
                            onClick={() => onDdxToDetailsRef.current?.()}
                          >
                            Ddx to Details
                          </Button>
                        )}
                      </ToolGroup>
                    </Box>
                    {isEditorEnabled ? (
                      <>
                        <DdxEditorDetails
                          ddxProps={ddxProps}
                          getFriendlyDescription={getFriendlyDesc}
                          getEditorRef={handleGetEditorRef}
                          errors={ddxErrors}
                          exprDesc={exprDescription}
                          onDdxToDetailsRef={onDdxToDetailsRef}
                        ></DdxEditorDetails>
                      </>
                    ) : (
                      <Box
                        sx={{
                          flex: 1,
                          maxHeight: "60vh",
                          overflow: "auto",
                          borderRadius: "4px",
                        }}
                      >
                        <Box
                          sx={{
                            display: "grid",
                            gridTemplateColumns: gridTemplateColumns,
                            backgroundColor: theme.palette.primary.main,
                            color: theme.palette.primary.contrastText,
                          }}
                          gap={1}
                        >
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            S.No.
                          </Typography>
                          <Divider
                            orientation="vertical"
                            sx={{ bgcolor: theme.palette.primary.contrastText }}
                          />
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            AND, OR, NOT
                          </Typography>
                          <Divider
                            orientation="vertical"
                            sx={{ bgcolor: theme.palette.primary.contrastText }}
                          />
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            (...(
                          </Typography>
                          <Divider
                            orientation="vertical"
                            sx={{ bgcolor: theme.palette.primary.contrastText }}
                          />
                          <Typography
