import { SxProps, Theme, useTheme } from "@textile/mui";
import * as monaco from "monaco-editor";
import { useEffect } from "react";

import {
  hoverProvider,
  provideCompletionItems,
  signatureHelpProvider,
} from "./ddx-helper";
import {
  DdxField,
  DdxFunction,
  DdxData,
  DdxTranslationError,
} from "../../solvasam-bizcomponents";
import { MonacoEditor } from "./monaco-editor.component";
import { MonacoHelper } from "./monaco-helper";

// eslint-disable-next-line @typescript-eslint/ban-ts-comment
// @ts-ignore
self.MonacoEnvironment = {
  getWorkerUrl: function () {
    return "/solvasam-bizcomponents/editor.worker.js";
  },
};

export const passThroughFunctionSuggestion = [
  {
    label: "<",
    kind: monaco.languages.CompletionItemKind.Interface,
    documentation: "Passthrough Text",
    insertText: "%${0},,,,%>",
    example: "<% Lien Type, LIEN_TYPE, TEXT, FALSE, V %>",
    params: [
      {
        id: "Parameter Name",
        parameter_name: "Parameter Name",
        description: `[Lien Type] = <% Lien Type, LIEN_TYPE, TEXT, FALSE, V %>`,
      },
      {
        id: `Lookup Type`,
        parameter_name: `Lookup Type`,
        description: `Type ctrl+space to get list of lookup types`,
      },
      {
        id: `Data Type`,
        parameter_name: `Data Type`,
        description: `TEXT, DATE, NUMERIC, CURRENCY, PERCENT, BOOLEAN`,
      },
      {
        id: `Multi Value`,
        parameter_name: `Multi Value`,
        description: `True or False`,
      },
      {
        id: `Type`,
        parameter_name: `Type`,
        description: ` 'F' for Field and 'V' for Variable`,
      },
    ],
    insertTextRules:
      monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
  },
];

const mapFieldToDdxSuggestion = (r: DdxField) => ({
  label: `${r.aggregation_level_description}: ${r.display_name}`,
  kind: monaco.languages.CompletionItemKind.Field,
  documentation: r.display_name ?? "",
  insertText: `${r.display_name ?? r.field_name}` + "${1}",
  insertTextRules:
    monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
  lookup_type: r.lookup_type,
  display_name: r.display_name,
  data_type: r.data_type,
  code: r.field_name,
  name: r.display_name,
});
const mapFunctionToDdxSuggestion = (r: Partial<DdxFunction>) => ({
  label: r.function_name,
  kind: monaco.languages.CompletionItemKind.Function,
  documentation: r.friendly_description ?? "",
  insertText: r.function_name,
  insertTextRules:
    monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
  params: r?.parameters,
  is_rule: r?.is_rule,
  example: r?.example ?? "",
  code: r.function_name,
  name: r.function_name,
});

const MonacoDdxEditor = (
  props: DdxData & {
    value?: string;
    ddxTranslationErrors?: DdxTranslationError[];
    onChange?: (value: string) => void;
    getEditorRef?: (editorRef: monaco.editor.IStandaloneCodeEditor) => void;
    editorOptions?: monaco.editor.IStandaloneEditorConstructionOptions;
    editorSx?: SxProps<Theme>;
  }
) => {
  const {
    ddxFields,
    ddxFunctions,
    fetchLookupItems,
    fetchLookupTypes,
    ddxTranslationErrors,
    value,
    onChange,
    getEditorRef,
    editorOptions,
  } = props;

  useEffect(() => {
    if (ddxFields?.length > 0 && ddxFunctions?.length > 0) {
      MonacoHelper.register(
        "ddx",
        {
          provideCompletionItems: provideCompletionItems(
            [
              ...ddxFields?.map(mapFieldToDdxSuggestion),
              ...ddxFunctions?.map(mapFunctionToDdxSuggestion),
            ],
            fetchLookupItems,
            fetchLookupTypes
          ),
          triggerCharacters: ["[", " ", "<"],
        },
        signatureHelpProvider([
          ...ddxFields?.map(mapFieldToDdxSuggestion),
          ...ddxFunctions?.map(mapFunctionToDdxSuggestion),
          ...passThroughFunctionSuggestion,
        ]),
        {
          provideHover: hoverProvider([
            ...ddxFields?.map(mapFieldToDdxSuggestion),
            ...ddxFunctions?.map(mapFunctionToDdxSuggestion),
          ]),
        }
      );
    }
  }, [fetchLookupItems, ddxFields, ddxFunctions, fetchLookupTypes]);
  const theme = useTheme();
  return (
    <MonacoEditor
      initialValue={value}
      ddxTranslationErrors={ddxTranslationErrors}
      onChange={onChange}
      getEditorRef={getEditorRef}
      sx={{
        minHeight: "30vh",
        paddingTop: "25px",
        maxWidth: "100%",
        backgroundColor: "#ffffff",
        overflow: "visible",
      }}
      monacoEditorOptions={{
        fontSize: 12,
        fontFamily: theme.typography.fontFamily,
        ...editorOptions,
      }}
    />
  );
};
export { MonacoDdxEditor };

import * as monaco from "monaco-editor";

let registeredItems: { type: string; disposable: monaco.IDisposable }[] = [];

export class MonacoHelper {
  static register(
    languageId: string,
    completionProvider: monaco.languages.CompletionItemProvider,
    signatureProvider: monaco.languages.SignatureHelpProvider,
    hoverProvider: monaco.languages.HoverProvider
  ) {
    if (registeredItems.length == 0) {
      registeredItems.push({
        type: "ddxCompletion",
        disposable: monaco.languages.registerCompletionItemProvider(
          languageId,
          completionProvider
        ),
      });

      registeredItems.push({
        type: "ddxSignature",
        disposable: monaco.languages.registerSignatureHelpProvider(
          languageId,
          signatureProvider
        ),
      });
      registeredItems.push({
        type: "ddxHover",
        disposable: monaco.languages.registerHoverProvider(
          languageId,
          hoverProvider
        ),
      });
    }
  }
}

export const useMonacoDispose = () => {
  const disposeFunction = () => {
    registeredItems.map((registeredItem) => {
      registeredItem.disposable.dispose();
    });
    registeredItems = [];
  };
  return { disposeFunction };
};

