onClick: () => void;
  ddxProps: DdxData;
  expression?: Expression;
  setHydratedExpressions?: React.Dispatch<
    React.SetStateAction<{
      [key: number]: string | null;
    }>
  >;
}

export const comparisonOperatorOptions = [
  { value: "=", label: "Equals" },
  { value: "<>", label: "Is Not Equal To" },
  { value: ">", label: "Is Greater Than" },
  { value: ">=", label: "Is Greater Than Or Equal To" },
  { value: "<", label: "Is Less Than" },
  { value: "<=", label: "Is Less Than Or Equal To" },
];
const topBoxSx: SxProps<Theme> = {
  py: 3,
};

const getTextFromLookUps = async (
  parameter: DdxFunctionParameter,
  values: { [x: string]: string },
  fetchLookupItems?: (
    lookupKey: string
  ) => Promise<AxiosResponse<GetLookupItemsResponse> | undefined>
) => {
  if (parameter && parameter?.lookup_type) {
    if (parameter?.lookup_type?.toLowerCase().trim() == "comparison_operator") {
      const compOperator = comparisonOperatorOptions.find(
        (f) => f.label?.toLowerCase() == values[parameter.id]?.toLowerCase()
      );
      return compOperator ? compOperator?.value : values[parameter.id];
    }
    const lookUpResponse =
      parameter.param_type?.trim()?.toLowerCase() === "v" &&
      parameter?.lookup_type &&
      parameter?.lookup_type?.trim()?.length > 0 &&
      fetchLookupItems
        ? await fetchLookupItems(parameter?.lookup_type?.trim())
        : {
            data: {
              lookup_items: [],
            },
          };

    const loookups =
      lookUpResponse?.data?.lookup_items &&
      lookUpResponse?.data?.lookup_items?.length > 0
        ? lookUpResponse?.data?.lookup_items
        : [];
    if (loookups && loookups.length > 0) {
      const currentLookup = loookups.find(
        (f) =>
          f.description?.toLowerCase() == values[parameter.id]?.toLowerCase() ||
          f.code?.toLowerCase() == values[parameter.id]?.toLowerCase()
      );
      return currentLookup
        ? parameter.param_type?.trim()?.toLowerCase() === "v"
          ? currentLookup.code
          : currentLookup.description
        : "";
    }
  }
  return values[parameter.id];
};

export const SelectRuleDialog: FunctionComponent<SelectRuleDialogProps> = (
  props
) => {
  const { open, handleOnCloseButtonClick, ddxProps, expression } = props;
  const [initialValues, setInitialValues] = useState<{ [x: string]: string }>(
    {}
  );
  const { values, setState, ddxData } = useExpressionBuilderContext();
  const { fetchHydrateRuleExpression } = useExpressionValidator();
  const previousExpression = useCallback(
    (expressions: Expression[]) => {
