import { createContext, ReactNode, useContext } from "react";
import { DdxData, useDdxValues } from "../solvasam-bizcomponents";

const DdxContext = createContext<DdxData | null>(null);

export const DdxProvider = ({ children }: { children: ReactNode }) => {
  const ddxData = useDdxValues();

  return <DdxContext.Provider value={ddxData}>{children}</DdxContext.Provider>;
};

export const useDdx = (): DdxData | null => {
  const context = useContext(DdxContext);

  if (context === undefined) {
    throw new Error("useDdx must be used within a DdxProvider");
  }

  return context;
};

