export * from "./ddx.types";
export * from "./monaco-ddx-editor.component";
export * from "./ddx-values";

import { useAxiosFactory } from "@textile/common";
import { useEffect, useMemo, useRef, useState } from "react";

import {
  DdxData,
  DdxField,
  DdxFunction,
  DdxResponseData,
  FieldsGetResponse,
  FunctionsGetResponse,
} from "./ddx.types";
import {
  GetLookupItemsResponse,
  GetLookupTypesResponse,
} from "../common.types";
import { useSelectedPortfolioId } from "../../hooks/selected-portfolio-id.hook";

export const useDdxValues = (purpose = "FILTER_EXPRESSION"): DdxData => {
  const [ddxFields, setDdxFields] = useState<DdxField[]>([]);
  const [ddxFunctions, setDdxFunctions] = useState<DdxFunction[]>([]);
  const { createAxiosInstance } = useAxiosFactory();
  const [selectedPortfolio] = useSelectedPortfolioId();

  const fetchFieldUrl = useMemo(
    () =>
      selectedPortfolio
        ? `/compliance-bff/v1/portfolios/${selectedPortfolio}/fields:ddx?paging.filter=purpose="${purpose}"`
        : `/compliance-bff/v1/fields:ddx?paging.filter=purpose="${purpose}"`,
    [purpose, selectedPortfolio]
  );

  const fieldUrlRef = useRef<string | null>();
  const fetchLookupItems = async (lookupKey: string) => {
    if (createAxiosInstance) {
      const axios = await createAxiosInstance();

      return axios.get<GetLookupItemsResponse>(
        `/solvasam-bff/v1/lookupTypes/${lookupKey}/lookupItems`
      );
    }
  };
  const fetchLookupTypes = async () => {
    if (createAxiosInstance) {
      const axios = await createAxiosInstance();

      return axios.get<GetLookupTypesResponse>(`/solvasam-bff/v1/lookupTypes`);
    }
  };

  useEffect(() => {
    const loadFunctions = async () => {
      const axios = await createAxiosInstance();
      return axios.get<FunctionsGetResponse>(
        `/compliance-bff/v1/functions:ddx`
      );
    };
    const loadFields = async () => {
      const axios = await createAxiosInstance();
      return axios.get<FieldsGetResponse>(fetchFieldUrl);
    };

    const setDdxState = (
      fieldsData?: FieldsGetResponse,
      functionsData?: FunctionsGetResponse
    ) => {
      if (fieldsData) {
        setDdxFields(fieldsData?.fields);
      }
      if (functionsData) {
        setDdxFunctions(functionsData?.functions);
      }
    };

    if (selectedPortfolio && fieldUrlRef.current != selectedPortfolio) {
      fieldUrlRef.current = selectedPortfolio;
    }
    const fetchDdx = async () => {
      let serializedFields: FieldsGetResponse | undefined = undefined;
      let serializedFunctions: FunctionsGetResponse | undefined = undefined;
      const results = await Promise.allSettled([
        await loadFields(),
        await loadFunctions(),
      ]);
      results?.forEach(
        (response: PromiseSettledResult<DdxResponseData>, index) => {
          if (response.status === "fulfilled") {
            switch (index) {
              case 0:
                serializedFields = response.value.data as FieldsGetResponse;
                break;
              case 1:
                serializedFunctions = {
                  functions: [
                    {
                      name: "",
                      id: crypto.randomUUID(),
                      lid: crypto.randomUUID(),
                      code: "AND",
                      function_name: "AND",
                      description: "AND",
                      friendly_description: "AND Operator",
                      purpose: null,
                      is_built_in: true,
                      example: "",
                      parameters: [],
                      is_rule: false,
                    } as DdxFunction,
                    {
                      name: "",
                      id: crypto.randomUUID(),
                      lid: crypto.randomUUID(),
                      code: "OR",
                      function_name: "OR",
                      description: "OR",
                      friendly_description: "OR Operator",
                      purpose: null,
                      is_built_in: true,
                      example: "",
                      parameters: [],
                      is_rule: false,
                    } as DdxFunction,
                    {
                      name: "",
                      id: crypto.randomUUID(),
                      lid: crypto.randomUUID(),
                      code: "NOT",
                      function_name: "NOT",
                      description: "NOT",
                      friendly_description: "NOT Operator",
                      purpose: null,
                      is_built_in: true,
                      example: "",
                      parameters: [],
                      is_rule: false,
                    } as DdxFunction,
                    ...(response.value.data as FunctionsGetResponse)?.functions,
                  ],
                };
                break;

              default:
                break;
            }
          }
        }
      );

      setDdxState(serializedFields, serializedFunctions);
    };

    fetchDdx();
  }, [createAxiosInstance, fetchFieldUrl, selectedPortfolio]);

  return {
    ddxFields,
    ddxFunctions,
    fetchLookupItems: fetchLookupItems,
    fetchLookupTypes: fetchLookupTypes,
  };
};

