import { Box, SxProps, useTheme } from "@textile/mui";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import * as monaco from "monaco-editor";

import { MonacoEditor } from "../monaco-ddx-editor/monaco-editor.component";
import {
  DdxData,
  DdxField,
  DdxFunction,
  useDdxValues,
} from "../monaco-ddx-editor";
import { hoverProvider } from "../monaco-ddx-editor/ddx-helper";
import {
  MonacoHelper,
  useMonacoDispose,
} from "../monaco-ddx-editor/monaco-helper";
import { replaceParameters } from "../helpers";
import { useDdx } from "../../contexts/ddxContext";

interface RuleDisplayComponentProps {
  value?: string;
  friendlyReq?: boolean;
}

const mapFunctionToDdxSuggestion = (r: Partial<DdxFunction>) => ({
  label: r.function_name,
  kind: monaco.languages.CompletionItemKind.Function,
  documentation: r.friendly_description ?? "",
  insertText: r.function_name,
  insertTextRules:
    monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
  params: r?.parameters,
  is_rule: r?.is_rule,
  example: r?.example ?? "",
  code: r.function_name,
  name: r.function_name,
});

export const RuleDisplayComponent = ({
  friendlyReq = true,
  ...props
}: RuleDisplayComponentProps) => {
  const theme = useTheme();
  const ddxData = useDdx();
  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const [height, setHeight] = useState<number>(40);
  const { disposeFunction } = useMonacoDispose();
  const monacoEditorSx = useMemo<SxProps>(
    () => ({
      minWidth: "100%",
      height: `${height}px`,
      overflow: "hidden",
      display: "flex",
      fontSize: theme.typography.caption.fontSize,
      backgroundColor: theme.palette.background.paper,
      "& .monaco-hover": {
        backgroundColor: "#000000 !important",
        border: "1px solid #000000 !important",
        maxWidth: "400px !important",
        maxHeight: "400px !important",
        zIndex: 9999,
        whiteSpace: "pre-wrap !important",
        wordWrap: "break-word !important",
        position: "fixed !important",
        cursor: "pointer",
      },
      "& .monaco-hover .hover-contents": {
        color: "#ffffff !important",
      },
      "& .monaco-hover .hover-row": {
        color: "#ffffff !important",
      },
      "& .monaco-editor .hoverHighlight": {
        fontWeight: 600,
      },
    }),
    [height, theme]
  );

  useEffect(() => {
    if (ddxData && ddxData?.ddxFunctions?.length > 0) {
      MonacoHelper.register(
        "ddx",
        {
          provideCompletionItems: () => Promise.resolve({ suggestions: [] }),
          triggerCharacters: [],
        },
        {
          provideSignatureHelp: () => ({
            dispose: () => {},
            value: { activeParameter: 0, activeSignature: 0, signatures: [] },
          }),
          signatureHelpTriggerCharacters: [],
        },
        {
          provideHover: hoverProvider([
            ...ddxData.ddxFunctions.map(mapFunctionToDdxSuggestion),
          ]),
        }
      );
    }
  }, [ddxData]);

  const handleGetEditorRef = useCallback(
    (editor: monaco.editor.IStandaloneCodeEditor) => {
      editorRef.current = editor;
      let lastRangeKey = "";
      const decorations = editor.createDecorationsCollection();

      const updateHeight = () => {
        const contentHeight = Math.min(500, editor.getContentHeight());
        setHeight(contentHeight);
      };

      editor.onDidContentSizeChange(updateHeight);
      updateHeight();

      editor.onMouseMove(async (e: any) => {
        if (!e.target.position) return;
        const model = editor.getModel();
        if (!model) return;
        const word = model.getWordAtPosition(e.target.position);
        if (!word) return;

        const wordText = model.getValueInRange({
          startLineNumber: e.target.position.lineNumber,
          startColumn: word.startColumn,
          endLineNumber: e.target.position.lineNumber,
          endColumn: word.endColumn,
        });

        const isValidFunction = ddxData?.ddxFunctions?.some(
          (fn) => fn.function_name === wordText
        );

        if (!isValidFunction) return;

        const range = new monaco.Range(
          e.target.position.lineNumber,
          word.startColumn,
          e.target.position.lineNumber,
          word.endColumn
        );

        const rangeKey = `${range.startLineNumber},${range.startColumn},${range.endLineNumber},${range.endColumn}`;
        if (rangeKey === lastRangeKey) return;

        lastRangeKey = rangeKey;
        decorations.set([
          { range, options: { inlineClassName: "hoverHighlight" } },
        ]);
      });

      editor.onMouseLeave(() => {
        decorations.clear();
        lastRangeKey = "";
      });
    },
    [ddxData]
  );

  return (
    <Box sx={{ display: "flex", flex: 1, overflow: "auto" }}>
      <MonacoEditor
        sx={monacoEditorSx}
        initialValue={
          friendlyReq ? replaceParameters(props.value ?? "") : props.value
        }
        monacoEditorOptions={{
          readOnly: true,
          fontSize: 12,
          lineNumbers: "off",
          lineDecorationsWidth: 0,
          lineNumbersMinChars: 0,
          minimap: { enabled: false },
          contextmenu: false,
          automaticLayout: true,
          scrollBeyondLastLine: false,
          wrappingStrategy: "advanced",
          overviewRulerLanes: 0,
          folding: false,
          roundedSelection: false,
          hideCursorInOverviewRuler: true,
          overviewRulerBorder: false,
          renderLineHighlight: "none",
          wordWrap: "on",
          wrappingIndent: "same",
          hover: {
            enabled: true,
            sticky: true,
          },
          occurrencesHighlight: "off",
          scrollbar: {
            vertical: "hidden",
            horizontal: "hidden",
            handleMouseWheel: false,
          },
        }}
        getEditorRef={handleGetEditorRef}
      />
    </Box>
  );
};

