import { SxProps, createTheme } from "@textile/mui";
import numeral from "numeral";

export const INVISIBLE_DELIMITER = "\u200B";
const COMPLEX_RULE_REGEX = /<%[\s\S]*?%>/;

export const INVISIBLE_DELIMITER_REGEX_PATTERN = new RegExp(
  `${INVISIBLE_DELIMITER}(?:[^${INVISIBLE_DELIMITER}]|${INVISIBLE_DELIMITER}')*${INVISIBLE_DELIMITER}`,
  "g"
);

export const WrapWithInvisibleDelimiter = (value: string | string[]) => {
  return (INVISIBLE_DELIMITER + value + INVISIBLE_DELIMITER)
    .replace(/'/g, INVISIBLE_DELIMITER + "'")
    .replaceAll(INVISIBLE_DELIMITER + INVISIBLE_DELIMITER, INVISIBLE_DELIMITER);
};

export const wrapMultiValues = (value: string | string[]) => {
  if (Array.isArray(value)) {
    return value.map((v) => {
      return WrapWithInvisibleDelimiter(v);
    });
  } else {
    return value?.split(",").map((v) => {
      return WrapWithInvisibleDelimiter(v);
    });
  }
};

export const isNullCheckOperator = (operator: string): boolean => {
  return ["IS NULL", "IS NOT NULL"].includes(operator?.trim()?.toUpperCase());
};
export const isRangeOperator = (operator: string): boolean => {
  return ["IS BETWEEN", "IS NOT BETWEEN"].includes(
    operator?.trim()?.toUpperCase()
  );
};
export const isMultiValueOperator = (operator: string): boolean => {
  return ["IS ONE OF", "IS NOT ONE OF"].includes(
    operator?.trim()?.toUpperCase()
  );
};
export const isLikeOperator = (operator: string): boolean => {
  return ["IS LIKE", "IS NOT LIKE"].includes(operator?.trim()?.toUpperCase());
};

export const unwrapValue = (
  comparison_operator: string | null | undefined,
  value: string | null | undefined
) => {
  const res = value
    ? !isMultiValueOperator(comparison_operator ?? "")
      ? replaceUniCodeForSingleValue(value)
      : value
    : "";
  return res;
};

export const replaceUniCodeForMultiValues = (
  value: string | null | undefined
) => {
  if (!value) return "";
  const items = value.split(
    new RegExp(`${INVISIBLE_DELIMITER},\\s*${INVISIBLE_DELIMITER}`)
  );
  return items.map((item) => replaceUniCodeForSingleValue(item));
};

export const replaceUniCodeForSingleValue = (
  value: string | null | undefined
) => {
  if (!value || typeof value != "string") return "";
  return value
    .replace(new RegExp(`^${INVISIBLE_DELIMITER}`), "")
    .replace(new RegExp(`${INVISIBLE_DELIMITER}$`), "")
    .replace(new RegExp(`${INVISIBLE_DELIMITER}'`, "g"), "'");
};

const breakpoints = createTheme().breakpoints.values;

const resolveDialogWidth = (width?: string | number): string | number => {
  if (!width) width = "sm";
  if (typeof width === "number") return width;
  return breakpoints[width as keyof typeof breakpoints] || width;
};

export const getDialogResizePaperPropsSx = (
  width?: string | number
): SxProps => ({
  resize: "both",
  overflow: "auto",
  maxWidth: "none", // <-- allow resizing
  width: resolveDialogWidth(width), //accepts 3 formats "1200px", 1200 or lg
});

export const formatFormula = (formula: string | null | undefined): string => {
  return formula?.replace("dbo.", "") ?? "";
};

export const percentFormat = (
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  value: any,
  format?: string,
  nullFormat?: string
): string => {
  if (value == null) {
    return nullFormat ?? "";
  }
  const formattedValue = format
    ? numeral(value).format(format.replace("%%", "").trim())
    : value.toString();
  return `${formattedValue}%`;
};

export const adjustDateTimeOffset = (
  asOfDate: Date,
  addOffsetHours: boolean
) => {
  const utcOffset = asOfDate.getTimezoneOffset();
  const offsetHours = -utcOffset / 60;

  const hours = Math.floor(offsetHours);
  const minutes = Math.round((offsetHours - hours) * 60);
  const adjustedDate = new Date(asOfDate.getTime());

  if (addOffsetHours) {
    adjustedDate.setHours(adjustedDate.getHours() + Math.abs(hours));
    adjustedDate.setMinutes(adjustedDate.getMinutes() + Math.abs(minutes));
  }

  return adjustedDate.toISOString();
};

export const isPassThroughCode = (expression: string) => {
  return COMPLEX_RULE_REGEX.test(expression);
};

// This is to replace
export const replaceParameters = (value: string) => {
  if (!value || value.trim() === "") return value;

  //Replace {} of multi value parameters with ()
  //e.g. ThirdPartyCreditExposure({​ABS​}, {​A-1+​, ​A-2​}, {​A-​, ​AA​}, {OS​, ​SP}, {​B​})
  //with ThirdPartyCreditExposure((​ABS​), (​A-1+​, ​A-2​), (​A-​, ​AA​), (​OS​, ​SP​), (​B​))
  value = value.replace(/{/g, "(").replace(/}/g, ")");
  if (isPassThroughCode(value)) {
    //Replace placeholder parameters with {Parameter Name}
    //e.g. [security_type] IN (<% Security Type, SECURITY_TYPE, TEXT, TRUE, V %>)
    //with [Security Type] Is One Of ({Security Type})
    value = value.replace(
      /<%\s*([^,]+),[^%]*%>/g,
      (_match, p1) => `{${p1.trim()}}`
    );
  }

  return value;
};

import { Box, SxProps, useTheme } from "@textile/mui";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import * as monaco from "monaco-editor";

import { MonacoEditor } from "../monaco-ddx-editor/monaco-editor.component";
import { DdxData, DdxFunction } from "../monaco-ddx-editor";
import { hoverProvider } from "../monaco-ddx-editor/ddx-helper";
import {
  MonacoHelper,
  useMonacoDispose,
} from "../monaco-ddx-editor/monaco-helper";
// import { useDdx } from "../../contexts/ddxContext";
import { normalizeParameterSyntax } from "../helpers";

interface RuleDisplayComponentProps {
  value?: string;
  ddxData?: DdxData;
  friendlyReq?: boolean;
}

const mapFunctionToDdxSuggestion = (r: Partial<DdxFunction>) => ({
  label: r.function_name,
  kind: monaco.languages.CompletionItemKind.Function,
  documentation: normalizeParameterSyntax(r.friendly_description ?? ""),
  insertText: r.function_name,
  insertTextRules:
    monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
  params: r?.parameters,
  is_rule: r?.is_rule,
  example: r?.example ?? "",
  code: r.function_name,
  name: r.function_name,
});

export const RuleDisplayComponent = ({
  friendlyReq = true,
  ...props
}: RuleDisplayComponentProps) => {
  const theme = useTheme();
  // const ddxData = useDdx();
  const ddxData = props.ddxData;

  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const [height, setHeight] = useState<number>(40);
  const monacoEditorSx = useMemo<SxProps>(
    () => ({
      minWidth: "100%",
      height: `${height}px`,
      overflow: "hidden",
      // position: "relative",
      display: "flex",
      fontSize: theme.typography.caption.fontSize,
      backgroundColor: theme.palette.background.paper,
      "& .monaco-hover": {
        backgroundColor: "#000000 !important",
        border: "1px solid #000000 !important",
        maxWidth: "400px !important",
        maxHeight: "400px !important",
        // position: "fixed !important",
        zIndex: "999999 !important",
        whiteSpace: "pre-wrap !important",
        wordWrap: "break-word !important",
        cursor: "pointer",
      },
      "& .monaco-hover .hover-contents": {
        color: "#ffffff !important",
      },
      "& .monaco-hover .hover-row": {
        color: "#ffffff !important",
      },
      "& .monaco-editor .hoverHighlight": {
        fontWeight: 600,
      },
    }),
    [height, theme]
  );

  useEffect(() => {
    if (ddxData && ddxData?.ddxFunctions?.length > 0) {
      MonacoHelper.register(
        "ddx",
        {
          provideCompletionItems: () => Promise.resolve({ suggestions: [] }),
          triggerCharacters: [],
        },
        {
          provideSignatureHelp: () => ({
            dispose: () => {},
            value: { activeParameter: 0, activeSignature: 0, signatures: [] },
          }),
          signatureHelpTriggerCharacters: [],
        },
        {
          provideHover: hoverProvider([
            ...ddxData.ddxFunctions.map(mapFunctionToDdxSuggestion),
          ]),
        }
      );
    }
  }, [ddxData]);

  const handleGetEditorRef = useCallback(
    (editor: monaco.editor.IStandaloneCodeEditor) => {
      editorRef.current = editor;
      let lastRangeKey = "";
      const decorations = editor.createDecorationsCollection();

      const updateHeight = () => {
        const contentHeight = Math.min(500, editor.getContentHeight());
        setHeight(contentHeight);
      };

      editor.onDidContentSizeChange(updateHeight);
      updateHeight();

      editor.onMouseMove(async (e: any) => {
        if (!e.target.position) return;
        const model = editor.getModel();
        if (!model) return;
        const word = model.getWordAtPosition(e.target.position);
        if (!word) return;

        const wordText = model.getValueInRange({
          startLineNumber: e.target.position.lineNumber,
          startColumn: word.startColumn,
          endLineNumber: e.target.position.lineNumber,
          endColumn: word.endColumn,
        });

        const isValidFunction = ddxData?.ddxFunctions?.some(
          (fn) => fn.function_name === wordText
        );

        if (!isValidFunction) return;

        const range = new monaco.Range(
          e.target.position.lineNumber,
          word.startColumn,
          e.target.position.lineNumber,
          word.endColumn
        );

        const rangeKey = `${range.startLineNumber},${range.startColumn},${range.endLineNumber},${range.endColumn}`;
        if (rangeKey === lastRangeKey) return;

        lastRangeKey = rangeKey;
        decorations.set([
          { range, options: { inlineClassName: "hoverHighlight" } },
        ]);
      });

      editor.onMouseLeave(() => {
        decorations.clear();
        lastRangeKey = "";
      });
    },
    [ddxData]
  );

  return (
    <Box sx={{ display: "flex", flex: 1, overflow: "auto" }}>
      <MonacoEditor
        sx={monacoEditorSx}
        initialValue={
          friendlyReq
            ? normalizeParameterSyntax(props.value ?? "")
            : props.value
        }
        monacoEditorOptions={{
          readOnly: true,
          fontSize: 12,
          lineNumbers: "off",
          lineDecorationsWidth: 0,
          lineNumbersMinChars: 0,
          minimap: { enabled: false },
          contextmenu: false,
          automaticLayout: true,
          scrollBeyondLastLine: false,
          wrappingStrategy: "advanced",
          overviewRulerLanes: 0,
          folding: false,
          roundedSelection: false,
          hideCursorInOverviewRuler: true,
          overviewRulerBorder: false,
          renderLineHighlight: "none",
          wordWrap: "on",
          wrappingIndent: "same",
          fixedOverflowWidgets: true,
          hover: {
            enabled: true,
            sticky: true,
          },
          occurrencesHighlight: "off",
          scrollbar: {
            vertical: "hidden",
            horizontal: "hidden",
            handleMouseWheel: false,
          },
        }}
        getEditorRef={handleGetEditorRef}
      />
    </Box>
  );
};

