import { SxProps, createTheme } from "@textile/mui";
import numeral from "numeral";
import { DdxData } from "../solvasam-bizcomponents.local-dev";

export const INVISIBLE_DELIMITER = "\u200B";
const COMPLEX_RULE_REGEX = /<%[\s\S]*?%>/;

export const INVISIBLE_DELIMITER_REGEX_PATTERN = new RegExp(
  `${INVISIBLE_DELIMITER}(?:[^${INVISIBLE_DELIMITER}]|${INVISIBLE_DELIMITER}')*${INVISIBLE_DELIMITER}`,
  "g"
);

export const WrapWithInvisibleDelimiter = (value: string | string[]) => {
  return (INVISIBLE_DELIMITER + value + INVISIBLE_DELIMITER)
    .replace(/'/g, INVISIBLE_DELIMITER + "'")
    .replaceAll(INVISIBLE_DELIMITER + INVISIBLE_DELIMITER, INVISIBLE_DELIMITER);
};

export const wrapMultiValues = (value: string | string[]) => {
  if (Array.isArray(value)) {
    return value.map((v) => {
      return WrapWithInvisibleDelimiter(v);
    });
  } else {
    return value?.split(",").map((v) => {
      return WrapWithInvisibleDelimiter(v);
    });
  }
};

export const isNullCheckOperator = (operator: string): boolean => {
  return ["IS NULL", "IS NOT NULL"].includes(operator?.trim()?.toUpperCase());
};
export const isRangeOperator = (operator: string): boolean => {
  return ["IS BETWEEN", "IS NOT BETWEEN"].includes(
    operator?.trim()?.toUpperCase()
  );
};
export const isMultiValueOperator = (operator: string): boolean => {
  return ["IS ONE OF", "IS NOT ONE OF"].includes(
    operator?.trim()?.toUpperCase()
  );
};
export const isLikeOperator = (operator: string): boolean => {
  return ["IS LIKE", "IS NOT LIKE"].includes(operator?.trim()?.toUpperCase());
};

export const unwrapValue = (
  comparison_operator: string | null | undefined,
  value: string | null | undefined
) => {
  const res = value
    ? !isMultiValueOperator(comparison_operator ?? "")
      ? replaceUniCodeForSingleValue(value)
      : value
    : "";
  return res;
};

export const replaceUniCodeForMultiValues = (
  value: string | null | undefined
) => {
  if (!value) return "";
  const items = value.split(
    new RegExp(`${INVISIBLE_DELIMITER},\\s*${INVISIBLE_DELIMITER}`)
  );
  return items.map((item) => replaceUniCodeForSingleValue(item));
};

export const replaceUniCodeForSingleValue = (
  value: string | null | undefined
) => {
  if (!value || typeof value != "string") return "";
  return value
    .replace(new RegExp(`^${INVISIBLE_DELIMITER}`), "")
    .replace(new RegExp(`${INVISIBLE_DELIMITER}$`), "")
    .replace(new RegExp(`${INVISIBLE_DELIMITER}'`, "g"), "'");
};

const breakpoints = createTheme().breakpoints.values;

const resolveDialogWidth = (width?: string | number): string | number => {
  if (!width) width = "sm";
  if (typeof width === "number") return width;
  return breakpoints[width as keyof typeof breakpoints] || width;
};

export const getDialogResizePaperPropsSx = (
  width?: string | number
): SxProps => ({
  resize: "both",
  overflow: "auto",
  maxWidth: "none", // <-- allow resizing
  width: resolveDialogWidth(width), //accepts 3 formats "1200px", 1200 or lg
});

export const formatFormula = (formula: string | null | undefined): string => {
  return formula?.replace("dbo.", "") ?? "";
};

export const percentFormat = (
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  value: any,
  format?: string,
  nullFormat?: string
): string => {
  if (value == null) {
    return nullFormat ?? "";
  }
  const formattedValue = format
    ? numeral(value).format(format.replace("%%", "").trim())
    : value.toString();
  return `${formattedValue}%`;
};

export const adjustDateTimeOffset = (
  asOfDate: Date,
  addOffsetHours: boolean
) => {
  const utcOffset = asOfDate.getTimezoneOffset();
  const offsetHours = -utcOffset / 60;

