export const MonacoTooltip: React.FC<{
  content: string;
  position: { x: number; y: number; lineHeight: number };
}> = ({ content, position }) => {
  const ref = useRef<HTMLDivElement>(null);
  const [style, setStyle] = useState<React.CSSProperties>({
    visibility: "hidden",
    position: "absolute",
    left: position.x,
    top: position.y,
  });

  useEffect(() => {
    if (!ref.current) return;
    const { height } = ref.current.getBoundingClientRect();
    const showAbove = position.y - height < 0;
    setStyle({
      position: "absolute",
      left: position.x,
      ...(showAbove
        ? { top: position.y + position.lineHeight }
        : { top: position.y - height }),
      visibility: "visible",
    });
  }, [position]);

  return ReactDOM.createPortal(
    <div
      ref={ref}
      style={{
        ...style,
        background: "black",
        color: "white",
        padding: "8px",
        borderRadius: "4px",
        zIndex: 999999,
        maxWidth: "400px",
        whiteSpace: "pre-wrap",
        pointerEvents: "auto",
      }}
      onMouseEnter={(e) => e.stopPropagation()}
      onMouseLeave={(e) => e.stopPropagation()}
    >
      {content}
    </div>,
    document.body
  );
};

