import { Box, SxProps, Tooltip, useTheme } from "@textile/mui";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import * as monaco from "monaco-editor";
import { MonacoEditor } from "../monaco-ddx-editor/monaco-editor.component";
import { DdxData, DdxFunction } from "../monaco-ddx-editor";
import { expandDescription, normalizeParameterSyntax } from "../helpers";

interface RuleDisplayComponentProps {
  value?: string;
  ddxData?: DdxData;
  friendlyReq?: boolean;
}

export const RuleDisplayComponent = ({
  friendlyReq = true,
  ...props
}: RuleDisplayComponentProps) => {
  const theme = useTheme();
  const ddxData = props.ddxData;
  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const [height, setHeight] = useState<number>(40);
  const [tooltip, setTooltip] = useState<{
    content: string;
    anchorEl: { getBoundingClientRect: () => DOMRect };
    placement: "top" | "bottom";
  } | null>(null);

  const currentWordRef = useRef<string>("");
  const tooltipTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const isMouseInEditorRef = useRef<boolean>(false);
  const decorationsRef =
    useRef<monaco.editor.IEditorDecorationsCollection | null>(null);

  const monacoEditorSx = useMemo<SxProps>(
    () => ({
      minWidth: "100%",
      height: `${height}px`,
      overflow: "hidden",
      display: "flex",
      fontSize: theme.typography.caption.fontSize,
      backgroundColor: theme.palette.background.paper,
      "& .hoverHighlight": {
        fontWeight: 600,
      },
    }),
    [height, theme]
  );

  const clearTooltipWithDelay = useCallback(() => {
    if (tooltipTimeoutRef.current) {
      clearTimeout(tooltipTimeoutRef.current);
    }
    tooltipTimeoutRef.current = setTimeout(() => {
      if (!isMouseInEditorRef.current) {
        setTooltip(null);
        currentWordRef.current = "";
        decorationsRef.current?.clear();
      }
    }, 300);
  }, []);

  const handleGetEditorRef = useCallback(
    (editor: monaco.editor.IStandaloneCodeEditor) => {
      editorRef.current = editor;
      let lastRangeKey: string | null = null;
      const decorations = editor.createDecorationsCollection();
      decorationsRef.current = decorations;

      const updateHeight = () => {
        const contentHeight = Math.min(500, editor.getContentHeight());
        setHeight(contentHeight);
      };

      editor.onDidContentSizeChange(updateHeight);
      updateHeight();

      let frame: number | null = null;
      editor.onMouseMove(async (e: any) => {
        isMouseInEditorRef.current = true;

        // Clear any pending timeout
        if (tooltipTimeoutRef.current) {
          clearTimeout(tooltipTimeoutRef.current);
          tooltipTimeoutRef.current = null;
        }

        if (!e.target.position) {
          decorations.clear();
          currentWordRef.current = "";
          setTooltip(null);
          return;
        }

        if (frame) cancelAnimationFrame(frame);

        frame = requestAnimationFrame(() => {
          const model = editor.getModel();
          if (!model) return;

          const word = model.getWordAtPosition(e.target.position);
          if (!word) {
            if (currentWordRef.current) {
              currentWordRef.current = "";
              decorations.clear();
              lastRangeKey = null;
              setTooltip(null);
            }
            return;
          }

          const wordText = model.getValueInRange({
            startLineNumber: e.target.position.lineNumber,
            startColumn: word.startColumn,
            endLineNumber: e.target.position.lineNumber,
            endColumn: word.endColumn,
          });

          console.log(`wordText: ${wordText}`);

          // Only update if word changed
          if (currentWordRef.current === wordText) return;

          const functionData = ddxData?.ddxFunctions?.find(
            (fn) => fn.function_name === wordText
          );

          if (!functionData) {
            if (currentWordRef.current) {
              currentWordRef.current = "";
              decorations.clear();
              lastRangeKey = null;
              setTooltip(null);
            }
            return;
          }

          currentWordRef.current = wordText;

          const range = new monaco.Range(
            e.target.position.lineNumber,
            word.startColumn,
            e.target.position.lineNumber,
            word.endColumn
          );

          const rangeKey = `${range.startLineNumber},${range.startColumn},${range.endLineNumber},${range.endColumn}`;
          if (rangeKey === lastRangeKey) return;

          lastRangeKey = rangeKey;

          decorations.set([
            {
              range,
              options: {
                inlineClassName: "hoverHighlight",
              },
            },
          ]);

          const wordDomPosition = editor.getScrolledVisiblePosition({
            lineNumber: e.target.position.lineNumber,
            column: word.startColumn,
          });

          const editorDomNode = editor.getDomNode();

          const editorRect = editorDomNode?.getBoundingClientRect();
          const x = (editorRect?.left ?? 0) + (wordDomPosition?.left ?? 0);
          const y = (editorRect?.top ?? 0) + (wordDomPosition?.top ?? 0);

          setTooltip({
            content: normalizeParameterSyntax(
              expandDescription(
                functionData.friendly_description ?? "",
                ddxData
              )
            ),
            placement: e.target.position.lineNumber === 1 ? "bottom" : "top",
            anchorEl: {
              getBoundingClientRect: () => new DOMRect(x, y, 0, 0),
            },
          });
        });
      });

      editor.onMouseLeave(() => {
        isMouseInEditorRef.current = false;
        clearTooltipWithDelay();
      });
    },
    [ddxData, clearTooltipWithDelay]
  );

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (tooltipTimeoutRef.current) {
        clearTimeout(tooltipTimeoutRef.current);
      }
    };
  }, []);

  return (
    <>
      <Box sx={{ display: "flex", flex: 1, overflow: "auto" }}>
        <MonacoEditor
          sx={monacoEditorSx}
          initialValue={
            friendlyReq
              ? normalizeParameterSyntax(props.value ?? "")
              : props.value
          }
          monacoEditorOptions={{
            readOnly: true,
            fontSize: 12,
            lineNumbers: "off",
            lineDecorationsWidth: 0,
            lineNumbersMinChars: 0,
            minimap: { enabled: false },
            contextmenu: false,
            automaticLayout: true,
            scrollBeyondLastLine: false,
            wrappingStrategy: "advanced",
            overviewRulerLanes: 0,
            folding: false,
            roundedSelection: false,
            hideCursorInOverviewRuler: true,
            overviewRulerBorder: false,
            renderLineHighlight: "none",
            wordWrap: "on",
            wrappingIndent: "same",
            hover: {
              enabled: false,
            },
            occurrencesHighlight: "off",
            scrollbar: {
              vertical: "hidden",
              horizontal: "hidden",
              handleMouseWheel: false,
            },
          }}
          getEditorRef={handleGetEditorRef}
        />
      </Box>
      {tooltip && (
        <Tooltip
          open={true}
          title={tooltip.content}
          placement={tooltip.placement}
          PopperProps={{
            anchorEl: tooltip.anchorEl,
            disablePortal: false,
            modifiers: [
              {
                name: "preventOverflow",
                enabled: true,
                options: {
                  boundary: "viewport",
                },
              },
            ],
          }}
          slotProps={{
            tooltip: {
              sx: {
                backgroundColor: theme.palette.common.black,
                maxWidth: "400px",
                fontSize: theme.typography.caption.fontSize,
                whiteSpace: "pre-wrap",
                wordWrap: "break-word",
                pointerEvents: "none",
              },
            },
            arrow: {
              sx: {
                color: theme.palette.common.black,
              },
            },
          }}
          arrow
        >
          <span style={{ position: "fixed", pointerEvents: "none" }} />
        </Tooltip>
      )}
    </>
  );
};

