        );

        if (!functionData) {
          if (currentRangeKeyRef.current) {
            currentRangeKeyRef.current = "";
            decorations.clear();
            setTooltip(null);
          }
          return;
        }

        const range = new monaco.Range(
          e.target.position.lineNumber,
          word.startColumn,
          e.target.position.lineNumber,
          word.endColumn
        );

        const rangeKey = `${range.startLineNumber},${range.startColumn},${range.endLineNumber},${range.endColumn}`;
        if (currentRangeKeyRef.current === rangeKey) return;

        currentRangeKeyRef.current = rangeKey;

        pendingDecorationRef.current = { range, wordText };

        const lineHeight = editor.getOption(
          monaco.editor.EditorOption.lineHeight
        );

        const wordDomPositionStart = editor.getScrolledVisiblePosition({
          lineNumber: e.target.position.lineNumber,
          column: word.startColumn,
        });

        const wordDomPositionEnd = editor.getScrolledVisiblePosition({
          lineNumber: e.target.position.lineNumber,
          column: word.endColumn,
        });

        const editorDomNode = editor.getDomNode();
        const editorRect = editorDomNode?.getBoundingClientRect();

        const x =
          (editorRect?.left ?? 0) +
          ((wordDomPositionStart?.left ?? 0) +
            (wordDomPositionEnd?.left ?? 0)) /
            2;
        const y = (editorRect?.top ?? 0) + (wordDomPositionStart?.top ?? 0);

        if (true) {
          setTooltip({
            content: normalizeParameterSyntax(
              expandDescription(
                functionData.friendly_description ?? "",
                ddxData
              )
            ),
            placement: e.target.position.lineNumber === 1 ? "bottom" : "top",
            anchorEl: {
              getBoundingClientRect: () => new DOMRect(x, y, 0, lineHeight),
            },
          });
        }
      });

      editor.onMouseLeave(() => {
        isMouseInEditorRef.current = false;
        currentRangeKeyRef.current = "";
        clearTooltipWithDelay();
      });
    },
    [ddxData, clearTooltipWithDelay]
  );

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (tooltipTimeoutRef.current) {
        clearTimeout(tooltipTimeoutRef.current);
      }
    };
  }, []);

  //on tooltip update the decoration clears but we want the highlight behavior
  useEffect(() => {
    if (!pendingDecorationRef.current || !decorationsRef.current) return;

    if (tooltip) {
      const { range } = pendingDecorationRef.current;

      decorationsRef.current.set([
        {
          range: range,
          options: {
            inlineClassName: "hoverHighlight",
          },
        },
      ]);
    }
  }, [tooltip]);

  return (
    <>
      <Box sx={{ display: "flex", flex: 1, overflow: "auto" }}>
        <MonacoEditor
          sx={monacoEditorSx}
          initialValue={
            friendlyReq
              ? normalizeParameterSyntax(props.value ?? "")
              : props.value
          }
          monacoEditorOptions={{
            readOnly: true,
            fontSize: 12,
            lineNumbers: "off",
            lineDecorationsWidth: 0,
            lineNumbersMinChars: 0,
            minimap: { enabled: false },
            contextmenu: false,
            automaticLayout: true,
            scrollBeyondLastLine: false,
            wrappingStrategy: "advanced",
            overviewRulerLanes: 0,
            folding: false,
            roundedSelection: false,
            hideCursorInOverviewRuler: true,
            overviewRulerBorder: false,
            renderLineHighlight: "none",
            wordWrap: "on",
            wrappingIndent: "same",
            scrollbar: {
              vertical: "hidden",
              horizontal: "hidden",
              handleMouseWheel: false,
            },
          }}
          getEditorRef={handleGetEditorRef}
        />
      </Box>
      {tooltip && (
        <Tooltip
          open={true}
          title={tooltip.content}
          placement={tooltip.placement}
          slotProps={{
            tooltip: {
              sx: {
                backgroundColor: theme.palette.common.black,
                maxWidth: "400px",
                fontSize: theme.typography.caption.fontSize,
                whiteSpace: "pre-wrap",
                wordWrap: "break-word",
                pointerEvents: "none",
              },
            },
            arrow: {
              sx: {
                color: theme.palette.common.black,
              },
            },
            popper: {
              anchorEl: tooltip.anchorEl,
              disablePortal: false,
              modifiers: [
                {
                  name: "preventOverflow",
                  enabled: true,
                  options: {
                    boundary: "viewport",
                  },
                },
              ],
            },
          }}
          arrow
        >
          <span style={{ position: "fixed", pointerEvents: "none" }} />
        </Tooltip>
      )}
    </>
  );
};

