import {
  AsyncFormSelect,
  DropdownTransferList,
  FormAutocomplete,
  useAsyncOptions,
  useField,
} from "@textile/biz-components";
import { SxProps, TextFieldProps } from "@textile/mui";
import {
  FunctionComponent,
  memo,
  useCallback,
  useEffect,
  useMemo,
} from "react";

import { LookupItem } from "../common.types";
import { DdxData } from "../monaco-ddx-editor";
import { useLookupDataSource } from "../form/lookup-autocomplete.component";
import {
  replaceUniCodeForMultiValues,
  replaceUniCodeForSingleValue,
} from "../helpers";

interface ExpressionBuilderLookupItemProps {
  id: string;
  label: string;
  lookupType: string;
  multiple?: boolean;
  sx?: SxProps;
  required?: boolean;
  ddxProps: DdxData;
}

export const ExpressionBuilderLookupAutoComplete: FunctionComponent<ExpressionBuilderLookupItemProps> =
  memo((props) => {
    const { id, label, lookupType, multiple, sx, required } = props;
    const [field, , helpers] = useField<string>(id);
    const TextFieldProps = useMemo<TextFieldProps>(
      () => ({
        label: label,
        variant: "outlined",
        required: required,
      }),
      [label, required]
    );
    const lookupDataSource = useLookupDataSource(lookupType);
    const { options, status } = useAsyncOptions<LookupItem>(lookupDataSource);

    const isLoading = status === "idle" || status === "pending";

    useEffect(() => {
      if (multiple) {
        typeof field.value === "object"
          ? field.value
          : field.value
          ? helpers.setValue(
              replaceUniCodeForMultiValues(field.value) as unknown as string
            )
          : [];
      } else {
        field.value
          ? helpers.setValue(
              replaceUniCodeForSingleValue(field.value) as unknown as string
            )
          : null;
      }
    }, [field.value, multiple]);

    const onBeforePopulate = useCallback(
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      async (data: any) => {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const sortedData = data.sort((a: any, b: any) =>
          a.description.localeCompare(b.description)
        );
        return sortedData;
      },
      []
    );
    return multiple ? (
      <AsyncFormSelect
        data-testid={id}
        fieldName={id}
        dataSource={lookupDataSource}
        labelField={"description"}
        valueField={"description"}
        label={label}
        required={required}
        defaultValue={[]}
        onBeforePopulate={onBeforePopulate}
        multiple
      >
        <DropdownTransferList autoFocusSearch />
      </AsyncFormSelect>
    ) : (
      <FormAutocomplete<Record<string, unknown>, LookupItem>
        data-testid={id}
        fieldName={id}
        sx={sx}
        defaultValue={
          (() => {
            const converted = replaceUniCodeForSingleValue(field.value);
            const match = options.find(
              (o) => o?.description === converted || o?.code === converted
            );
            console.log(`[Autocomplete] fieldValue=${field.value} converted=${converted} optionsCount=${options.length} match=${JSON.stringify(match)}`);
            return match ?? null;
          })()
        }
        onChange={(_e, v) => {
          helpers.setValue((v as LookupItem)?.description);
        }}
        labelField="description"
        valueField="description"
        textFieldProps={TextFieldProps}
        options={[...options].sort((a, b) =>
          a.description.localeCompare(b.description)
        )}
        getOptionLabel={(option) => (option as LookupItem)?.description ?? ""}
        loading={isLoading}
      />
    );
  });

