export const FormTableGrid: FunctionComponent<FormTableGridProps> = ({
  id,
  tableValueSchema,
  label,
}) => {
  const { setFieldValue } = useFormikContext();
  const [{ value: tableValues }] = useField(id);
  const [disableDelete, setDisableDelete] = useState<boolean>(true);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [selectedTableRecords, setSelectedRecords] = useState<any>([]);
  const [colDefOverrides, setColDefOverrides] = useState<ColDefOverride[]>([]);

  useEffect(() => {
    if (tableValueSchema?.gridFields) {
      const overrides = tableValueSchema.gridFields.map((field) => ({
        field: field.name,
        colDef: {
          editable: true,
          cellRenderer: CustomCellRenderer,
        },
      }));
      setColDefOverrides(overrides);
    }
  }, [tableValueSchema?.gridFields]);

  const handleAdd = useCallback(() => {
    const newRecord: Record<string, string> = {};

    tableValueSchema?.gridFields?.forEach((field) => {
      newRecord[field.name] = field.name === "id" ? uuid() : "";
    });

    setFieldValue(id, [...(tableValues ?? []), newRecord]);
  }, [id, setFieldValue, tableValueSchema?.gridFields, tableValues]);

  const handleDelete = useCallback(() => {
    if (selectedTableRecords.length > 0)
      setFieldValue(id, [
        ...tableValues.filter(
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          (value: any) =>
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            !selectedTableRecords.some((record: any) => record.id === value.id)
        ),
      ]);
  }, [id, selectedTableRecords, setFieldValue, tableValues]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleSelectionChange = useCallback((selectedRecords: any[]) => {
    setDisableDelete(selectedRecords.length !== 0 ? false : true);
    setSelectedRecords(selectedRecords.length !== 0 ? selectedRecords : []);
  }, []);

  return (
    <FormFieldGroup>
      <FormDataGrid<Record<string, unknown>>
        label={label as string}
        fieldName={id}
        meta={tableValueSchema ?? { idField: "id", gridFields: [] }}
        sx={tableGridSxProps}
        rowSelectionMode="multi"
        agGridProps={{
          getRowHeight: function () {
            return 50;
          },
          suppressRowClickSelection: true,
          singleClickEdit: true,
          stopEditingWhenCellsLoseFocus: true,
        }}
        colDefOverrides={colDefOverrides}
        onSelectionChanged={handleSelectionChange}
      >
        <Box sx={{ display: "flex", flexDirection: "row" }}>
          <IconButton aria-label="Add" onClick={handleAdd}>
            <AddIcon size={24} />
          </IconButton>
          <IconButton
            aria-label="Delete"
            onClick={handleDelete}
            disabled={disableDelete}
          >
            <DeleteIcon size={24} />
          </IconButton>
        </Box>
      </FormDataGrid>
    </FormFieldGroup>
  );
};

