        </FormFieldGroup>
      );
    case "CURRENCY":
    case "NUMERIC":
    case "PERCENT":
      return (
        <FormFieldGroup sx={{ gap: 0.5 }}>
          <FormTextField
            fieldName={id}
            label={label}
            variant={variant}
            required={required}
            disabled={disabled}
            InputProps={{
              inputProps: {
                type: "number",
                ...textFieldInputProps,
              },
            }}
          ></FormTextField>
          {dataType === "CURRENCY" ? (
            <Typography sx={{ pt: 1 }}>$</Typography>
          ) : dataType === "PERCENT" ? (
            <Typography sx={{ pt: 1 }}>%</Typography>
          ) : null}
        </FormFieldGroup>
      );
    case "TABLE":
      return (
        <FormTableGrid
          id={id}
          tableValueSchema={tableValueSchema}
          label={label}
        />
      );
    default:
      return (
        <FormFieldGroup>
          <FormTextField
            fieldName={id}
            label={label}
            variant={variant}
            required={required}
            disabled={disabled}
            InputProps={{
              inputProps: {
                ...textFieldInputProps,
              },
            }}
          ></FormTextField>
        </FormFieldGroup>
      );
  }
};

const toggleButtonBoxProps: SxProps = {
