const defaultValueTypeId = "value_type";

interface FormValueSelectorProps {
  valFieldId: string;
  refFieldId: string;
  valueTypeId?: string;
  dataType: string;
  valueType: string;
  textFieldProps: TextFieldProps;
  isCurrencyCode?: boolean;
  lockValueType?: boolean;
  isCalculated?: boolean;
  tableValueSchema?: DataGridMeta;
  predefinedTable?: boolean | null;
  parameterValueType?: string | null;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  onBeforePopulate?: (data: any) => Promise<any>;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  onBeforeSave?: (data: any) => Promise<false | OperationItem[] | any>;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  onReferenceFieldChange?: (event: SyntheticEvent, value: any) => void;
}

export const FormValueSelector: FunctionComponent<FormValueSelectorProps> = ({
  valFieldId,
  refFieldId,
  valueTypeId,
  valueType,
  textFieldProps,
  dataType,
  lockValueType = false,
  isCalculated,
  tableValueSchema,
  onReferenceFieldChange,
  parameterValueType,
  predefinedTable,
}) => {
  const [valueTypeState, setValueTypeState] = useState<string>(
    valueType?.toLowerCase()
  );
  const [, , valueTypeHelpers] = useField(valueTypeId ?? defaultValueTypeId);
  const [selectedPortfolio] = useSelectedPortfolioId();
  const [refreshToken, refresh] = useRefreshToken();
  const { setFieldValue } = useFormikContext();

  const handleToggleChange = useCallback(
    (event: React.MouseEvent<HTMLElement>, value: string | null) => {
      if (value !== null) {
        valueTypeHelpers.setValue(value, false);
        setValueTypeState(value);
      }
    },
    [valueTypeHelpers]
  );

  useEffect(() => {
    if (valueType) {
      setValueTypeState(valueType?.toLowerCase());
    }
    if (lockValueType) {
      const event = {} as React.MouseEvent<HTMLElement>;

      handleToggleChange(event, "ref");
    }
  }, [
    handleToggleChange,
    lockValueType,
    setFieldValue,
    valueType,
    valueTypeHelpers,
    valueTypeId,
  ]);

  const portfolioFieldDataSource =
    useMemo<AutocompleteDataServiceProviderDataSource>(
      () => ({
        idField: "id",
        url: `/portfolio-bff/v1/portfolios/${selectedPortfolio}/fields`,
        dataPath: "portfolio_fields",

        queryParams: {
          "paging.filter": isCalculated
            ? `data_types="${dataType ?? ""}" AND is_calculated=${isCalculated}`
            : `data_types="${dataType ?? ""}"`,
        },
      }),
      // eslint-disable-next-line react-hooks/exhaustive-deps
      [dataType, isCalculated, selectedPortfolio, refreshToken]
    );

  return (
    <Box sx={toggleButtonBoxProps}>
      {valueTypeState ? (
        valueTypeState === "val" ? (
          <FormValueField
            id={valFieldId}
            dataType={dataType}
            tableValueSchema={tableValueSchema}
            textFieldProps={textFieldProps}
          ></FormValueField>
        ) : (
          <AsyncFormAutocomplete
            valueField="field_name"
            labelField="display_name"
            fieldName={refFieldId}
            dataSource={portfolioFieldDataSource}
            textFieldProps={textFieldProps}
            onChange={onReferenceFieldChange}
          ></AsyncFormAutocomplete>
        )
      ) : null}
      {!lockValueType && (
        <Tooltip title="Click on the toggle button to choose from the drop down or enter a manual value">
          <ToggleButtonGroup
            id={valueTypeId ?? defaultValueTypeId}
            value={valueTypeState}
            onChange={handleToggleChange}
            exclusive
            orientation="vertical"
          >
            <ToggleButton value="val" size="small" sx={{ height: 16 }}>
              V
            </ToggleButton>
            <ToggleButton value="ref" size="small" sx={{ height: 16 }}>
              F
            </ToggleButton>
          </ToggleButtonGroup>
        </Tooltip>
      )}
      <AddNewFieldFormComponent
        id={refFieldId}
        dataType={dataType}
        predefinedTable={predefinedTable}
        parameterValueType={parameterValueType}
        valueType={valueTypeState}
        refresh={refresh}
      ></AddNewFieldFormComponent>
    </Box>
  );
};

