export const ExpressionBuilder: FunctionComponent<ExpressionBuilderProps> = (
  props
) => {
  const theme = useTheme();
  const { fetchHydrateExpression, fetchHydrateRuleExpression } =
    useExpressionValidator();
  const axiosFactory = useAxiosFactory();
  const {
    open,
    expression,
    ddxProps,
    handleOnCloseButtonClick,
    targetType,
    targetKey,
    children,
    setValue,
    isComplexRule,
  } = props;
  const [gridExpression, setState] = useState(expression);
  const [initialValues, setInitialValues] = useState<{ [x: string]: string }>(
    expressionToFieldValues(expression)
  );
  const [isEditorEnabled, setIsEditorEnabled] = useState(false);
  const [openRuleSelect, setOpenRuleSelect] = useState<boolean>(false);
  const [ruleToEdit, setRuleToEdit] = useState<Expression | null>(null);
  const [ddxErrors, setDdxErrors] = useState<
    DdxTranslationError[] | undefined
  >();
  const exprDescription = useRef<string>("");
  const editorVal = useRef<string>("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [failed, setFailed] = useState<boolean>(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [isPassThrough, setIsPassThrough] = useState(false);

  const [hydratedExpressions, setHydratedExpressions] = useState<{
    [key: number]: string | null;
  }>({});

  const { error } = useMessageAnnouncer();
  useEffect(() => {
    setState([...expression]);
    setFailed(false);
    return () => {
      if (!isComplexRule) {
        setIsEditorEnabled(false);
      }
      setDdxErrors([]);
    };
  }, [expression, open, isComplexRule]);

  useEffect(() => {
    setInitialValues(expressionToFieldValues([...expression]));
  }, [expression, ddxProps]);

  const compOperator = (
    dataDictionaryFieldName: string,
    valueType: string
  ) => ({
    options: comparisonOperatorList?.filter(function (listItem) {
      const field = {
        ...getDdxFieldByDisplayName(
          ddxProps.ddxFields,
          dataDictionaryFieldName
        )[0],
      };
      field.lookup_type = valueType === "F" ? null : field.lookup_type;
      return listItem.applicable(field);
    }),
  });

  useEffect(() => {
    if (isComplexRule) {
      setIsEditorEnabled(true);
      const exprDesc = getFriendlyDescription(expression);
      exprDescription.current = exprDesc;
      isEditorDirty.current = false;
    }
  }, [isComplexRule]);

  const toggleEditor = async (
    setValues: ExpressionBuilderState["setValues"]
  ) => {
    if (isPassThroughCode(editorRef?.current?.getValue() ?? "")) {
      return;
    }

    if (
      isEditorEnabled &&
      editorRef.current &&
      editorRef?.current?.getValue()?.trim()?.length > 0
    ) {
      const modelExpression = await hydrateExpression(
        editorRef?.current?.getValue()
      );

      if (modelExpression.ddx_errors.length === 0) {
        setDdxErrors([]);
        const expressions = modelExpressionToExpressions(
          modelExpression,
          ddxProps.ddxFields,
          ddxProps.ddxFunctions
        );
        setValues(expressionToFieldValues(expressions));
        setState(expressions);
        setIsEditorEnabled((s) => !s);
      } else {
        setIsEditorEnabled(true);
        setDdxErrors(modelExpression.ddx_errors);
        modelExpression?.ddx_errors?.forEach((err) => {
          error(`${err.message_code}: ${err.message}`);
        });
      }
    } else {
      if (
        isEditorEnabled &&
        editorRef?.current?.getValue()?.trim()?.length === 0
      ) {
        setValues({});
        setState([]);
      }
      setIsEditorEnabled((s) => !s);
    }
  };

  const handleSubmit = useCallback(
    async (values: { [x: string]: string }) => {
      try {
        const expressions: Expression[] = fieldValuesToExpressions(
          [...gridExpression],
          values,
          ddxProps
        );

        setState(expressions);
        const editorValue = editorVal.current;
        exprDescription.current = editorValue ?? exprDescription.current;
        editorRef?.current?.setValue(
          isEditorEnabled
            ? editorValue
            : getFriendlyDescription(expressions) ?? ""
        );
        setIsSubmitting(true);
        const modelExpression = await fetchHydrateExpression(
          "FILTER_EXPRESSION",
          isEditorEnabled ? editorValue : getFriendlyDescription(expressions),
          "bool"
        );

        if (modelExpression.ddx_errors.length === 0) {
          setDdxErrors([]);
          if (setValue) {
            setValue(modelExpression);
          } else {
            const axios = await axiosFactory.createAxiosInstance();
            await axios.put(`/compliance-modeling/v1/expressionput`, {
              target_type: targetType,
              target_key: targetKey,
              ddx: modelExpression.ddx,
            });
          }
          handleOnCloseButtonClick ? handleOnCloseButtonClick() : null;
        } else {
          setDdxErrors(modelExpression.ddx_errors);
          setFailed(true);
        }
        isEditorDirty.current = false;
      } catch (err) {
        error("Error: Saving Expression");
      } finally {
        setIsSubmitting(false);
      }
    },
    [
      axiosFactory,
      ddxProps,
      error,
      fetchHydrateExpression,
      gridExpression,
      handleOnCloseButtonClick,
      isEditorEnabled,
      setValue,
      targetKey,
      targetType,
    ]
  );

  const hydrateExpression = async (friendlyDescription?: string) => {
    return await fetchHydrateExpression(
      "FILTER_EXPRESSION",
      friendlyDescription,
      "bool"
    );
  };

  const hydrateRuleExpression = async (friendlyDescription?: string) => {
    return await fetchHydrateRuleExpression(
      "FILTER_EXPRESSION",
      friendlyDescription,
      "bool"
    );
  };

  const isEditorDirty = useRef(false);

  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const handleGetEditorRef = (editor: monaco.editor.IStandaloneCodeEditor) => {
    editorRef.current = editor;
    editorRef?.current?.onDidChangeModelContent(() => {
      isEditorDirty.current = true;
      setIsPassThrough(isPassThroughCode(editorRef?.current?.getValue() ?? ""));
    });
    // Set initial passthrough state
    setIsPassThrough(isPassThroughCode(editorRef?.current?.getValue() ?? ""));
  };

  const getFriendlyDesc = useCallback(() => {
    editorVal.current = editorRef?.current?.getValue() ?? "";
    if (!isEditorEnabled || isEditorDirty.current) {
      return editorRef?.current?.getValue() ?? "";
    } else {
      return exprDescription.current ?? "";
    }
  }, [isEditorEnabled]);
  const onDdxToDetailsRef = useRef<(() => void) | null>(null);

  const handleClose = useCallback(() => {
    setIsFullScreen(false);
    handleOnCloseButtonClick?.();
  }, [handleOnCloseButtonClick]);

  return (
    <Box>
      <Dialog
        open={open}
        fullWidth
        fullScreen={isFullScreen}
        PaperProps={{
          sx: !isFullScreen ? getDialogResizePaperPropsSx("xl") : {},
        }}
        draggable={true}
      >
        <Formik
          initialValues={initialValues}
          enableReinitialize={true}
          onSubmit={async (values) => {
            handleSubmit(values);
          }}
        >
          {({ handleSubmit, values, setValues }) => (
            <FormValidateField>
              <form onSubmit={handleSubmit}>
                <DialogTitle>
                  <Stack
                    direction="row"
                    alignItems="center"
                    justifyContent="space-between"
                  >
                    Expression Builder
                    <Stack direction="row">
                      <IconButton
                        sx={(theme) => ({
                          color: theme.palette.primary.contrastText,
                          mr: 1,
                        })}
                        aria-label={
                          isFullScreen
                            ? "Exit full screen"
                            : "Enter full screen"
                        }
                        onClick={() => setIsFullScreen((prev) => !prev)}
                      >
                        {isFullScreen ? (
                          <CollapseIcon size={20} />
                        ) : (
                          <ExpandIcon size={20} />
                        )}
                      </IconButton>
                      <IconButton
                        aria-label="close"
                        onClick={handleClose}
                        sx={(theme) => ({
                          color: theme.palette.primary.contrastText,
                        })}
                      >
                        <CloseIcon size={20} />
                      </IconButton>
                    </Stack>
                  </Stack>
                </DialogTitle>
                <ProgressOrDivider isLoading={isSubmitting} />
                <ExpressionBuilderContextProvider
                  expression={gridExpression}
                  ddxData={ddxProps}
                  setState={setState}
                  values={values}
                  setValues={setValues}
                >
                  <DialogContent>
                    <Box sx={topBoxSx}>
                      <Box sx={shimBoxSx}></Box>
                      <ToolGroup sx={{ gap: 1 }}>
                        <FormControlLabel
                          label={
                            isPassThrough
                              ? "View Editor (Disabled - Complex Rule)"
                              : "View Editor"
                          }
                          sx={{
                            flex: "1 1 0px",
                            opacity: isPassThrough ? 0.5 : 1,
                          }}
                          control={
                            <Checkbox
                              checked={isEditorEnabled}
                              disabled={isPassThrough}
                            />
                          }
                          onClick={(e) => {
                            e.preventDefault();
                            toggleEditor(setValues);
                            if (!isEditorEnabled) {
                              const expressions: Expression[] =
                                fieldValuesToExpressions(
                                  [...gridExpression],
                                  values,
                                  ddxProps
                                );
                              const exprDesc =
                                getFriendlyDescription(expressions);

                              exprDescription.current = exprDesc;
                              isEditorDirty.current = false;
                            }
                          }}
                        />

                        {!isEditorEnabled && !isComplexRule ? (
                          <>
                            <Divider orientation="vertical" flexItem></Divider>
                            {children}
                          </>
                        ) : (
                          <Button
                            variant="outlined"
                            onClick={() => onDdxToDetailsRef.current?.()}
                          >
                            Ddx to Details
                          </Button>
                        )}
                      </ToolGroup>
                    </Box>
                    {isEditorEnabled ? (
                      <>
                        <DdxEditorDetails
                          ddxProps={ddxProps}
                          getFriendlyDescription={getFriendlyDesc}
                          getEditorRef={handleGetEditorRef}
                          errors={ddxErrors}
                          exprDesc={exprDescription}
                          onDdxToDetailsRef={onDdxToDetailsRef}
                        ></DdxEditorDetails>
                      </>
                    ) : (
                      <Box
                        sx={{
                          flex: 1,
                          maxHeight: "60vh",
                          overflow: "auto",
                          borderRadius: "4px",
                        }}
                      >
                        <Box
                          sx={{
                            display: "grid",
                            gridTemplateColumns: gridTemplateColumns,
                            backgroundColor: theme.palette.primary.main,
                            color: theme.palette.primary.contrastText,
                          }}
                          gap={1}
                        >
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            S.No.
                          </Typography>
                          <Divider
                            orientation="vertical"
                            sx={{ bgcolor: theme.palette.primary.contrastText }}
                          />
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            AND, OR, NOT
                          </Typography>
                          <Divider
                            orientation="vertical"
                            sx={{ bgcolor: theme.palette.primary.contrastText }}
                          />
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            (...(
                          </Typography>
                          <Divider
                            orientation="vertical"
                            sx={{ bgcolor: theme.palette.primary.contrastText }}
                          />
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            Logical Expression
                          </Typography>
                          <Divider
                            orientation="vertical"
                            sx={{ bgcolor: theme.palette.primary.contrastText }}
                          />
                          <Typography
                            textAlign="center"
                            variant="caption"
                            sx={headersx}
                          >
                            )...)
                          </Typography>
                        </Box>
                        <Box>
                          {gridExpression.map((expression, index) => {
