                                        exclusive
                                        orientation="vertical"
                                        value={values["value_type_" + index]}
                                        disabled={
                                          !(
                                            values["field_" + index] &&
                                            values[
                                              "comparison_operator_" + index
                                            ]
                                          )
                                        }
                                        onChange={(_e, v) => {
                                          setValues((prev) => {
                                            prev["value_type_" + index] = v;

                                            return prev;
                                          });
                                        }}
                                        aria-label={"toggle_button_" + index}
                                      >
                                        <ToggleButton
                                          sx={{ height: 16 }}
                                          value={"V"}
                                          aria-label="V"
                                        >
                                          V
                                        </ToggleButton>
                                        <ToggleButton
                                          sx={{ height: 16 }}
                                          value={"F"}
                                          aria-label="F"
                                        >
                                          F
                                        </ToggleButton>
                                      </ToggleButtonGroup>
                                    ) : null}
                                    <Stack
                                      sx={{
                                        display: "flex",
                                        flex: "4 1 0",
                                        mr: 1,
                                      }}
                                      direction="column"
                                      spacing={1}
                                    >
                                      {values["field_" + index] &&
                                      !isNullCheckOperator(
                                        values["comparison_operator_" + index]
                                      ) &&
                                      values["comparison_operator_" + index] ? (
                                        values["value_type_" + index] ===
                                        "F" ? (
                                          <FormDdxFieldsGrid
                                            id={"value_" + index}
                                            ddxFields={ddxProps.ddxFields.filter(
                                              (item) => {
                                                return (
                                                  item.data_type ===
                                                  getDdxFieldByDisplayName(
                                                    ddxProps.ddxFields,
                                                    values["field_" + index]
                                                  )[0]?.data_type
                                                );
                                              }
                                            )}
                                            required
                                          ></FormDdxFieldsGrid>
                                        ) : getDdxFieldByDisplayName(
                                            ddxProps.ddxFields,
                                            values["field_" + index]
                                          )[0]?.lookup_type ? (
                                          <ExpressionBuilderLookupAutoComplete
                                            id={"value_" + index}
                                            label={"Value"}
                                            required={true}
                                            multiple={isMultiValueOperator(
                                              values[
                                                "comparison_operator_" + index
                                              ]
                                            )}
                                            lookupType={
                                              getDdxFieldByDisplayName(
                                                ddxProps.ddxFields,
                                                values["field_" + index]
                                              )[0].lookup_type ?? ""
                                            }
                                            ddxProps={ddxProps}
                                          ></ExpressionBuilderLookupAutoComplete>
                                        ) : getDdxFieldByDisplayName(
                                            ddxProps.ddxFields,
                                            values["field_" + index]
                                          )[0]?.data_type?.toLowerCase() ===
                                          "boolean" ? (
                                          <FormAutocomplete
                                            fieldName={"value_" + index}
                                            valueField={"value"}
                                            labelField={"label"}
                                            options={booleanOptions}
                                            textFieldProps={{
                                              required: true,
                                              label: "Value",
                                            }}
                                            getOptionLabel={(option) =>
                                              (option as typeof booleanOptions[0])?.label ?? String(option)
                                            }
                                          ></FormAutocomplete>
                                        ) : (
                                          <FormValueField
                                            id={"value_" + index}
                                            dataType={
                                              getDdxFieldByDisplayName(
                                                ddxProps.ddxFields,
                                                values["field_" + index]
                                              )[0]?.data_type?.toUpperCase() ??
                                              ""
                                            }
                                            textFieldProps={{
                                              label: "Value",
                                              required: true,
                                            }}
                                          ></FormValueField>
                                        )
                                      ) : (
                                        <TextField
                                          label={"Value"}
                                          disabled
                                        ></TextField>
                                      )}

                                      {isRangeOperator(
                                        values["comparison_operator_" + index]
                                      ) ? (
                                        values["value_type_" + index] ===
                                        "F" ? (
                                          <FormDdxFieldsGrid
                                            id={"value2_" + index}
                                            ddxFields={ddxProps.ddxFields.filter(
                                              (item) => {
                                                return (
                                                  item.data_type ===
                                                  getDdxFieldByDisplayName(
                                                    ddxProps.ddxFields,
                                                    values["field_" + index]
                                                  )[0]?.data_type
                                                );
                                              }
                                            )}
                                            required
                                          ></FormDdxFieldsGrid>
                                        ) : (
                                          <FormValueField
                                            id={"value2_" + index}
                                            dataType={
                                              getDdxFieldByDisplayName(
                                                ddxProps.ddxFields,
                                                values["field_" + index]
                                              )[0]?.data_type?.toUpperCase() ??
                                              ""
                                            }
                                            textFieldProps={{
                                              label: "Value2",
                                              required: true,
                                            }}
                                          ></FormValueField>
                                        )
                                      ) : null}
                                    </Stack>
                                  </Stack>
                                </Box>
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"close_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={closeParenthesisOptions}
                                  sx={{ py: 1, pr: 1 }}
                                />
                              </DraggableExpression>
                            ) : (
                              <DraggableExpression index={index}>
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"logical_operator_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  aria-label={"logical_operator_" + index}
                                  textFieldProps={{
                                    required: index !== 0,
                                  }}
                                  options={
                                    index === 0
                                      ? logicalOperatorOptionsFirstRow
                                      : logicalOperatorOptions
                                  }
                                  sx={{ py: 1 }}
                                />
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"open_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={openParenthesisOptions}
                                  sx={{ py: 1 }}
                                />
                                <Divider orientation="vertical" />

                                {expression.logical_expression === "Rule" ? (
                                  <Button
                                    onClick={() => {
                                      setRuleToEdit(expression);
                                      setOpenRuleSelect(true);
                                    }}
                                    aria-label="Rule"
                                    sx={{ p: 1 }}
                                  >
                                    {expression.logical_expression}
                                  </Button>
                                ) : (
                                  <Stack direction="column" sx={{ p: 1 }}>
                                    <Stack direction="row" spacing={1}>
                                      <Typography
                                        alignContent="center"
                                        variant="caption"
                                        sx={{
                                          display: "flex",
                                          flex: "20 1 0",
                                          fontWeight: expression.isRule
                                            ? 600
                                            : 400,
                                        }}
                                      >
                                        {expression.isRule
                                          ? ddxProps.ddxFunctions.find(
                                              (func) =>
                                                func.function_name.toLowerCase() ===
                                                expression?.logical_expression
                                                  ?.split("(")[0]
                                                  .toLowerCase()
                                            )?.function_name ?? ""
                                          : expression.logical_expression}
                                      </Typography>

                                      {expression.isRule && (
                                        <IconButton
                                          onClick={() => {
                                            setRuleToEdit(expression);
                                            setValues((prev) => {
                                              prev["expand_" + index] =
                                                "collapsed";

                                              return prev;
                                            });
                                            setOpenRuleSelect(true);
                                          }}
                                          aria-label="edit"
                                        >
                                          <EditIcon size={16} />
                                        </IconButton>
                                      )}
                                      {expression.isRule && (
                                        <IconButton
                                          aria-label="expand"
                                          onClick={async () => {
                                            setValues((prev) => {
                                              prev["expand_" + index] =
                                                prev["expand_" + index] ===
                                                "collapsed"
                                                  ? "expanded"
                                                  : "collapsed";

                                              return prev;
                                            });

                                            if (
                                              !(index in hydratedExpressions)
                                            ) {
                                              const modelExp =
                                                await hydrateRuleExpression(
                                                  expression.logical_expression
                                                );

                                              setHydratedExpressions(
                                                (prev) => ({
                                                  ...prev,
                                                  [index]:
                                                    modelExp.friendly_description_expanded ??
                                                    "",
                                                })
                                              );
                                            }
                                          }}
                                        >
                                          {values["expand_" + index] ===
                                          "collapsed" ? (
                                            <ExpandIcon size={16} />
                                          ) : (
                                            <CollapseIcon size={16} />
                                          )}
                                        </IconButton>
                                      )}
                                    </Stack>
                                    {values["expand_" + index] ===
                                    "expanded" ? (
                                      index in hydratedExpressions ? (
                                        <RuleDisplayComponent
                                          value={
                                            hydratedExpressions[index] || ""
                                          }
                                          ddxData={ddxProps}
                                        />
                                      ) : (
                                        <CircularProgress size={20} />
                                      )
                                    ) : null}
                                  </Stack>
                                )}
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"close_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={closeParenthesisOptions}
                                  sx={{ p: 1 }}
                                />
                              </DraggableExpression>
                            );
                          })}
                        </Box>
                      </Box>
                    )}
                  </DialogContent>
                  <SelectRuleDialog
                    open={openRuleSelect}
                    handleOnCloseButtonClick={function (): void {
                      setOpenRuleSelect(false);
                    }}
                    ddxProps={ddxProps}
                    expression={ruleToEdit ? ruleToEdit : undefined}
                    setHydratedExpressions={setHydratedExpressions}
                  ></SelectRuleDialog>
                </ExpressionBuilderContextProvider>
                {failed ? (
                  <Alert
                    severity="error"
                    onClose={() => {
                      setFailed(false);
                    }}
                  >
                    Error: Saving Expression
                  </Alert>
                ) : null}
                <Divider></Divider>
                <DialogActions sx={{ height: 50 }}>
                  <Button variant="outlined" onClick={handleClose}>
                    Cancel
                  </Button>
                  <Button variant="contained" type="submit">
                    Save
                  </Button>
                </DialogActions>
              </form>
            </FormValidateField>
          )}
        </Formik>
      </Dialog>
    </Box>
  );
};

const isNumericOrDate = (val: string): boolean => {
  if (!val) return false;

  const trimmed = val.trim();

  const isNumeric = !isNaN(Number(trimmed));

  const isDate = !isNaN(Date.parse(trimmed));

  return isNumeric || isDate;
};

export const fieldValuesToExpressions = (
  expressions: Expression[],
  values: { [x: string]: string },
  ddxData: DdxData
) => {
  expressions.forEach((expression, index) => {
    expression.field = values["field_" + index];
    expression.open_parenthesis = parseInt(values["open_parenthesis_" + index]);
    expression.close_parenthesis = parseInt(
      values["close_parenthesis_" + index]
    );
    expression.comparison_operator = values["comparison_operator_" + index];

    expression.value =
      values["value_type_" + index] === "F" && values["value_" + index]
        ? "[" + values["value_" + index] + "]"
        : isMultiValueOperator(values["comparison_operator_" + index]) &&
          typeof values["value_" + index] === "object"
        ? JSON.parse(JSON.stringify(values["value_" + index]))
            .map((item: string) =>
              isNumericOrDate(item) ? item : WrapWithInvisibleDelimiter(item)
            )
            .join(",")
        : isNumericOrDate(values["value_" + index])
        ? values["value_" + index]
        : WrapWithInvisibleDelimiter(values["value_" + index]);

    expression.value2 =
      values["value_type_" + index] === "F" && values["value2_" + index]
        ? "[" + values["value2_" + index] + "]"
        : WrapWithInvisibleDelimiter(values["value2_" + index]);
    expression.logical_operator = values["logical_operator_" + index] ?? "";
    expression.logical_expression = values["field_" + index]
      ? getLogicalExpressionFunc(
          getDdxFieldByDisplayName(
            ddxData.ddxFields,
            values["field_" + index]
          )[0],
          values["comparison_operator_" + index],
          values["value_" + index],
          values["value2_" + index],
          values["value_type_" + index]
        )
      : expression.logical_expression;
    expression.line_number = index;
  });
  return expressions;
};

export const modelExpressionToExpressions = (
  modelExpression: ModelExpression,
  ddxField: DdxField[],
  ddxFunctions: DdxFunction[]
) => {
  return modelExpression?.logic?.map((item: ModelExpressionLogic) => ({
    line_number: item.line_number,
    logical_operator: item.logical_operator ? item.logical_operator : "",
    open_parenthesis: item.open_parenthesis ? item.open_parenthesis : 0,
    close_parenthesis: item.close_parenthesis ? item.close_parenthesis : 0,
    comparison_operator: item.comparison_operator
      ? item.comparison_operator
      : null,
    friendly_description: item.friendly_description
      ? item.friendly_description
      : null,
    field: item.display_name ?? null,
    isRule: Boolean(
      item.friendly_description &&
        ddxFunctions.find(
          (func) =>
            func.function_name.toLowerCase() ===
            item.friendly_description?.split("(")[0].toLowerCase()
        )?.is_rule
    ),

    value: unwrapValue(item.comparison_operator, item.comparison_value),
    value2: unwrapValue(item.comparison_operator, item.comparison_value2),
    logical_expression: item.field_name
      ? getLogicalExpressionFunc(
          ddxField?.filter((x) => x.field_name === item.field_name)[0],
          item.comparison_operator ? item.comparison_operator : "",
          replaceUniCodeForMultiValues(item.comparison_value),
          replaceUniCodeForSingleValue(item.comparison_value2),
          ""
        )
      : item.friendly_description
          ?.replace(item.logical_operator ?? "", "")
          ?.trim() ?? "",
  }));
};

const replaceSquareBrackets = (value: string | null) => {
  return value?.toString().includes("[")
    ? value.replaceAll("[", "").replaceAll("]", "")
    : value ?? "";
};

export const expressionToFieldValues = (expression: Expression[]) => {
  const fieldValues: { [x: string]: string } = {};
  expression.forEach((exp, index) => {
    fieldValues["order_" + index] = (index + 1).toString() ?? "";
    fieldValues["logical_operator_" + index] = exp.logical_operator ?? "";
    fieldValues["field_" + index] = exp.field ?? "";
    fieldValues["comparison_operator_" + index] = exp.comparison_operator ?? "";
    fieldValues["value_" + index] = replaceSquareBrackets(exp?.value);
    fieldValues["value2_" + index] = replaceSquareBrackets(exp.value2);
    fieldValues["open_parenthesis_" + index] =
      exp.open_parenthesis?.toString() ?? "";
    fieldValues["close_parenthesis_" + index] =
      exp.close_parenthesis?.toString() ?? "";
    fieldValues["logical_expression_" + index] = exp.logical_expression ?? "";
    fieldValues["expand_" + index] = "collapsed";
    fieldValues["value_type_" + index] = exp.value?.toString().includes("[")
      ? "F"
      : "V";
  });
  return fieldValues;
};

import { SxProps, createTheme } from "@textile/mui";
import numeral from "numeral";
import { DdxData } from "./monaco-ddx-editor/ddx.types";

export const INVISIBLE_DELIMITER = "\u200B";
const COMPLEX_RULE_REGEX = /<%[\s\S]*?%>/;

export const INVISIBLE_DELIMITER_REGEX_PATTERN = new RegExp(
  `${INVISIBLE_DELIMITER}(?:[^${INVISIBLE_DELIMITER}]|${INVISIBLE_DELIMITER}')*${INVISIBLE_DELIMITER}`,
  "g"
);

export const WrapWithInvisibleDelimiter = (value: string | string[]) => {
  return (INVISIBLE_DELIMITER + value + INVISIBLE_DELIMITER)
    .replace(/'/g, INVISIBLE_DELIMITER + "'")
    .replaceAll(INVISIBLE_DELIMITER + INVISIBLE_DELIMITER, INVISIBLE_DELIMITER);
};

export const wrapMultiValues = (value: string | string[]) => {
  if (Array.isArray(value)) {
    return value.map((v) => {
      return WrapWithInvisibleDelimiter(v);
    });
  } else {
    return value?.split(",").map((v) => {
      return WrapWithInvisibleDelimiter(v);
    });
  }
};

export const isNullCheckOperator = (operator: string): boolean => {
  return ["IS NULL", "IS NOT NULL"].includes(operator?.trim()?.toUpperCase());
};
export const isRangeOperator = (operator: string): boolean => {
  return ["IS BETWEEN", "IS NOT BETWEEN"].includes(
    operator?.trim()?.toUpperCase()
  );
};
export const isMultiValueOperator = (operator: string): boolean => {
  return ["IS ONE OF", "IS NOT ONE OF"].includes(
    operator?.trim()?.toUpperCase()
  );
};
export const isLikeOperator = (operator: string): boolean => {
  return ["IS LIKE", "IS NOT LIKE"].includes(operator?.trim()?.toUpperCase());
};

export const unwrapValue = (
  comparison_operator: string | null | undefined,
  value: string | null | undefined
) => {
  const res = value
    ? !isMultiValueOperator(comparison_operator ?? "")
      ? replaceUniCodeForSingleValue(value)
      : value
    : "";
  return res;
};

export const replaceUniCodeForMultiValues = (
  value: string | null | undefined
) => {
  if (!value) return "";
  const items = value.split(
    new RegExp(`${INVISIBLE_DELIMITER},\\s*${INVISIBLE_DELIMITER}`)
  );
  return items.map((item) => replaceUniCodeForSingleValue(item));
};

export const replaceUniCodeForSingleValue = (
  value: string | null | undefined
) => {
  if (!value || typeof value != "string") return "";
  return value
    .replace(new RegExp(`^${INVISIBLE_DELIMITER}`), "")
    .replace(new RegExp(`${INVISIBLE_DELIMITER}$`), "")
    .replace(new RegExp(`${INVISIBLE_DELIMITER}'`, "g"), "'");
};

const breakpoints = createTheme().breakpoints.values;

const resolveDialogWidth = (width?: string | number): string | number => {
  if (!width) width = "sm";
  if (typeof width === "number") return width;
  return breakpoints[width as keyof typeof breakpoints] || width;
};

export const getDialogResizePaperPropsSx = (
  width?: string | number
): SxProps => ({
  resize: "both",
  overflow: "auto",
  maxWidth: "none", // <-- allow resizing
  width: resolveDialogWidth(width), //accepts 3 formats "1200px", 1200 or lg
});

export const formatFormula = (formula: string | null | undefined): string => {
  return formula?.replace("dbo.", "") ?? "";
};

export const percentFormat = (
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  value: any,
  format?: string,
  nullFormat?: string
): string => {
  if (value == null) {
    return nullFormat ?? "";
  }
  const formattedValue = format
    ? numeral(value).format(format.replace("%%", "").trim())
    : value.toString();
  return `${formattedValue}%`;
};

export const adjustDateTimeOffset = (
  asOfDate: Date,
  addOffsetHours: boolean
) => {
  const utcOffset = asOfDate.getTimezoneOffset();
  const offsetHours = -utcOffset / 60;

  const hours = Math.floor(offsetHours);
  const minutes = Math.round((offsetHours - hours) * 60);
  const adjustedDate = new Date(asOfDate.getTime());

  if (addOffsetHours) {
    adjustedDate.setHours(adjustedDate.getHours() + Math.abs(hours));
    adjustedDate.setMinutes(adjustedDate.getMinutes() + Math.abs(minutes));
  }

  return adjustedDate.toISOString();
};

export const isPassThroughCode = (expression: string) => {
  return COMPLEX_RULE_REGEX.test(expression);
};

// This is to replace placeholder parameters with friendly Parameter name
export const normalizeParameterSyntax = (value: string) => {
  if (!value || value.trim() === "") return value;

  //Replace {} of multi value parameters with ()
  //e.g. ThirdPartyCreditExposure({​ABS​}, {​A-1+​, ​A-2​}, {​A-​, ​AA​}, {OS​, ​SP}, {​B​})
  //with ThirdPartyCreditExposure((​ABS​), (​A-1+​, ​A-2​), (​A-​, ​AA​), (​OS​, ​SP​), (​B​))
  value = value.replace(/{/g, "(").replace(/}/g, ")");
  if (isPassThroughCode(value)) {
    //Replace placeholder parameters with {Parameter Name}
    //e.g. [security_type] IN (<% Security Type, SECURITY_TYPE, TEXT, TRUE, V %>)
    //with [Security Type] Is One Of ({Security Type})
    value = value.replace(
      /<%\s*([^,]+),[^%]*%>/g,
      (_match, p1) => `{${p1.trim()}}`
    );
  }

  return value;
};

export const expandDescription = (
  desc: string,
  ddxData: DdxData | undefined,
  visited = new Set<string>()
): string => {
  if (!ddxData?.ddxFunctions) return desc;
  const funcMap = new Map(
    ddxData.ddxFunctions
      .filter((f) => f.is_rule)
      .map((f) => [f.function_name, f.friendly_description ?? ""])
  );
  let expanded = desc;
  for (const [name, friendly] of Array.from(funcMap.entries())) {
    if (expanded.includes(name) && !visited.has(name)) {
      visited.add(name);
      expanded = expanded.replaceAll(
        `${name}()`,
        expandDescription(friendly, ddxData, visited)
      );
    }
  }
  return expanded;
};

