    [key: number]: string | null;
  }>({});

  const { error } = useMessageAnnouncer();
  useEffect(() => {
    setState([...expression]);
    setFailed(false);
    return () => {
      if (!isComplexRule) {
        setIsEditorEnabled(false);
      }
      setDdxErrors([]);
    };
  }, [expression, open, isComplexRule]);

  useEffect(() => {
    setInitialValues(expressionToFieldValues([...expression]));
  }, [expression, ddxProps]);

  const compOperator = (
    dataDictionaryFieldName: string,
    valueType: string
  ) => ({
    options: comparisonOperatorList?.filter(function (listItem) {
      const field = {
        ...getDdxFieldByDisplayName(
          ddxProps.ddxFields,
          dataDictionaryFieldName
        )[0],
      };
      field.lookup_type = valueType === "F" ? null : field.lookup_type;

      return field.data_type === "TABLE" ? [] : listItem.applicable(field);
    }),
  });

