const isNumericOrDate = (val: string): boolean => {
  if (!val) return false;

  const trimmed = val.trim();

  const isNumeric = !isNaN(Number(trimmed));

  const isDate = !isNaN(Date.parse(trimmed));

  return isNumeric || isDate;
};

export const fieldValuesToExpressions = (
  expressions: Expression[],
  values: { [x: string]: string },
  ddxData: DdxData
) => {
  expressions.forEach((expression, index) => {
    expression.field = values["field_" + index];
    expression.open_parenthesis = parseInt(values["open_parenthesis_" + index]);
    expression.close_parenthesis = parseInt(
      values["close_parenthesis_" + index]
    );
    expression.comparison_operator = values["comparison_operator_" + index];

    const isBoolean =
      getDdxFieldByDisplayName(
        ddxData.ddxFields,
        values["field_" + index]
      )[0]?.data_type?.toLowerCase() === "boolean";

    expression.value =
      values["value_type_" + index] === "F" && values["value_" + index]
        ? "[" + values["value_" + index] + "]"
        : isMultiValueOperator(values["comparison_operator_" + index]) &&
          typeof values["value_" + index] === "object"
        ? JSON.parse(JSON.stringify(values["value_" + index]))
            .map((item: string) =>
              isNumericOrDate(item) ? item : WrapWithInvisibleDelimiter(item)
            )
            .join(",")
        : isBoolean || isNumericOrDate(values["value_" + index])
        ? values["value_" + index]
        : WrapWithInvisibleDelimiter(values["value_" + index]);

    expression.value2 =
      values["value_type_" + index] === "F" && values["value2_" + index]
        ? "[" + values["value2_" + index] + "]"
        : WrapWithInvisibleDelimiter(values["value2_" + index]);
    expression.logical_operator = values["logical_operator_" + index] ?? "";
    expression.logical_expression = values["field_" + index]
      ? getLogicalExpressionFunc(
          getDdxFieldByDisplayName(
            ddxData.ddxFields,
            values["field_" + index]
          )[0],
          values["comparison_operator_" + index],
          values["value_" + index],
          values["value2_" + index],
          values["value_type_" + index]
        )
      : expression.logical_expression;
    expression.line_number = index;
  });
  return expressions;
};

export const modelExpressionToExpressions = (
  modelExpression: ModelExpression,
  ddxField: DdxField[],
  ddxFunctions: DdxFunction[]
) => {
  return modelExpression?.logic?.map((item: ModelExpressionLogic) => ({
    line_number: item.line_number,
    logical_operator: item.logical_operator ? item.logical_operator : "",
    open_parenthesis: item.open_parenthesis ? item.open_parenthesis : 0,
    close_parenthesis: item.close_parenthesis ? item.close_parenthesis : 0,
    comparison_operator: item.comparison_operator
      ? item.comparison_operator
      : null,
    friendly_description: item.friendly_description
      ? item.friendly_description
      : null,
    field: item.display_name ?? null,
    isRule: Boolean(
      item.friendly_description &&
        ddxFunctions.find(
          (func) =>
            func.function_name.toLowerCase() ===
            item.friendly_description?.split("(")[0].toLowerCase()
        )?.is_rule
    ),

    value: unwrapValue(item.comparison_operator, item.comparison_value),
    value2: unwrapValue(item.comparison_operator, item.comparison_value2),
    logical_expression: item.field_name
      ? getLogicalExpressionFunc(
          ddxField?.filter((x) => x.field_name === item.field_name)[0],
          item.comparison_operator ? item.comparison_operator : "",
          replaceUniCodeForMultiValues(item.comparison_value),
          replaceUniCodeForSingleValue(item.comparison_value2),
          ""
        )
      : item.friendly_description
          ?.replace(item.logical_operator ?? "", "")
          ?.trim() ?? "",
  }));
};

const replaceSquareBrackets = (value: string | null) => {
  return value?.toString().includes("[")
    ? value.replaceAll("[", "").replaceAll("]", "")
    : value ?? "";
};

export const expressionToFieldValues = (expression: Expression[]) => {
  const fieldValues: { [x: string]: string } = {};
  expression.forEach((exp, index) => {
    fieldValues["order_" + index] = (index + 1).toString() ?? "";
    fieldValues["logical_operator_" + index] = exp.logical_operator ?? "";
    fieldValues["field_" + index] = exp.field ?? "";
    fieldValues["comparison_operator_" + index] = exp.comparison_operator ?? "";
    fieldValues["value_" + index] = replaceSquareBrackets(exp?.value);
    fieldValues["value2_" + index] = replaceSquareBrackets(exp.value2);
    fieldValues["open_parenthesis_" + index] =
      exp.open_parenthesis?.toString() ?? "";
    fieldValues["close_parenthesis_" + index] =
      exp.close_parenthesis?.toString() ?? "";
    fieldValues["logical_expression_" + index] = exp.logical_expression ?? "";
    fieldValues["expand_" + index] = "collapsed";
    fieldValues["value_type_" + index] = exp.value?.toString().includes("[")
      ? "F"
      : "V";
  });
  return fieldValues;
};

document.text:
= useTheme();
 const { fetchHydrateExpression, fetchHydrateRuleExpression } =
   useExpressionValidator();
 const axiosFactory = useAxiosFactory();
 const {
   open,
   expression,
   ddxProps,
   handleOnCloseButtonClick,
   targetType,
   targetKey,
   children,
   setValue,
   isComplexRule,
 } = props;
 const [gridExpression, setState] = useState(expression);
 const [initialValues, setInitialValues] = useState<{ [x: string]: string }>(
   expressionToFieldValues(expression)
 );
 const [isEditorEnabled, setIsEditorEnabled] = useState(false);
 const [openRuleSelect, setOpenRuleSelect] = useState<boolean>(false);
 const [ruleToEdit, setRuleToEdit] = useState<Expression | null>(null);
 const [ddxErrors, setDdxErrors] = useState<
   DdxTranslationError[] | undefined
 >();
 const exprDescription = useRef<string>("");
 const editorVal = useRef<string>("");
 const [isSubmitting, setIsSubmitting] = useState(false);
 const [failed, setFailed] = useState<boolean>(false);
 const [isFullScreen, setIsFullScreen] = useState(false);
 const [isPassThrough, setIsPassThrough] = useState(false);

 const [hydratedExpressions, setHydratedExpressions] = useState<{
   [key: number]: string | null;
 }>({});

 const { error } = useMessageAnnouncer();
 useEffect(() => {
   setState([...expression]);
   setFailed(false);
   return () => {
     if (!isComplexRule) {
       setIsEditorEnabled(false);
     }
     setDdxErrors([]);
   };
 }, [expression, open, isComplexRule]);

 useEffect(() => {
   setInitialValues(expressionToFieldValues([...expression]));
 }, [expression, ddxProps]);

 const compOperator = (
   dataDictionaryFieldName: string,
   valueType: string
 ) => ({
   options: comparisonOperatorList?.filter(function (listItem) {
     const field = {
       ...getDdxFieldByDisplayName(
         ddxProps.ddxFields,
         dataDictionaryFieldName
       )[0],
     };
     field.lookup_type = valueType === "F" ? null : field.lookup_type;
     return field.data_type === "TABLE" ? false : listItem.applicable(field);
   }),
 });

 useEffect(() => {
   if (isComplexRule) {
     setIsEditorEnabled(true);
     const exprDesc = getFriendlyDescription(expression);
     exprDescription.current = exprDesc;
     isEditorDirty.current = false;
   }
 }, [isComplexRule]);

 const toggleEditor = async (
   setValues: ExpressionBuilderState["setValues"]
 ) => {
   if (isPassThroughCode(editorRef?.current?.getValue() ?? "")) {
     return;
   }

   if (
     isEditorEnabled &&
     editorRef.current &&
     editorRef?.current?.getValue()?.trim()?.length > 0
   ) {
     const modelExpression = await hydrateExpression(
       editorRef?.current?.getValue()
     );

     if (modelExpression.ddx_errors.length === 0) {
       setDdxErrors([]);
       const expressions = modelExpressionToExpressions(
         modelExpression,
         ddxProps.ddxFields,
         ddxProps.ddxFunctions
       );
       setValues(expressionToFieldValues(expressions));
       setState(expressions);
       setIsEditorEnabled((s) => !s);
     } else {
       setIsEditorEnabled(true);
       setDdxErrors(modelExpression.ddx_errors);
       modelExpression?.ddx_errors?.forEach((err) => {
         error(`${err.message_code}: ${err.message}`);
       });
     }
   } else {
     if (
       isEditorEnabled &&
       editorRef?.current?.getValue()?.trim()?.length === 0
     ) {
       setValues({});
       setState([]);
     }
     setIsEditorEnabled((s) => !s);
   }
 };

 const handleSubmit = useCallback(
   async (values: { [x: string]: string }) => {
     try {
       const expressions: Expression[] = fieldValuesToExpressions(
         [...gridExpression],
         values,
         ddxProps
       );

       setState(expressions);
       const editorValue = editorVal.current;
       exprDescription.current = editorValue ?? exprDescription.current;
       editorRef?.current?.setValue(
         isEditorEnabled
           ? editorValue
           : getFriendlyDescription(expressions) ?? ""
       );
       setIsSubmitting(true);
       const modelExpression = await fetchHydrateExpression(
         "FILTER_EXPRESSION",
         isEditorEnabled ? editorValue : getFriendlyDescription(expressions),
         "bool"
       );

       if (modelExpression.ddx_errors.length === 0) {
         setDdxErrors([]);
         if (setValue) {
           setValue(modelExpression);
         } else {
           const axios = await axiosFactory.createAxiosInstance();
           await axios.put(`/compliance-modeling/v1/expressionput`, {
             target_type: targetType,
             target_key: targetKey,
             ddx: modelExpression.ddx,
           });
         }
         handleOnCloseButtonClick ? handleOnCloseButtonClick() : null;
       } else {
         setDdxErrors(modelExpression.ddx_errors);
         setFailed(true);
       }
       isEditorDirty.current = false;
     } catch (err) {
       error("Error: Saving Expression");
     } finally {
       setIsSubmitting(false);
     }
   },
   [
     axiosFactory,
     ddxProps,
     error,
     fetchHydrateExpression,
     gridExpression,
     handleOnCloseButtonClick,
     isEditorEnabled,
     setValue,
     targetKey,
     targetType,
   ]
 );

 const hydrateExpression = async (friendlyDescription?: string) => {
   return await fetchHydrateExpression(
     "FILTER_EXPRESSION",
     friendlyDescription,
     "bool"
   );
 };

 const hydrateRuleExpression = async (friendlyDescription?: string) => {
   return await fetchHydrateRuleExpression(
     "FILTER_EXPRESSION",
     friendlyDescription,
     "bool"
   );
 };

 const isEditorDirty = useRef(false);

 const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
 const handleGetEditorRef = (editor: monaco.editor.IStandaloneCodeEditor) => {
   editorRef.current = editor;
   editorRef?.current?.onDidChangeModelContent(() => {
     isEditorDirty.current = true;
     setIsPassThrough(isPassThroughCode(editorRef?.current?.getValue() ?? ""));
   });
   // Set initial passthrough state
   setIsPassThrough(isPassThroughCode(editorRef?.current?.getValue() ?? ""));
 };

 const getFriendlyDesc = useCallback(() => {
   editorVal.current = editorRef?.current?.getValue() ?? "";
   if (!isEditorEnabled || isEditorDirty.current) {
     return editorRef?.current?.getValue() ?? "";
   } else {
     return exprDescription.current ?? "";
   }
 }, [isEditorEnabled]);
 const onDdxToDetailsRef = useRef<(() => void) | null>(null);

 const handleClose = useCallback(() => {
   setIsFullScreen(false);
   handleOnCloseButtonClick?.();
 }, [handleOnCloseButtonClick]);

 return (
   <Box>
     <Dialog
       open={open}
       fullWidth
       fullScreen={isFullScreen}
       PaperProps={{
         sx: !isFullScreen ? getDialogResizePaperPropsSx("xl") : {},
       }}
       draggable={true}
     >
