interface FormValueFieldProps {
  id: string;
  dataType: string;
  textFieldProps: TextFieldProps;
  tableValueSchema?: DataGridMeta;
  textFieldInputProps?: {
    [x: string]: string | undefined;
  };
}

export const FormValueField: FunctionComponent<FormValueFieldProps> = ({
  id,
  dataType,
  textFieldProps,
  tableValueSchema,
  textFieldInputProps,
}) => {
  const { label, variant, required, disabled } = textFieldProps;
  switch (dataType) {
    case "BOOLEAN":
      return (
        <FormFieldGroup>
          <FormAutocomplete
            fieldName={id}
            valueField={"id"}
            labelField={"value"}
            options={[
              { id: true, value: "Yes" },
              { id: false, value: "No" },
            ]}
            textFieldProps={textFieldProps}
          ></FormAutocomplete>
        </FormFieldGroup>
      );
    case "DATE":
      return (
        <FormFieldGroup sx={{ flexDirection: "column" }}>
          <FormCustomDatePicker
            fieldName={id}
            label={label}
            textFieldProps={{
              ...textFieldProps,
              helperText: "",
            }}
          ></FormCustomDatePicker>
        </FormFieldGroup>
      );
    case "CURRENCY":
    case "NUMERIC":
    case "PERCENT":
      return (
        <FormFieldGroup sx={{ gap: 0.5 }}>
          <FormTextField
            fieldName={id}
            label={label}
            variant={variant}
            required={required}
            disabled={disabled}
            InputProps={{
              inputProps: {
                type: "number",
                ...textFieldInputProps,
              },
            }}
          ></FormTextField>
          {dataType === "CURRENCY" ? (
            <Typography sx={{ pt: 1 }}>$</Typography>
          ) : dataType === "PERCENT" ? (
            <Typography sx={{ pt: 1 }}>%</Typography>
          ) : null}
        </FormFieldGroup>
      );
    case "TABLE":
      return (
        <FormTableGrid
          id={id}
          tableValueSchema={tableValueSchema}
          label={label}
        />
      );
    default:
      return (
        <FormFieldGroup>
          <FormTextField
            fieldName={id}
            label={label}
            variant={variant}
            required={required}
            disabled={disabled}
            InputProps={{
              inputProps: {
