            : `data_types="${dataType ?? ""}"`,
        },
      }),
      // eslint-disable-next-line react-hooks/exhaustive-deps
      [dataType, isCalculated, selectedPortfolio, refreshToken]
    );

  return (
    <Box sx={toggleButtonBoxProps}>
      {valueTypeState ? (
        valueTypeState === "val" ? (
          <FormValueField
            id={valFieldId}
            dataType={dataType}
            tableValueSchema={tableValueSchema}
            textFieldProps={textFieldProps}
          ></FormValueField>
