interface FormTableGridProps {
  id: string;
  tableValueSchema?: DataGridMeta;
  label: React.ReactNode;
}

const agGridCustomSx: SxProps = {
  ".ag-cell-wrapper": {
    paddingTop: 0.25,
    paddingLeft: 1.25,
  },
  ".ag-cell": {
    padding: 0.75,
  },
};

const tableGridSxProps: SxProps = {
  height: "400px",
  flexGrow: 1,
  ...agGridCustomSx,
};

export const CustomCellRenderer = (params: ICellRendererParams) => {
  return (
    <Box
      sx={{
        borderRadius: "4px",
        border: "1px solid rgba(0, 0, 0, 0.23)",
        py: 0.25,
        px: 1,
        "&:hover": {
          borderColor: "rgba(0, 0, 0, 0.87)",
        },
        height: "100%",
      }}
    >
      <Typography
        variant="inherit"
        noWrap
        sx={{
          overflow: "hidden",
          textOverflow: "ellipsis",
        }}
      >
        {params.valueFormatted}
      </Typography>
    </Box>
  );
};

export const FormTableGrid: FunctionComponent<FormTableGridProps> = ({
  id,
  tableValueSchema,
  label,
}) => {
  const { setFieldValue } = useFormikContext();
  const [{ value: tableValues }] = useField(id);
  const [disableDelete, setDisableDelete] = useState<boolean>(true);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [selectedTableRecords, setSelectedRecords] = useState<any>([]);
  const [colDefOverrides, setColDefOverrides] = useState<ColDefOverride[]>([]);

  useEffect(() => {
    if (tableValueSchema?.gridFields) {
      const overrides = tableValueSchema.gridFields.map((field) => ({
        field: field.name,
        colDef: {
          editable: true,
          cellRenderer: CustomCellRenderer,
        },
      }));
      setColDefOverrides(overrides);
    }
  }, [tableValueSchema?.gridFields]);

  const handleAdd = useCallback(() => {
    const newRecord: Record<string, string> = {};

    tableValueSchema?.gridFields?.forEach((field) => {
      newRecord[field.name] = field.name === "id" ? uuid() : "";
    });

    setFieldValue(id, [...(tableValues ?? []), newRecord]);
  }, [id, setFieldValue, tableValueSchema?.gridFields, tableValues]);

  const handleDelete = useCallback(() => {
    if (selectedTableRecords.length > 0)
      setFieldValue(id, [
        ...tableValues.filter(
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          (value: any) =>
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            !selectedTableRecords.some((record: any) => record.id === value.id)
        ),
      ]);
  }, [id, selectedTableRecords, setFieldValue, tableValues]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleSelectionChange = useCallback((selectedRecords: any[]) => {
    setDisableDelete(selectedRecords.length !== 0 ? false : true);
    setSelectedRecords(selectedRecords.length !== 0 ? selectedRecords : []);
  }, []);

  return (
    <FormFieldGroup>
      <FormDataGrid<Record<string, unknown>>
        label={label as string}
        fieldName={id}
        meta={tableValueSchema ?? { idField: "id", gridFields: [] }}
        sx={tableGridSxProps}
        rowSelectionMode="multi"
        agGridProps={{
          getRowHeight: function () {
            return 50;
          },
          suppressRowClickSelection: true,
          singleClickEdit: true,
          stopEditingWhenCellsLoseFocus: true,
        }}
        colDefOverrides={colDefOverrides}
        onSelectionChanged={handleSelectionChange}
      >
        <Box sx={{ display: "flex", flexDirection: "row" }}>
          <IconButton aria-label="Add" onClick={handleAdd}>
            <AddIcon size={24} />
          </IconButton>
          <IconButton
            aria-label="Delete"
            onClick={handleDelete}
            disabled={disableDelete}
          >
            <DeleteIcon size={24} />
          </IconButton>
        </Box>
      </FormDataGrid>
    </FormFieldGroup>
  );
};

interface FormValueFieldProps {
  id: string;
  dataType: string;
  textFieldProps: TextFieldProps;
  tableValueSchema?: DataGridMeta;
  textFieldInputProps?: {
    [x: string]: string | undefined;
  };
}

export const FormValueField: FunctionComponent<FormValueFieldProps> = ({
  id,
  dataType,
  textFieldProps,
  tableValueSchema,
  textFieldInputProps,
}) => {
  const { label, variant, required, disabled } = textFieldProps;
  switch (dataType) {
    case "BOOLEAN":
      return (
        <FormFieldGroup>
          <FormAutocomplete
            fieldName={id}
            valueField={"id"}
            labelField={"value"}
            options={[
              { id: true, value: "Yes" },
              { id: false, value: "No" },
            ]}
            textFieldProps={textFieldProps}
          ></FormAutocomplete>
        </FormFieldGroup>
      );
    case "DATE":
      return (
        <FormFieldGroup sx={{ flexDirection: "column" }}>
          <FormCustomDatePicker
            fieldName={id}
            label={label}
            textFieldProps={{
              ...textFieldProps,
              helperText: "",
            }}
          ></FormCustomDatePicker>
        </FormFieldGroup>
      );
    case "CURRENCY":
    case "NUMERIC":
    case "PERCENT":
      return (
        <FormFieldGroup sx={{ gap: 0.5 }}>
          <FormTextField
            fieldName={id}
            label={label}
            variant={variant}
            required={required}
            disabled={disabled}
            InputProps={{
              inputProps: {
                type: "number",
                ...textFieldInputProps,
              },
            }}
          ></FormTextField>
          {dataType === "CURRENCY" ? (
            <Typography sx={{ pt: 1 }}>$</Typography>
          ) : dataType === "PERCENT" ? (
            <Typography sx={{ pt: 1 }}>%</Typography>
          ) : null}
        </FormFieldGroup>
      );
    case "TABLE":
      return (
        <FormTableGrid
          id={id}
          tableValueSchema={tableValueSchema}
          label={label}
        />
      );
    default:
      return (
        <FormFieldGroup>
          <FormTextField
            fieldName={id}
            label={label}
            variant={variant}
            required={required}
            disabled={disabled}
            InputProps={{
              inputProps: {
                ...textFieldInputProps,
              },
            }}
          ></FormTextField>
        </FormFieldGroup>
      );
  }
};

