                                  valueField={"value"}
                                  labelField={"displayText"}
                                  sx={{ py: 1 }}
                                  textFieldProps={{
                                    required: index !== 0,
                                  }}
                                  options={
                                    index === 0
                                      ? logicalOperatorOptionsFirstRow
                                      : logicalOperatorOptions
                                  }
                                />
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"open_parenthesis_" + index}
                                  aria-label={"open_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  sx={{ py: 1 }}
                                  options={openParenthesisOptions}
                                />
                                <Divider orientation="vertical" />
                                <Box sx={{ py: 1, display: "flex" }}>
                                  <FormDdxFieldsGrid
                                    id={"field_" + index}
                                    sx={{
