                        line_number: 0,
                        close_parenthesis: 0,
                        logical_operator: "",
                        comparison_operator: "",
                        field: null,
                        logical_expression: "",
                        open_parenthesis: 0,
                        value: "",
                        value2: "",
                      },
                    ]);
                    setOpen(true);
