                                            values[
                                              "comparison_operator_" + index
                                            ]
                                          )
                                        }
                                        onChange={(_e, v) => {
                                          if (v) {
                                            setValues((prev) => {
                                              if (v === "V") {
                                                const val =
                                                  prev[
                                                    "cached_value_V" + index
                                                  ] ?? null;
                                                prev["cached_value_F" + index] =
                                                  prev["value_" + index];
                                                prev["value_" + index] = val;
                                              } else {
                                                const val =
                                                  prev[
                                                    "cached_value_F" + index
                                                  ] ?? null;
                                                prev["cached_value_V" + index] =
                                                  prev["value_" + index];
                                                prev["value_" + index] = val;
                                              }

                                              prev["value_type_" + index] = v;
                                              return prev;
                                            });
                                          }
                                        }}
                                        aria-label={"toggle_button_" + index}
                                      >
                                        <ToggleButton
                                          sx={{ height: 16 }}
                                          value={"V"}
                                          aria-label="V"
                                        >
                                          V
                                        </ToggleButton>
                                        <ToggleButton
                                          sx={{ height: 16 }}
                                          value={"F"}
                                          aria-label="F"
                                        >
                                          F
                                        </ToggleButton>
                                      </ToggleButtonGroup>
                                    ) : null}
                                    <Stack
                                      sx={{
                                        display: "flex",
                                        flex: "4 1 0",
                                        mr: 1,
                                      }}
                                      direction="column"
                                      spacing={1}
                                    >
                                      {values["field_" + index] &&
                                      !isNullCheckOperator(
                                        values["comparison_operator_" + index]
                                      ) &&
                                      values["comparison_operator_" + index] ? (
                                        values["value_type_" + index] ===
                                        "F" ? (
                                          <FormDdxFieldsGrid
                                            id={"value_" + index}
                                            ddxFields={ddxProps.ddxFields.filter(
                                              (item) => {
                                                return (
                                                  item.data_type ===
                                                  getDdxFieldByDisplayName(
                                                    ddxProps.ddxFields,
                                                    values["field_" + index]
                                                  )[0]?.data_type
                                                );
                                              }
                                            )}
                                            required
                                          ></FormDdxFieldsGrid>
                                        ) : getDdxFieldByDisplayName(
                                            ddxProps.ddxFields,
                                            values["field_" + index]
                                          )[0]?.lookup_type ? (
                                          <ExpressionBuilderLookupAutoComplete
                                            id={"value_" + index}
                                            label={"Value"}
                                            required={true}
                                            multiple={isMultiValueOperator(
                                              values[
                                                "comparison_operator_" + index
                                              ]
                                            )}
                                            lookupType={
                                              getDdxFieldByDisplayName(
                                                ddxProps.ddxFields,
                                                values["field_" + index]
                                              )[0].lookup_type ?? ""
                                            }
                                            ddxProps={ddxProps}
                                          ></ExpressionBuilderLookupAutoComplete>
                                        ) : getDdxFieldByDisplayName(
                                            ddxProps.ddxFields,
                                            values["field_" + index]
                                          )[0]?.data_type?.toLowerCase() ===
                                          "boolean" ? (
                                          <FormAutocomplete
                                            fieldName={"value_" + index}
                                            valueField={"value"}
                                            labelField={"id"}
                                            options={booleanOptions}
                                            textFieldProps={{
                                              required: true,
                                              label: "Value",
                                            }}
                                          ></FormAutocomplete>
                                        ) : (
                                          <FormValueField
                                            id={"value_" + index}
                                            dataType={
                                              getDdxFieldByDisplayName(
                                                ddxProps.ddxFields,
                                                values["field_" + index]
                                              )[0]?.data_type?.toUpperCase() ??
                                              ""
                                            }
                                            textFieldProps={{
                                              label: "Value",
                                              required: true,
                                            }}
                                          ></FormValueField>
                                        )
                                      ) : (
                                        <TextField
                                          label={"Value"}
                                          disabled
                                        ></TextField>
                                      )}

                                      {isRangeOperator(
                                        values["comparison_operator_" + index]
                                      ) ? (
                                        values["value_type_" + index] ===
                                        "F" ? (
                                          <FormDdxFieldsGrid
                                            id={"value2_" + index}
                                            ddxFields={ddxProps.ddxFields.filter(
                                              (item) => {
                                                return (
                                                  item.data_type ===
                                                  getDdxFieldByDisplayName(
                                                    ddxProps.ddxFields,
                                                    values["field_" + index]
                                                  )[0]?.data_type
                                                );
                                              }
                                            )}
                                            required
                                          ></FormDdxFieldsGrid>
                                        ) : (
                                          <FormValueField
                                            id={"value2_" + index}
                                            dataType={
                                              getDdxFieldByDisplayName(
                                                ddxProps.ddxFields,
                                                values["field_" + index]
                                              )[0]?.data_type?.toUpperCase() ??
                                              ""
                                            }
                                            textFieldProps={{
                                              label: "Value2",
                                              required: true,
                                            }}
                                          ></FormValueField>
                                        )
                                      ) : null}
                                    </Stack>
                                  </Stack>
                                </Box>
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"close_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={closeParenthesisOptions}
                                  sx={{ py: 1, pr: 1 }}
                                />
                              </DraggableExpression>
                            ) : (
                              <DraggableExpression index={index}>
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"logical_operator_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  aria-label={"logical_operator_" + index}
                                  textFieldProps={{
                                    required: index !== 0,
                                  }}
                                  options={
                                    index === 0
                                      ? logicalOperatorOptionsFirstRow
                                      : logicalOperatorOptions
                                  }
                                  sx={{ py: 1 }}
                                />
                                <Divider orientation="vertical" />
                                <FormAutocomplete
                                  fieldName={"open_parenthesis_" + index}
                                  valueField={"value"}
                                  labelField={"displayText"}
                                  options={openParenthesisOptions}
                                  sx={{ py: 1 }}
                                />
                                <Divider orientation="vertical" />

                                {expression.logical_expression === "Rule" ? (
                                  <Button
                                    onClick={() => {
                                      setRuleToEdit(expression);
                                      setOpenRuleSelect(true);
                                    }}
                                    aria-label="Rule"
                                    sx={{ p: 1 }}
                                  >
                                    {expression.logical_expression}
                                  </Button>
                                ) : (
                                  <Stack direction="column" sx={{ p: 1 }}>
                                    <Stack direction="row" spacing={1}>
                                      <Typography
                                        alignContent="center"
                                        variant="caption"
                                        sx={{
                                          display: "flex",
                                          flex: "20 1 0",
                                          fontWeight: expression.isRule
                                            ? 600
                                            : 400,
                                        }}
                                      >
                                        {expression.isRule
                                          ? ddxProps.ddxFunctions.find(
                                              (func) =>
                                                func.function_name.toLowerCase() ===
                                                expression?.logical_expression
                                                  ?.split("(")[0]
                                                  .toLowerCase()
                                            )?.function_name ?? ""
                                          : expression.logical_expression}
                                      </Typography>

                                      {expression.isRule && (
                                        <IconButton
                                          onClick={() => {
                                            setRuleToEdit(expression);
                                            setValues((prev) => {
                                              prev["expand_" + index] =
