export const getFriendlyDescription = (expressions: Expression[]) => {
  return expressions
    .map((item) => ({
      ddx:
        item.logical_operator +
        " " +
        (item.open_parenthesis
          ? openParenthesisOptions?.filter(
              (x) => x.value === item.open_parenthesis.toString()
            )[0]?.displayText
          : "") +
        item.logical_expression +
        (item.close_parenthesis
          ? closeParenthesisOptions?.filter(
              (x) => x.value === item.close_parenthesis.toString()
            )[0]?.displayText
          : ""),
    }))
    .map((u) => u.ddx)
    .join(" ");
};

export const ExpressionBuilderContext =
  createContext<ExpressionBuilderState | null>(null);

export interface ExpressionBuilderContextProviderProps
  extends ExpressionBuilderState {
  children?: ReactNode;
}

export const ExpressionBuilderContextProvider: FunctionComponent<
  ExpressionBuilderContextProviderProps
> = ({ children, ...props }) => {
  return (
    <ExpressionBuilderContext.Provider value={props}>
      {children}
    </ExpressionBuilderContext.Provider>
  );
};

export const useExpressionBuilderContext = () => {
  const context = useContext(ExpressionBuilderContext);

  if (!context) {
    throw new Error(
      "useExpressionBuilderContext cannot be called outside of a ExpressionBuilderContext"
    );
  }

  return context;
};

const getDdxFieldByDisplayName = (
  ddxFields: DdxField[],
  displayName: string
) => {
  return ddxFields.filter((field) => field.display_name === displayName);
};

