import { useCallback, useMemo, useRef, useState } from "react";
import {
  GridReadyEvent,
  IRowNode,
  RowClickedEvent,
  CellKeyDownEvent,
  GetQuickFilterTextParams,
} from "@textile/ag-grid";
import {
  DataGridMeta,
  DataGridPanel,
  DataGridQuickSearch,
  useField,
} from "@textile/biz-components";
import {
  IconButton,
  InputAdornment,
  Popover,
  SxProps,
  TextField,
  TextFieldProps,
  Theme,
} from "@textile/mui";
import { ArrowDownIcon } from "@textile/common";
import {
  DdxField,
  useExpressionBuilderContext,
} from "../../solvasam-bizcomponents";

interface FormDdxFieldsGridProps {
  ddxFields: DdxField[];
  id?: string;
  sx?: SxProps<Theme>;
  index?: number | null;
}

export const FieldsMeta: DataGridMeta = {
  idField: "id",
  title: "Select a Field",
  gridActionMasks: [],
  dataTypeFormats: {},
  initialOrderBy: "display_name",
  gridFields: [
    {
      name: "id",
      dataType: "id",
      header: "Id",
      visible: false,
      isLink: false,
    },
    {
      name: "display_name",
      dataType: "string",
      header: "Field Name",
      visible: true,
      isLink: false,
      flex: 1,
    },
    {
      name: "aggregation_level_description",
      dataType: "string",
      header: "Aggregation Level",
      visible: true,
      isLink: false,
      flex: 2,
    },
    {
      name: "data_type",
      dataType: "string",
      header: "Data Type",
      visible: true,
      isLink: false,
      flex: 1,
    },
  ],
};
const gridSx: SxProps = {
  display: "flex",
  flexGrow: 1,
  height: "30vmax",
  width: "35vmax",
  m: 3,
};

export const FormDdxFieldsGrid = (
  props: FormDdxFieldsGridProps & Partial<TextFieldProps>
) => {
  const { id, ddxFields, sx, index, ...others } = props;
  const [field, , helpers] = useField<string>(id ?? "missing-id");
  const [, , valueHelpers] = useField<string | null>(
    index !== null ? "value_" + index : "missing-index"
  );
  const [, , cacheValueVHelper] = useField<string | null>(
    index !== null ? "cached_value_V" + index : "missing-index"
  );
  const [, , cacheValueFHelper] = useField<string | null>(
    index !== null ? "cached_value_F" + index : "missing-index"
  );

  const [, , comparisonOperatorHelper] = useField<string | null>(
    index !== null ? "comparison_operator_" + index : "missing-index"
  );

  const iconButtonRef = useRef<HTMLButtonElement>(null);
  const textFieldRef = useRef<HTMLInputElement>(null);
  const [anchorEl, setAnchorEl] = useState<HTMLElement | null>(null);
  const searchTextRef = useRef<HTMLInputElement>(null);
  const fieldSx = useMemo(
    () => ({
      flex: "1 1 0px",
      ...sx,
    }),
    [sx]
  );

  const handleClick = () => {
    if (iconButtonRef.current) {
      setAnchorEl(iconButtonRef.current);
    }
  };

  const handleClose = () => {
    setAnchorEl(null);
    if (textFieldRef.current) {
      const formElements = Array.from(
        document.querySelectorAll<HTMLElement>(
          'input, button, select, textarea, a[href], [tabindex]:not([tabindex="-1"])'
        )
      ).filter((el) => !el.hasAttribute("disabled") && el.tabIndex >= 0);
      const currentIndex = formElements.indexOf(textFieldRef.current);
      const nextElement = formElements[currentIndex + 1];
      if (nextElement) nextElement.focus();
    }
  };

  const open = Boolean(anchorEl);
  const popoverId = open ? "popover" : undefined;

  const onRowClicked = useCallback(
    (event: RowClickedEvent) => {
      const selectedRecord: IRowNode<DdxField>[] = event.api.getSelectedNodes();
      if (selectedRecord && selectedRecord.length === 1) {
        helpers.setValue(selectedRecord[0].data?.display_name ?? "");
        valueHelpers.setValue(null);
        cacheValueVHelper.setValue(null);
        cacheValueFHelper.setValue(null);
        if (selectedRecord[0].data?.data_type === "TABLE") {
          comparisonOperatorHelper.setValue(null);
        }
        handleClose();
      }
    },
    [helpers, valueHelpers]
  );

  const onCellKeyDown = useCallback(
    (event: CellKeyDownEvent) => {
      const keyboardEvent = event.event as KeyboardEvent;
      if (keyboardEvent.key === "Enter") {
        const focusedNode = event.api.getDisplayedRowAtIndex(
          event.rowIndex as number
        );
        if (focusedNode && focusedNode.data) {
          helpers.setValue(focusedNode.data.display_name ?? "");
          handleClose();
        }
      }
    },
    [helpers]
  );

  const onGridReady = useCallback(
    (params: GridReadyEvent) => {
      params.api.forEachNode((node) =>
        node.data?.display_name === field.value
          ? node.setSelected(true)
          : node.setSelected(false)
      );
    },
    [field.value]
  );

  const handlePopoverEntered = () => {
    if (open && searchTextRef.current) {
      searchTextRef.current.focus();
    }
  };

  return (
    <>
      <TextField
        label="Field Name"
        sx={fieldSx}
        value={field.value ?? ""}
        inputRef={textFieldRef}
        onClick={handleClick}
        onFocus={handleClick}
        InputProps={{
          endAdornment: (
            <InputAdornment position="end">
              <IconButton
                ref={iconButtonRef}
                aria-label="field-options"
                edge="end"
                onClick={handleClick}
                sx={{ m: 0 }}
              >
                {<ArrowDownIcon size={24} />}
              </IconButton>
            </InputAdornment>
          ),
        }}
        {...others}
      />
      <Popover
        id={popoverId}
        open={open}
        anchorEl={anchorEl}
        onClose={handleClose}
        TransitionProps={{ onEntered: handlePopoverEntered }}
        anchorOrigin={{ vertical: "bottom", horizontal: "left" }}
        transformOrigin={{ vertical: "top", horizontal: "right" }}
        disableAutoFocus
        disableEnforceFocus
        disableRestoreFocus
      >
        {open && (
          <DataGridPanel
            meta={FieldsMeta}
            data={{ rowData: ddxFields }}
            sx={gridSx}
            agGridProps={{
              rowSelection: "single",
              suppressRowClickSelection: false,
              enableCellTextSelection: true,
              onGridReady: onGridReady,
              onRowClicked: onRowClicked,
              onCellKeyDown: onCellKeyDown,
              defaultColDef: {
                getQuickFilterText: (
                  // eslint-disable-next-line @typescript-eslint/no-explicit-any
                  params: GetQuickFilterTextParams<any, any>
                ) => {
                  return params.column.getColId() == "display_name"
                    ? params.value
                    : "";
                },
              },
              quickFilterMatcher: (
                quickFilterParts: string[],
                rowQuickFilterAggregateText: string
              ) => {
                return (
                  rowQuickFilterAggregateText.indexOf(
                    quickFilterParts.join(" ")
                  ) >= 0
                );
              },
            }}
          >
            <DataGridQuickSearch inputRef={searchTextRef} />
          </DataGridPanel>
        )}
      </Popover>
    </>
  );
};

