export const FormulaBuilderScreen = () => {
  const exp: ModelExpression = {
    id: "",
    code: "",
    logic: [
      {
        line_number: 0,
        logical_operator: "NOT",
        open_parenthesis: 1,
        close_parenthesis: 1,
        comparison_operator: "=",
        comparison_value: "10",
        comparison_value2: "",
        field_name: "issue_id",
        display_name: "Issue ID",
        friendly_description: "NOT ([Issue ID] = '10')",
        ddx: "",
        raw_description: null,
        created_by: "",
        modified_by: "",
      },
      {
        line_number: 1,
        logical_operator: "AND",
        open_parenthesis: 0,
        close_parenthesis: 0,
        comparison_operator: "=",
        comparison_value: "10",
        comparison_value2: "",
        field_name: null,
        display_name: "",
        friendly_description:
          "AND LienTypeTest({'UAE Dirham','Afghani','Lek'},'lien_type')",
        ddx: "",
        raw_description: null,
        created_by: "",
        modified_by: "",
      },
    ],
    friendly_description:
      "NOT ([Issue ID] = '10') AND LienTypeTest({'UAE Dirham','Afghani','Lek'},'lien_type')",
    raw_description: null,
    ddx: "",
    created_by: "",
    modified_by: "",
    ddx_errors: [],
  };
  const FormBase = styled("form")({});
  const ddxData = useDdxValues();
  return (
    <Box>
      <Formik
        initialValues={{ formula_expression: exp }}
        onSubmit={() => Promise.resolve()}
      >
        {({ handleSubmit }) => (
          <FormValidateField>
            <FormBase onSubmit={handleSubmit}>
              <FormControl sx={{ display: "flex", flex: "1 1 0", my: 2 }}>
                <FormFormulaEditor
                  id="formula_expression"
                  purpose="FIELD_FORMULA"
                  errors={[]}
                  ddxData={ddxData}
                ></FormFormulaEditor>
              </FormControl>
              <DialogActions>
                <Button>Cancel</Button>
                <Button type="submit" sx={{ width: 70, placeSelf: "end" }}>
                  Finish
                </Button>
              </DialogActions>
            </FormBase>
          </FormValidateField>
        )}
      </Formik>
    </Box>
  );
};

