import {
  LocalizationProvider,
  TextFieldProps,
  AdapterDateFns,
  TextField,
  Tooltip,
  InputAdornment,
  IconButton,
  Popover,
  DateCalendar,
} from "@textile/mui";

import {
  ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { useField } from "@textile/biz-components";

import { Locale, format, parse, addMonths, addYears } from "date-fns";
import {
  enUS,
  enGB,
  fr,
  de,
  es,
  it,
  ja,
  zhCN,
  zhTW,
  ptBR,
} from "date-fns/locale";
import dayjs from "dayjs";
import { CalendarIcon, CloseIcon } from "@textile/common";

/**
 * Converts a Date object to ISO string at UTC midnight (00:00:00.000Z)
 * This ensures the date doesn't shift when converted to UTC
 */
function dateToISOString(date: Date): string {
  const year = date.getFullYear();
  const month = date.getMonth();
  const day = date.getDate();
  // Create date at UTC midnight to avoid timezone shifts
  const utcDate = new Date(Date.UTC(year, month, day, 0, 0, 0, 0));
  return utcDate.toISOString();
}

/**
 * Parses a date string that can be either ISO date format (MM/DD/YYYY)  or localized format (MM/DD/YYYY)
 * supports formats like:
 * - ISO: "2025-11-25" or "2025-11-25T18:30:00Z"
 * - Localized: "11/25/2025" (from toLocaleDateString())
 * Returns a Date object at UTC noon to avoid timezone shifts when displaying
 */
function parseDateFromISO(dateString: string): Date | null {
  if (!dateString || typeof dateString !== "string") return null;

  try {
    // Extract date part (YYYY-MM-DD or YYYY-MM-DDTHH:mm:ssZ)
    const isoMatch = dateString.match(/^(\d{4}-\d{2}-\d{2})/);
    if (isoMatch) {
      const [year, month, day] = isoMatch[1].split("-").map(Number);
      return new Date(Date.UTC(year, month - 1, day, 12, 0, 0, 0));
    }

    //Try localized format (MM/DD/YYYY or M/D/YYYY) - common format from toLocaleDateString()
    const localizedMatch = dateString.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if (!localizedMatch) return null;
    const [, month, day, year] = localizedMatch.map(Number);
    //Validate date components
    if (month < 1 || month > 12 || day < 1 || day > 31) return null;
    return new Date(Date.UTC(year, month - 1, day, 12, 0, 0, 0));
  } catch {
    return null;
  }
}

/** Helper to map navigator.language to a date-fns locale */
export function getLocaleFromBrowser(): Locale {
  const lang = (navigator.language || "en-US").toLowerCase();

  const localeMap: Record<string, Locale> = {
    "en-us": enUS,
    "en-gb": enGB,
    fr,
    de,
    es,
    it,
    ja,
    "zh-cn": zhCN,
    "zh-tw": zhTW,
    "pt-br": ptBR,
  };

  return localeMap[lang] || localeMap[lang.split("-")[0]] || enUS;
}

export interface FormCustomDatePickerProps<R = Record<string, unknown>> {
  fieldName: keyof R & string;
  label: ReactNode;
  helperText?: string;
  locale?: Locale;
  textFieldProps?: Partial<TextFieldProps>;
}

export function FormCustomDatePicker<R = Record<string, unknown>>({
  fieldName,
  label,
  helperText,
  locale,
  textFieldProps,
}: FormCustomDatePickerProps<R>) {
  const detectedLocale = locale || getLocaleFromBrowser();

  const [field, meta, helpers] = useField<string | null>(fieldName as string);
  const [inputValue, setInputValue] = useState<string>("");
  const [anchorEl, setAnchorEl] = useState<HTMLElement | null>(null);
  const [calendarView, setCalendarView] = useState<"year" | "month" | "day">(
    "day"
  );
  const [isFocused, setIsFocused] = useState(false);
  const inputRef = useRef<HTMLInputElement | null>(null);
  const [tooltipOpen, setTooltipOpen] = useState(false);
  const shouldFocusOnClose = useRef(false);

  const open = Boolean(anchorEl);

  // Handle focus restoration when Popover closes after date selection
  useEffect(() => {
    if (!open && shouldFocusOnClose.current && inputRef.current) {
      shouldFocusOnClose.current = false;
      // Use requestAnimationFrame to ensure Popover's focus management completes first
      requestAnimationFrame(() => {
        if (inputRef.current) {
          inputRef.current.focus();
        }
      });
    }
  }, [open]);

  const setErrorFormat = useCallback(() => {
    helpers.setTouched(true);
    // Set error asynchronously to ensure it persists after Formik's validation cycle
    setTimeout(() => {
      helpers.setError("Invalid date");
    }, 0);
  }, [helpers]);

  // Extract defaultValue from textFieldProps if provided
  const defaultValue = textFieldProps?.defaultValue;

  // Initialize field value with defaultValue if provided (takes precedence over initialValues)
  useEffect(() => {
    if (defaultValue !== undefined) {
      // defaultValue can be a string (ISO date), empty string, or null
      if (typeof defaultValue === "string" && defaultValue.trim() !== "") {
        // Normalize to UTC midnight to avoid timezone issues
        const parsedDate = parseDateFromISO(defaultValue);
        if (parsedDate) {
          const normalizedISO = dateToISOString(parsedDate);
          helpers.setValue(normalizedISO, false);
        } else {
          helpers.setValue(null, false);
        }
      } else {
        helpers.setValue(null, false);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Only run on mount - defaultValue takes precedence over initialValues

  //Sync input value with field value when field changes externally
  useEffect(() => {
    const valueToUse =
      field.value ?? (typeof defaultValue === "string" ? defaultValue : null);

    if (valueToUse) {
      // Parse date from ISO string (extracts date-only, uses UTC noon to avoid shifts)
      const parsedDate = parseDateFromISO(valueToUse);
      if (parsedDate === null || isNaN(parsedDate.getTime())) {
        setInputValue("Invalid Date");
        setErrorFormat();
        return;
      }
      const formatted = format(parsedDate, "P", {
        locale: detectedLocale,
      });
      setInputValue(formatted);
    } else {
      setInputValue("");
    }
  }, [defaultValue, detectedLocale, field.value, setErrorFormat]);

  // Handle calendar date selection
  const handleDateChange = useCallback(
    (date: Date | null) => {
      // Only close and set value when in day view (user clicked a specific day)
      if (calendarView !== "day") return;

      // Convert to UTC midnight ISO string to avoid timezone shifts
      const dateValue = date ? dateToISOString(date) : null;
      helpers.setValue(dateValue, true);
      helpers.setError(undefined);

      // Update input display
      if (date) {
        setInputValue(format(date, "P", { locale: detectedLocale }));
      } else {
        setInputValue("");
      }

      // Close calendar and return focus
      setAnchorEl(null);
      shouldFocusOnClose.current = true;
    },
    [helpers, detectedLocale, calendarView]
  );

  // Clear date
  const clearDate = useCallback(() => {
    helpers.setValue(null, true);
    helpers.setError(undefined);
    setInputValue("");
    if (inputRef.current) {
      inputRef.current.focus();
    }
  }, [helpers]);

  // Parse shortcut strings like "d", "d1", "m2", "y3"
  const parseShortcut = useCallback((input: string): Date | null => {
    const trimmed = input?.trim().toLowerCase();

    // Match patterns: d, d1, m2, y3, etc.
    const match = trimmed?.match(/^([dmy])(\d*)$/);
    if (!match) return null;

    const [, type, numStr] = match;
    const num = numStr ? parseInt(numStr, 10) : 0;

    if (type === "d") {
      return dayjs().add(num, "day").toDate();
    } else if (type === "m") {
      return dayjs().add(num, "month").toDate();
    } else if (type === "y") {
      return dayjs().add(num, "year").toDate();
    }

    return null;
  }, []);

  // Handle input change
  const handleInputChange = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      const newValue = event.target.value;
      setInputValue(newValue);

      if (meta.error) {
        helpers.setError(undefined);
      }
    },
    [helpers, meta.error]
  );

  const formatDate = useCallback(
    (newDate: Date) => {
      const isoDate = dateToISOString(newDate);
      helpers.setValue(isoDate, true);
      helpers.setError(undefined);
      setInputValue(format(newDate, "P", { locale: detectedLocale }));
    },
    [detectedLocale, helpers]
  );

  // Handle keyboard shortcuts
  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>) => {
      const input = event.currentTarget;
      const currentValue = field.value;

      // Ctrl+Left/Right: Change month
      if (
        event.ctrlKey &&
        (event.key === "ArrowLeft" || event.key === "ArrowRight")
      ) {
        event.preventDefault();
        if (currentValue) {
          const currentDate = parseDateFromISO(currentValue);
          if (currentDate) {
            const newDate =
              event.key === "ArrowLeft"
                ? addMonths(currentDate, -1)
                : addMonths(currentDate, 1);
            formatDate(newDate);
          }
        }
        return;
      }

      // Ctrl+Up/Down: Change year
      if (
        event.ctrlKey &&
        (event.key === "ArrowUp" || event.key === "ArrowDown")
      ) {
        event.preventDefault();
        if (currentValue) {
          const currentDate = parseDateFromISO(currentValue);
          if (currentDate) {
            const newDate =
              event.key === "ArrowUp"
                ? addYears(currentDate, 1)
                : addYears(currentDate, -1);

            formatDate(newDate);
          }
        }
        return;
      }

      // Tab: Process shortcuts
      if (event.key === "Tab") {
        const inputValue = input.value?.trim();
        const shortcutDate = parseShortcut(inputValue);
        if (shortcutDate) {
          event.preventDefault();
          formatDate(shortcutDate);
        }
      }

      // Enter: Process shortcuts
      if (event.key === "Enter") {
        const inputValue = input.value.trim();
        const shortcutDate = parseShortcut(inputValue);
        if (shortcutDate) {
          event.preventDefault();
          formatDate(shortcutDate);
        }
      }
    },
    [field.value, formatDate, parseShortcut]
  );

  const handleFocus = useCallback(() => {
    setIsFocused(true);
    setTooltipOpen(true);
  }, []);

  const handleBlur = useCallback(
    (event: React.FocusEvent<HTMLInputElement>) => {
      setIsFocused(false);
      setTooltipOpen(false);
      helpers.setTouched(true);
      const value = event.target.value.trim();

      if (!value) {
        helpers.setValue(null, true);
        helpers.setError(undefined);
        setInputValue("");
        return;
      }

      // Try shortcut parsing first
      const shortcutDate = parseShortcut(value);
      if (shortcutDate) {
        formatDate(shortcutDate);
        return;
      }

      // Validate numeric date formats before parsing
      if (/^\d{1,2}\/\d{1,2}(\/\d{2,4})?$/.test(value)) {
        const parts = value.split("/");
        const month = parseInt(parts[0]);
        const day = parseInt(parts[1]);

        // Validate month and day ranges
        if (month < 1 || month > 12 || day < 1 || day > 31) {
          setErrorFormat();
          return;
        }
      }

      let parsed: Date | null = null;
      const currentYear = new Date().getFullYear();
      let isValid = false;

      // Handle specific date patterns first to avoid ambiguity
      // Handle formats like "4/5" -> "04/05/2025"
      if (/^\d{1,2}\/\d{1,2}$/.test(value)) {
        const [month, day] = value.split("/");
        parsed = new Date(currentYear, parseInt(month) - 1, parseInt(day));
        isValid = !isNaN(parsed.getTime());
      }
      // Handle formats like "4/5/23" -> "04/05/2023" (2-digit year)
      else if (/^\d{1,2}\/\d{1,2}\/\d{2}$/.test(value)) {
        const [month, day, year] = value.split("/");
        const fullYear = parseInt(year) + 2000;
        parsed = new Date(fullYear, parseInt(month) - 1, parseInt(day));
        isValid = !isNaN(parsed.getTime());
      }
      // Handle formats like "4/5/2025" -> "04/05/2025" (4-digit year)
      else if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(value)) {
        const [month, day, year] = value.split("/");
        parsed = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
        isValid = !isNaN(parsed.getTime());
      }
      // Fall back to locale-specific parsing for other formats
      else {
        // Check if input contains any non-date-like characters (for simple text like "abc")
        if (!/[\d\/\-\s,]+/.test(value)) {
          setErrorFormat();
          return;
        }
        parsed = parse(value, "P", new Date(), { locale: detectedLocale });
        isValid = !isNaN(parsed.getTime());

        // If validation failed during format check, set error
        if (!isValid) {
          setErrorFormat();
          return;
        }
      }

      if (isValid && parsed) {
        // Convert to UTC midnight to avoid timezone shifts
        formatDate(parsed);
      } else {
        // Invalid date, show error and keep the input value
        // Use setTimeout to ensure error is set after Formik's internal validation completes
        helpers.setTouched(true);
        // Set error asynchronously to ensure it persists after Formik's validation cycle
        setTimeout(() => {
          helpers.setError("Invalid date format");
        }, 0);
      }
    },
    [helpers, parseShortcut, formatDate, setErrorFormat, detectedLocale]
  );

  const handleMouseEnter = useCallback(() => {
    setTooltipOpen(true);
  }, []);

  const handleMouseLeave = useCallback(() => {
    if (!isFocused) setTooltipOpen(false);
  }, [isFocused]);

  const errorState = meta.touched && Boolean(meta.error);

  const displayError = useMemo(() => {
    if (meta.touched && meta.error) return meta.error;
    return helperText || "";
  }, [meta.touched, meta.error, helperText]);

  const dateValue = useMemo(() => {
    if (!field.value) return null;
    // Parse date from ISO string (extracts date-only, uses UTC noon to avoid shifts)
    return parseDateFromISO(field.value);
  }, [field.value]);

  // Filter out conflicting props from textFieldProps since we're using Formik (controlled mode)
  // Remove defaultValue and value to avoid conflicts with controlled input
  // defaultValue is extracted above and used to initialize the field value
  const sanitizedTextFieldProps = useMemo(() => {
    if (!textFieldProps) return {};
    const { defaultValue, value, ...rest } = textFieldProps;
    return rest;
  }, [textFieldProps]);

  const tooltipTitle = useMemo(() => {
    const today = new Date();
    const todayFormatted = format(today, "P", { locale: detectedLocale });
    const oneDayMore = format(dayjs().add(1, "day").toDate(), "P", {
      locale: detectedLocale,
    });
    const oneMonthMore = format(addMonths(today, 1), "P", {
      locale: detectedLocale,
    });
    const oneYearMore = format(addYears(today, 1), "P", {
      locale: detectedLocale,
    });
    return (
      <div
        style={{
          whiteSpace: "pre-line",
          fontSize: "12px",
          lineHeight: "1.6",
          width: "300px",
        }}
      >
        {`Ctrl+Up/Down - change year.\n` +
          `Ctrl+Left/Right - change month\n` +
          `d - display current date.  ${todayFormatted}\n` +
          `d1 - Add 1 day to the current date. ${oneDayMore}\n` +
          `m1 - Add 1 month to the current date. ${oneMonthMore}\n` +
          `y1 - Add 1 year to the current date. ${oneYearMore}\n`}
      </div>
    );
  }, [detectedLocale]);

  return (
    <LocalizationProvider
      dateAdapter={AdapterDateFns}
      adapterLocale={detectedLocale}
    >
      <Tooltip
        title={tooltipTitle}
        open={tooltipOpen}
        onClose={() => setTooltipOpen(false)}
        placement="bottom-start"
        arrow={false}
        slotProps={{
          popper: {
            modifiers: [
              {
                name: "offset",
                options: {
                  offset: [0, -8],
                },
              },
            ],
          },
        }}
      >
        <TextField
          {...sanitizedTextFieldProps}
          label={label}
          inputRef={inputRef}
          value={inputValue}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          onFocus={handleFocus}
          onBlur={handleBlur}
          error={errorState}
          helperText={displayError}
          placeholder=""
          sx={{ ...textFieldProps?.sx }}
          size="small"
          slotProps={{
            input: {
              sx: { ...textFieldProps?.sx },
              onMouseEnter: handleMouseEnter,
              onMouseLeave: handleMouseLeave,
              endAdornment: (
                <InputAdornment position="end">
                  {inputValue && isFocused && (
                    <IconButton
                      onMouseDown={(e) => {
                        e.preventDefault();
                        clearDate();
                      }}
                      edge="end"
                      sx={{ mr: 0.5 }}
                      tabIndex={-1}
                    >
                      <CloseIcon size={20} />
                    </IconButton>
                  )}
                  <IconButton
                    onClick={(e) => setAnchorEl(e.currentTarget)}
                    edge="end"
                    tabIndex={-1}
                    sx={{ mr: 0.25 }}
                    disabled={textFieldProps?.disabled}
                    aria-label="Choose Date"
                  >
                    <CalendarIcon size={20} />
                  </IconButton>
                </InputAdornment>
              ),
            },
          }}
        />
      </Tooltip>

      <Popover
        open={open}
        anchorEl={anchorEl}
        onClose={() => setAnchorEl(null)}
        anchorOrigin={{
          vertical: "bottom",
          horizontal: "right",
        }}
        transformOrigin={{
          vertical: "top",
          horizontal: "right",
        }}
      >
        <DateCalendar
          value={dateValue}
          onChange={handleDateChange}
          view={calendarView}
          onViewChange={(newView) => setCalendarView(newView)}
        />
      </Popover>
    </LocalizationProvider>
  );
}

import {
  Formik,
  FormTextField,
  ProgressOrDivider,
  useField,
  useFormikContext,
} from "@textile/biz-components";
import {
