  CollapseIcon,
  DeleteIcon,
  Dialog,
  DialogTitle,
  ExpandIcon,
  SecondaryEditIcon,
  ToolGroup,
  useMessageAnnouncer,
} from "@textile/common";
import {
  Alert,
  Box,
  Button,
  Checkbox,
  DialogActions,
  DialogContent,
  Divider,
  FormControlLabel,
  IconButton,
  Stack,
  SxProps,
  Theme,
  Typography,
  styled,
} from "@textile/mui";
import * as monaco from "monaco-editor";
import {
  FunctionComponent,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import {
  FormulaEditorAddFieldPopover,
  FormulaEditorAddFunctionDialog,
  FormulaEditorAddVariablePopover,
} from "./formula-editor-action-dialog.component";
import {
  DdxField,
  DdxFunction,
  DdxFunctionParameter,
  DdxData,
} from "../monaco-ddx-editor";
import {
  DdxTranslationError,
  ModelExpression,
  useExpressionValidator,
} from "../../hooks/expression-validator.hook";
