          multiline
        ></FormTextField>
        <Stack direction="row">
          <ToolGroup sx={{ alignItems: "flex-start", columnGap: 1 }}>
            <IconButton
              onClick={() => {
                setOpen(true);
              }}
              aria-label="Edit Formula"
            >
              <SecondaryEditIcon size={24} />
            </IconButton>
            <IconButton
              aria-label="Delete Formula"
              onClick={() => {
                helpers.setValue(null);
              }}
            >
              <DeleteIcon size={24} />
            </IconButton>
          </ToolGroup>
        </Stack>

        <FormulaBuilder
          {...props}
          open={open}
          sx={fieldSx}
          setValue={helpers.setValue}
          value={formattedFormula}
          handleOnCloseButtonClick={() => setOpen(false)}
          ddxData={ddxData}
        ></FormulaBuilder>
      </Stack>
    </>
  );
};

export const FormulaBuilder: FunctionComponent<FormulaBuilderProps> = (
  props
) => {
  const [isFullScreen, setIsFullScreen] = useState(false);
  const { fetchHydrateExpression } = useExpressionValidator();
  const FormBase = styled("form")({});
  const {
    open,
    handleOnCloseButtonClick,
    setValue,
    value,
    addField,
    ddxData,
    purpose,
  } = props;
  const [isEditorEnabled, setIsEditorEnabled] = useState<boolean>(false);
  const onDdxToDetailsRef = useRef<(() => void) | null>(null);
  const formikContext = useFormikContext();

  const initialValues = useMemo(
    () => ({
      formula_text_editor: value || "",
    }),
    [value]
  );

  const [isSubmitting, setIsSubmitting] = useState(false);

  const [ddxErrors, setDdxErrors] = useState<
    DdxTranslationError[] | undefined
  >();
  const exprDescription = useRef<string>("");
  const editorVal = useRef<string>("");
  exprDescription.current = value;
  editorVal.current = value;

  const { error } = useMessageAnnouncer();

  const handleSubmit = useCallback(async () => {
    try {
      const currentValue = isEditorEnabled
        ? editorRef.current?.getValue() ?? "" // Get value from editor
        : valuesRef.current?.formula_text_editor ?? ""; // Get value from text field

      exprDescription.current = currentValue ?? exprDescription.current;
      setIsSubmitting(true);
      const modelExpression = await fetchHydrateExpression(
        "FIELD_FORMULA",
        currentValue,
        "value"
      );

      if (modelExpression.ddx_errors.length === 0) {
        setDdxErrors([]);
        if (setValue) {
          await setValue(modelExpression);
          if (formikContext?.setFieldValue)
            formikContext.setFieldValue("formula_text_editor", undefined);
        }
        handleOnCloseButtonClick ? handleOnCloseButtonClick() : null;
      } else {
        setDdxErrors(modelExpression.ddx_errors);
      }
    } catch (err) {
      error("Error: Saving Formula");
    } finally {
      setIsSubmitting(false);
    }
  }, [
    error,
    fetchHydrateExpression,
    handleOnCloseButtonClick,
    setValue,
    formikContext,
    isEditorEnabled,
  ]);

  const isEditorDirty = useRef(false);

  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const handleGetEditorRef = (editor: monaco.editor.IStandaloneCodeEditor) => {
    editorRef.current = editor;
    editorRef?.current?.onDidChangeModelContent(() => {
      isEditorDirty.current = true;
    });
  };

  const getFriendlyDesc = useCallback(() => {
    editorVal.current = editorRef?.current?.getValue() ?? "";
    if (isEditorDirty.current) {
      return editorRef?.current?.getValue() ?? "";
    } else {
      return exprDescription.current ?? "";
    }
  }, []);

  // Text field handlers for inserting at cursor position
  const textFieldRef = useRef<HTMLTextAreaElement | null>(null);
  const setFieldValueRef = useRef<((field: string, value: any) => void) | null>(
    null
  );
  const valuesRef = useRef<any>(null);

  const setCursorPosition = useCallback(
    (currentCursorPos: number, insertedTextLength: number) => {
      setTimeout(() => {
        if (textFieldRef.current) {
          const newCursorPos = currentCursorPos + insertedTextLength;
          textFieldRef.current.setSelectionRange(newCursorPos, newCursorPos);
          textFieldRef.current.focus();
        }
      }, 0);
    },
    []
  );

  const handleTextFieldSelectedFieldsChange = useCallback(
    (selectedRecord: DdxField) => {
      if (
        selectedRecord?.display_name &&
        setFieldValueRef.current &&
        valuesRef.current
      ) {
        const currentValue = valuesRef.current.formula_text_editor || "";
        const textToInsert = `[${selectedRecord.display_name}]`;
        const currentCursorPos =
          textFieldRef.current?.selectionStart || currentValue.length;
        const newValue =
          currentValue.slice(0, currentCursorPos) +
          textToInsert +
          currentValue.slice(currentCursorPos);
        setFieldValueRef.current("formula_text_editor", newValue);

        setCursorPosition(currentCursorPos, textToInsert.length);
      }
    },
    [setCursorPosition]
  );

  const handleTextFieldSelectedFunctionChange = useCallback(
    (selectedRecord: DdxFunction) => {
      if (setFieldValueRef.current && valuesRef.current) {
        const functionParameterList = selectedRecord.parameters?.length
          ? selectedRecord.parameters?.map((param: DdxFunctionParameter) => {
              return param.description;
            })
          : [];

        const functionTemplate =
          selectedRecord.function_name === "CASE ... WHEN" ||
          selectedRecord.function_name === "CASE WHEN ..."
            ? selectedRecord?.description
            : selectedRecord?.function_name +
              "(" +
              functionParameterList.join(" ,") +
              ")";

        if (functionTemplate) {
          const currentValue = valuesRef.current.formula_text_editor || "";
          const currentCursorPos =
            textFieldRef.current?.selectionStart || currentValue.length;
          const newValue =
            currentValue.slice(0, currentCursorPos) +
            functionTemplate +
            currentValue.slice(currentCursorPos);
          setFieldValueRef.current("formula_text_editor", newValue);

          setCursorPosition(currentCursorPos, functionTemplate.length);
        }
      }
    },
    []
  );

  const handleClose = () => {
    handleOnCloseButtonClick?.();
    isEditorDirty.current = false;
    setDdxErrors([]);
    setIsFullScreen(false);
  };

  // state to re-render FormulaEditorAddVariablePopover on submit complete
  const [updateFormulaEditorPopover, setUpdateFormulaEditorPopover] =
    useState<symbol>(Symbol());

  return (
    <Box>
      <Dialog
        open={open}
        fullScreen={isFullScreen}
        PaperProps={{
          sx: !isFullScreen ? getDialogResizePaperPropsSx("xl") : {},
        }}
        draggable={true}
      >
        <Formik
          initialValues={initialValues}
          enableReinitialize={true}
          onSubmit={async () => {
            handleSubmit();
          }}
        >
          {({ handleSubmit, values, setFieldValue }) => {
            // Store Formik functions in refs
            setFieldValueRef.current = setFieldValue;
            valuesRef.current = values;
            return (
              <>
                <FormulaFieldSync value={value} />
                <FormBase onSubmit={handleSubmit}>
                  <DialogTitle>
                    <Stack
                      direction="row"
                      alignItems="center"
                      justifyContent="space-between"
                    >
                      Formula Editor
                      <Stack direction="row">
                        <IconButton
                          sx={(theme) => ({
                            color: theme.palette.primary.contrastText,
                            mr: 1,
                          })}
                          aria-label={
                            isFullScreen
                              ? "Exit full screen"
                              : "Enter full screen"
                          }
                          onClick={() => setIsFullScreen((prev) => !prev)}
                        >
                          {isFullScreen ? (
                            <CollapseIcon size={20} />
                          ) : (
                            <ExpandIcon size={20} />
                          )}
                        </IconButton>
                        <IconButton
                          aria-label="close"
                          onClick={handleClose}
                          sx={(theme) => ({
                            color: theme.palette.primary.contrastText,
                          })}
                        >
                          <CloseIcon size={20} />
                        </IconButton>
                      </Stack>
                    </Stack>
                  </DialogTitle>
                  <ProgressOrDivider isLoading={isSubmitting} />
                  <DialogContent>
                    <ToolGroup
                      sx={{
                        alignItems: "flex-end",
                        justifyContent: "flex-end",
                        gap: 1,
                      }}
                    >
                      <FormControlLabel
                        label={"View Editor"}
                        control={<Checkbox checked={isEditorEnabled} />}
                        onClick={() => {
                          if (isEditorEnabled) {
                            // Switching from editor to text field
                            const currentValue =
                              editorRef.current?.getValue() ?? "";
                            setFieldValue("formula_text_editor", currentValue);
                            setIsEditorEnabled(false);
                          } else {
                            // Switching from text field to editor
                            const textFieldValue =
                              values.formula_text_editor || "";
                            setIsEditorEnabled(true);
                            setTimeout(() => {
                              if (editorRef.current) {
                                editorRef.current.setValue(textFieldValue);
                              }
                            }, 100);
                          }
                        }}
                      />
                      {!isEditorEnabled ? (
                        <>
                          <Divider orientation="vertical" flexItem></Divider>
                          {addField ? (
                            <FormulaEditorAddFieldPopover
                              ddxData={ddxData}
                              handleSelectedFieldChange={
                                handleTextFieldSelectedFieldsChange
                              }
                            ></FormulaEditorAddFieldPopover>
                          ) : (
                            <FormulaEditorAddVariablePopover
                              key={updateFormulaEditorPopover.toString()}
                              updateKey={setUpdateFormulaEditorPopover}
                              ddxData={ddxData}
                              purpose={purpose}
                              handleSelectedFieldChange={
                                handleTextFieldSelectedFieldsChange
                              }
                            ></FormulaEditorAddVariablePopover>
                          )}
                          <FormulaEditorAddFunctionDialog
                            ddxFunctions={ddxData?.ddxFunctions ?? []}
                            handleSelectedFunctionChange={
                              handleTextFieldSelectedFunctionChange
                            }
                          />
                        </>
                      ) : (
                        <Button
                          variant="outlined"
                          onClick={() => onDdxToDetailsRef.current?.()}
                        >
                          Ddx to Details
                        </Button>
                      )}
                    </ToolGroup>
                    <Box sx={topBoxSx}>
                      {isEditorEnabled ? (
                        <DdxEditorDetails
                          ddxProps={ddxData}
                          getFriendlyDescription={getFriendlyDesc}
                          getEditorRef={handleGetEditorRef}
                          errors={ddxErrors}
                          exprDesc={exprDescription}
                          isFormula={true}
                          onDdxToDetailsRef={onDdxToDetailsRef}
                        ></DdxEditorDetails>
                      ) : (
                        <>
                          <FormTextField
                            fieldName={"formula_text_editor"}
                            multiline
                            minRows={15}
                            sx={{ flex: 1 }}
                            inputRef={textFieldRef}
                          ></FormTextField>
                          {ddxErrors && ddxErrors.length > 0 ? (
                            <Alert
                              severity="error"
                              onClose={() => setDdxErrors([])}
                            >
                              {ddxErrors.map((error, index) => (
                                <Typography key={index}>
                                  {error.message}
                                </Typography>
                              ))}
                            </Alert>
                          ) : null}
                        </>
                      )}
                    </Box>
                  </DialogContent>
                  <Divider></Divider>
                  <DialogActions sx={{ gap: 1 }}>
                    <Button variant="outlined" onClick={handleClose}>
                      Cancel
                    </Button>
                    <Button
                      variant="contained"
                      type="submit"
                      sx={{ placeSelf: "end" }}
                      disabled={isSubmitting}
                    >
                      Save
                    </Button>
                  </DialogActions>
                </FormBase>
              </>
            );
          }}
        </Formik>
      </Dialog>
    </Box>
  );
};

const FormulaFieldSync: FunctionComponent<{ value: string }> = ({ value }) => {
  const [, , helpers] = useField("formula_text_editor");

  useEffect(() => {
    helpers.setValue(value || "");
  }, [value, helpers]);

  return null;
};

