import {
  Formik,
  FormTextField,
  ProgressOrDivider,
  useField,
  useFormikContext,
} from "@textile/biz-components";
import {
  CloseIcon,
  CollapseIcon,
  DeleteIcon,
  Dialog,
  DialogTitle,
  ExpandIcon,
  SecondaryEditIcon,
  ToolGroup,
  useMessageAnnouncer,
} from "@textile/common";
import {
  Alert,
  Box,
  Button,
  Checkbox,
  DialogActions,
  DialogContent,
  Divider,
  FormControlLabel,
  IconButton,
  Stack,
  SxProps,
  Theme,
  Typography,
  styled,
} from "@textile/mui";
import * as monaco from "monaco-editor";
import {
  FunctionComponent,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import {
  FormulaEditorAddFieldPopover,
  FormulaEditorAddFunctionDialog,
  FormulaEditorAddVariablePopover,
} from "./formula-editor-action-dialog.component";
import {
  DdxField,
  DdxFunction,
  DdxFunctionParameter,
  DdxData,
} from "../monaco-ddx-editor";
import {
  DdxTranslationError,
  ModelExpression,
  useExpressionValidator,
} from "../../hooks/expression-validator.hook";
import { DdxEditorDetails } from "../monaco-ddx-editor/ddx-editor-details";
import { formatFormula, getDialogResizePaperPropsSx } from "../helpers";

export interface FormFormulaEditorProps<T = unknown> {
  id: string;
  name?: keyof T & string;
  label?: string;
  sx?: SxProps;
  purpose: string;
  purposeModifier?: string;
  addField?: boolean;
  errors: DdxTranslationError[];
  ddxData: DdxData;
  required?: boolean;
}
export interface FormulaBuilderProps {
  value: string;
  sx?: SxProps;
  open: boolean;
  handleOnCloseButtonClick?: () => void;
  setValue?: (
    value: ModelExpression,
    shouldValidate?: boolean | undefined
  ) => void | Promise<unknown>;
  targetKey?: string;
  targetType?: string;

  addField?: boolean;
  ddxData: DdxData;
  purpose?: string;
}
const topBoxSx: SxProps<Theme> = {
  py: 1,
  display: "flex",
  flexDirection: "column",
  minWidth: 1200,
};

export const FormFormulaEditor = <T,>(props: FormFormulaEditorProps<T>) => {
  const { id, name, sx, ddxData, label, required } = props;
  const idField = id ?? name ?? "missing-id";
  const [field, , helpers] = useField(idField);
  const { submitCount } = useFormikContext();
  const formattedFormula = formatFormula(field.value?.friendly_description);
  const displayFormula = formattedFormula?.replace(/\s+/g, " ");

  useEffect(() => {
    if (submitCount > 0) helpers.setTouched(true);
  }, [submitCount]);

  const [open, setOpen] = useState<boolean>(false);
  const fieldSx = useMemo(
    () => ({
      flex: "1 1 0px",
      ...sx,
    }),
    [sx]
  );
  return (
    <>
      <Stack direction="row" gap={1} alignItems="center">
        <FormTextField
          inputProps={{
            readOnly: true,
          }}
          sx={{ display: "flex", flex: "1 1 0" }}
          label={label ?? "Formula"}
          value={displayFormula}
          fieldName={idField}
          required={required ?? false}
          multiline
        ></FormTextField>
        <Stack direction="row">
          <ToolGroup sx={{ alignItems: "flex-start", columnGap: 1 }}>
            <IconButton
              onClick={() => {
                setOpen(true);
              }}
              aria-label="Edit Formula"
            >
              <SecondaryEditIcon size={24} />
            </IconButton>
            <IconButton
              aria-label="Delete Formula"
              onClick={() => {
                helpers.setValue(null);
              }}
            >
              <DeleteIcon size={24} />
            </IconButton>
          </ToolGroup>
        </Stack>

        <FormulaBuilder
          {...props}
          open={open}
          sx={fieldSx}
          setValue={helpers.setValue}
          value={formattedFormula}
          handleOnCloseButtonClick={() => setOpen(false)}
          ddxData={ddxData}
        ></FormulaBuilder>
      </Stack>
    </>
  );
};

export const FormulaBuilder: FunctionComponent<FormulaBuilderProps> = (
  props
) => {
  const [isFullScreen, setIsFullScreen] = useState(false);
  const { fetchHydrateExpression } = useExpressionValidator();
  const FormBase = styled("form")({});
  const {
    open,
    handleOnCloseButtonClick,
    setValue,
    value,
    addField,
    ddxData,
    purpose,
  } = props;
  const [isEditorEnabled, setIsEditorEnabled] = useState<boolean>(false);
  const onDdxToDetailsRef = useRef<(() => void) | null>(null);
  const formikContext = useFormikContext();

  const initialValues = useMemo(
    () => ({
      formula_text_editor: value || "",
    }),
    [value]
  );

  const [isSubmitting, setIsSubmitting] = useState(false);

  const [ddxErrors, setDdxErrors] = useState<
    DdxTranslationError[] | undefined
  >();
  const exprDescription = useRef<string>("");
  const editorVal = useRef<string>("");
  exprDescription.current = value;
  editorVal.current = value;

  const { error } = useMessageAnnouncer();

  const handleSubmit = useCallback(async () => {
    try {
      const currentValue = isEditorEnabled
        ? editorRef.current?.getValue() ?? "" // Get value from editor
        : valuesRef.current?.formula_text_editor ?? ""; // Get value from text field

      exprDescription.current = currentValue ?? exprDescription.current;
      setIsSubmitting(true);
      const modelExpression = await fetchHydrateExpression(
        "FIELD_FORMULA",
        currentValue,
        "value"
      );

      if (modelExpression.ddx_errors.length === 0) {
        setDdxErrors([]);
        if (setValue) {
          await setValue(modelExpression);
          if (formikContext?.setFieldValue)
            formikContext.setFieldValue("formula_text_editor", undefined);
        }
        handleOnCloseButtonClick ? handleOnCloseButtonClick() : null;
      } else {
        setDdxErrors(modelExpression.ddx_errors);
      }
    } catch (err) {
      error("Error: Saving Formula");
    } finally {
      setIsSubmitting(false);
    }
  }, [
    error,
    fetchHydrateExpression,
    handleOnCloseButtonClick,
    setValue,
    formikContext,
    isEditorEnabled,
  ]);

  const isEditorDirty = useRef(false);

  const editorRef = useRef<monaco.editor.IStandaloneCodeEditor | undefined>();
  const handleGetEditorRef = (editor: monaco.editor.IStandaloneCodeEditor) => {
    editorRef.current = editor;
    editorRef?.current?.onDidChangeModelContent(() => {
      isEditorDirty.current = true;
    });
  };

  const getFriendlyDesc = useCallback(() => {
    editorVal.current = editorRef?.current?.getValue() ?? "";
