import { useEffect, useMemo, useState } from "react";
import { useField } from "@textile/biz-components";
import {
  Box,
  IconButton,
  Menu,
  MenuItem,
  Stack,
  Typography,
  useTheme,
} from "@textile/mui";
import {
  AddIcon,
  DeleteIcon,
  SecondaryEditIcon,
  ToolGroup,
} from "@textile/common";
import {
  ddxFormatter,
  DdxTranslationError,
  isPassThroughCode,
  modelExpressionToExpressions,
} from "../../solvasam-bizcomponents";
import {
  Expression,
  ExpressionBuilder,
  ExpressionBuilderProps,
} from "../expression-builder/expression-builder.component";
import { RuleDisplayComponent } from "../expression-builder/rule-display.component";

export interface FormExpressionBuilderProps<T = unknown>
  extends Omit<ExpressionBuilderProps, "expression" | "onChange" | "open"> {
  id?: (keyof T & string) | string;
  name?: keyof T & string;
  label?: string;
  required?: boolean;
}

export const FormExpressionBuilder = <T,>(
  props: FormExpressionBuilderProps<T> & {
    ddxTranslationErrors?: DdxTranslationError[];
  }
) => {
  const { id, name, label, required, sx, ddxProps, ...expressionBuilderProps } =
    props;
  const idField = id ?? name ?? "missing-id";
  const [field, , helpers] = useField(idField);
  const [addExpression, setAddExpression] = useState<Expression[]>([]);
  const [open, setOpen] = useState<boolean>(false);
  const fieldSx = useMemo(
    () => ({
      flex: "1 1 0px",
      ...sx,
    }),
    [sx]
  );
  const { ddxFields: ddxField, ddxFunctions: ddxFunctions } = ddxProps;
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
  const openMenu = Boolean(anchorEl);
  const [isComplexRule, setIsComplexRule] = useState<boolean>(false);
  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleClose = () => {
    setAnchorEl(null);
  };

  const expressions: Expression[] = useMemo(
    () =>
      ddxField.length > 0
        ? modelExpressionToExpressions(field.value, ddxField, ddxFunctions) ??
          []
        : [],
    [ddxField, field.value, ddxFunctions]
  );

  useEffect(() => {
    if (field.value && isPassThroughCode(field.value.ddx)) {
      setIsComplexRule(true);
    } else {
      setIsComplexRule(false);
    }
  }, [field.value]);
  const theme = useTheme();

  return (
    <Stack direction="row" spacing={1}>
      <Box sx={{ flexGrow: 1 }}>
        <Stack direction="row" spacing={1} alignItems="center">
          <fieldset
            style={{
              overflow: "auto",
              backgroundColor: theme.palette.background.paper,
              border: `1px groove ${theme.palette.divider}`,
              borderRadius: "4px",
              flex: "1 1 0px",
              fontFamily: theme.typography.fontFamily,
            }}
          >
            <legend>
              <Typography
                variant="caption"
                sx={{
                  color:
                    required && !field.value
                      ? theme.palette.error.dark
                      : theme.palette.text.secondary,
                }}
              >
                {label ?? "Applicability Expression"}
                {required && " *"}
              </Typography>
            </legend>

            <RuleDisplayComponent
              value={ddxFormatter.format(field.value?.friendly_description)}
              ddxData={ddxProps}
            ></RuleDisplayComponent>
          </fieldset>
          {required && !field.value && (
            <Typography
              variant="caption"
              sx={{
                color: theme.palette.error.dark,
              }}
            >
              {`${label} ?? "Applicability Expression" is required `}
            </Typography>
          )}
          <Box sx={{ flexShrink: 0, position: "relative" }}>
            <ToolGroup
              sx={{
                alignItems: "flex-start",
                columnGap: 1,
                visibility: field.value ? "visible" : "hidden",
              }}
            >
              <IconButton
                aria-label="Edit Expression"
                onClick={() => {
                  setOpen(true);
                }}
              >
                <SecondaryEditIcon size={24} />
              </IconButton>
              <IconButton
                aria-label="Delete Expression"
                onClick={() => {
                  helpers.setValue(null);
                }}
              >
                <DeleteIcon size={24} />
              </IconButton>
            </ToolGroup>
            <Box
              sx={{
                visibility: field.value ? "hidden" : "visible",
                position: "absolute",
                top: 0,
                left: 0,
              }}
            >
              <IconButton
                id="add-button"
                aria-label="Add Expression"
                aria-controls={open ? "basic-menu" : undefined}
                aria-haspopup="true"
                aria-expanded={open ? "true" : undefined}
                onClick={handleClick}
              >
                <AddIcon size={24} />
              </IconButton>
              <Menu
                id="add-expression-menu"
                anchorEl={anchorEl}
                open={openMenu}
                onClose={handleClose}
                MenuListProps={{
                  "aria-labelledby": "basic-button",
                }}
              >
                <MenuItem
                  onClick={() => {
                    handleClose();
                    setAddExpression([
                      {
                        isRule: false,
                        line_number: 0,
                        close_parenthesis: 0,
                        logical_operator: "",
                        comparison_operator: "",
                        field: null,
                        logical_expression: "",
                        open_parenthesis: 0,
                        value: "",
                        value2: "",
                      },
                    ]);
                    setOpen(true);
                  }}
                >
                  <Typography variant="subtitle2">
                    Add Simple Expression
                  </Typography>
                </MenuItem>

                <MenuItem
                  onClick={() => {
                    handleClose();
                    setAddExpression([
                      {
                        isRule: true,
                        line_number: 0,
                        close_parenthesis: 0,
                        logical_operator: "",
                        comparison_operator: "",
                        field: null,
                        logical_expression: "Rule",
                        open_parenthesis: 0,
                        value: "",
                        value2: "",
                      },
                    ]);
                    setOpen(true);
                  }}
                >
                  <Typography variant="subtitle2">Add Rule</Typography>
                </MenuItem>
              </Menu>
            </Box>
          </Box>
        </Stack>
      </Box>
      <ExpressionBuilder
        {...expressionBuilderProps}
        expression={field.value == null ? addExpression : expressions}
        open={open}
        sx={fieldSx}
        setValue={(modelExpression) => {
          helpers.setValue(modelExpression);
        }}
        ddxProps={ddxProps}
        handleOnCloseButtonClick={() => setOpen(false)}
        isComplexRule={isComplexRule}
      ></ExpressionBuilder>
    </Stack>
  );
};

