import { FormCheckbox, FormTextField } from "@textile/biz-components";
import { Box, Stack, IconButton, FormControl } from "@textile/mui";
import { FunctionComponent, useCallback, useRef } from "react";
import {
  gridTemplateColumns,
  useExpressionBuilderContext,
} from "./expression-builder.component";
import { DragIcon } from "@textile/common";

interface DraggableExpressionProps {
  index: number;
