              }
              InputProps={{
                inputProps: {
                  min: 1,
                  max: expressions.length,
                  "aria-label": `order_${index}`,
                },
              }}
            ></FormTextField>
          </Stack>
          {children}
        </Stack>
      </FormControl>
    </Box>
  );
};

const updateLogicalOperatorsForReordering = (
  values: { [key: string]: string },
  index: number,
  newIndex: number
): { [key: string]: string } => {
  const updatedFormikValues = { ...values };

  const first = values["logical_operator_0"];
  const current = values[`logical_operator_${index}`];
  const next = values[`logical_operator_${index + 1}`];

  // Handle cases where the expression is either moving from or to the first position
  if (index === 0 || newIndex === 0) {
    // Case 1: Moving the first expression to a later position
    if (index === 0) {
      if (current === "NOT" && ["AND NOT", "AND"].includes(next)) {
        updatedFormikValues[`logical_operator_0`] = "AND NOT";
      } else if (current === "NOT" && ["OR NOT", "OR"].includes(next)) {
        updatedFormikValues[`logical_operator_0`] = "OR NOT";
      } else if (current !== "NOT" && ["OR NOT", "OR"].includes(next)) {
        updatedFormikValues[`logical_operator_0`] = "OR";
      } else if (current !== "NOT" && ["AND NOT", "AND"].includes(next)) {
        updatedFormikValues[`logical_operator_0`] = "AND";
      }

      updatedFormikValues[`logical_operator_${index + 1}`] = [
        "AND NOT",
        "OR NOT",
      ].includes(next)
        ? "NOT"
        : "";
    }

    // Case 2: Moving an expression from a later position to the first
    if (newIndex === 0) {
      if (first === "NOT" && ["AND NOT", "AND"].includes(current)) {
        updatedFormikValues[`logical_operator_0`] = "AND NOT";
      } else if (first === "NOT" && ["OR NOT", "OR"].includes(current)) {
        updatedFormikValues[`logical_operator_0`] = "OR NOT";
      } else if (first !== "NOT" && ["OR NOT", "OR"].includes(current)) {
        updatedFormikValues[`logical_operator_0`] = "OR";
      } else if (first !== "NOT" && ["AND NOT", "AND"].includes(current)) {
        updatedFormikValues[`logical_operator_0`] = "AND";
      }

      updatedFormikValues[`logical_operator_${index}`] = [
        "AND NOT",
        "OR NOT",
      ].includes(current)
        ? "NOT"
        : "";
    }
  }

  return updatedFormikValues;
};

