        const [month, day] = value.split("/");
        parsed = new Date(currentYear, parseInt(month) - 1, parseInt(day));
        isValid = !isNaN(parsed.getTime());
      }
      // Handle formats like "4/5/23" -> "04/05/2023" (2-digit year)
      else if (/^\d{1,2}\/\d{1,2}\/\d{2}$/.test(value)) {
        const [month, day, year] = value.split("/");
        const fullYear = parseInt(year) + 2000;
        parsed = new Date(fullYear, parseInt(month) - 1, parseInt(day));
        isValid = !isNaN(parsed.getTime());
      }
      // Handle formats like "4/5/2025" -> "04/05/2025" (4-digit year)
      else if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(value)) {
        const [month, day, year] = value.split("/");
        parsed = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
        isValid = !isNaN(parsed.getTime());
      }
      // Fall back to locale-specific parsing for other formats
      else {
        // Check if input contains any non-date-like characters (for simple text like "abc")
        if (!/[\d\/\-\s,]+/.test(value)) {
          setErrorFormat(value);
          return;
        }
        parsed = parse(value, "P", new Date(), { locale: detectedLocale });
        isValid = !isNaN(parsed.getTime());

        // If validation failed during format check, set error
        if (!isValid) {
          setErrorFormat(value);
          return;
        }
      }

      if (isValid && parsed) {
        // Convert to UTC midnight to avoid timezone shifts
        formatDate(parsed);
      } else {
        // Invalid date - store raw input so consumers can detect the invalid value
        helpers.setValue(value, false);
        helpers.setTouched(true);
        // Set error asynchronously to ensure it persists after Formik's validation cycle
        setTimeout(() => {
          helpers.setError("Invalid date format");
        }, 0);
      }
    },
    [helpers, parseShortcut, formatDate, setErrorFormat, detectedLocale]
  );

  const handleMouseEnter = useCallback(() => {
    setTooltipOpen(true);
  }, []);

  const handleMouseLeave = useCallback(() => {
    if (!isFocused) setTooltipOpen(false);
  }, [isFocused]);

  const errorState = meta.touched && Boolean(meta.error);

  const displayError = useMemo(() => {
    if (meta.touched && meta.error) return meta.error;
    return helperText || "";
  }, [meta.touched, meta.error, helperText]);

  const dateValue = useMemo(() => {
    if (!field.value) return null;
    // Parse date from ISO string (extracts date-only, uses UTC noon to avoid shifts)
    return parseDateFromISO(field.value);
  }, [field.value]);

  // Filter out conflicting props from textFieldProps since we're using Formik (controlled mode)
  // Remove defaultValue and value to avoid conflicts with controlled input
  // defaultValue is extracted above and used to initialize the field value
  const sanitizedTextFieldProps = useMemo(() => {
    if (!textFieldProps) return {};
    const { defaultValue, value, ...rest } = textFieldProps;
    return rest;
  }, [textFieldProps]);

  const tooltipTitle = useMemo(() => {
    const today = new Date();
    const todayFormatted = format(today, "P", { locale: detectedLocale });
    const oneDayMore = format(dayjs().add(1, "day").toDate(), "P", {
      locale: detectedLocale,
    });
    const oneMonthMore = format(addMonths(today, 1), "P", {
      locale: detectedLocale,
    });
    const oneYearMore = format(addYears(today, 1), "P", {
      locale: detectedLocale,
    });
    return (
      <div
        style={{
          whiteSpace: "pre-line",
          fontSize: "12px",
          lineHeight: "1.6",
          width: "300px",
        }}
      >
        {`Ctrl+Up/Down - change year.\n` +
          `Ctrl+Left/Right - change month\n` +
          `d - display current date.  ${todayFormatted}\n` +
          `d1 - Add 1 day to the current date. ${oneDayMore}\n` +
          `m1 - Add 1 month to the current date. ${oneMonthMore}\n` +
          `y1 - Add 1 year to the current date. ${oneYearMore}\n`}
      </div>
    );
  }, [detectedLocale]);

  return (
    <LocalizationProvider
      dateAdapter={AdapterDateFns}
      adapterLocale={detectedLocale}
    >
      <Tooltip
        title={tooltipTitle}
        open={tooltipOpen}
        onClose={() => setTooltipOpen(false)}
        placement="bottom-start"
        arrow={false}
        slotProps={{
          popper: {
            modifiers: [
              {
                name: "offset",
                options: {
                  offset: [0, -8],
                },
              },
            ],
          },
        }}
      >
        <TextField
          {...sanitizedTextFieldProps}
          label={label}
          inputRef={inputRef}
          value={inputValue}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          onFocus={handleFocus}
          onBlur={handleBlur}
          error={errorState}
          helperText={displayError}
          placeholder=""
          sx={{ ...textFieldProps?.sx }}
          size="small"
          slotProps={{
            input: {
              sx: { ...textFieldProps?.sx },
              onMouseEnter: handleMouseEnter,
              onMouseLeave: handleMouseLeave,
              endAdornment: (
                <InputAdornment position="end">
                  {inputValue && isFocused && (
                    <IconButton
                      onMouseDown={(e) => {
                        e.preventDefault();
                        clearDate();
                      }}
                      edge="end"
                      sx={{ mr: 0.5 }}
                      tabIndex={-1}
                    >
                      <CloseIcon size={20} />
                    </IconButton>
                  )}
                  <IconButton
                    onClick={(e) => setAnchorEl(e.currentTarget)}
                    edge="end"
                    tabIndex={-1}
                    sx={{ mr: 0.25 }}
                    disabled={textFieldProps?.disabled}
                    aria-label="Choose Date"
                  >
                    <CalendarIcon size={20} />
                  </IconButton>
                </InputAdornment>
              ),
            },
          }}
        />
      </Tooltip>

      <Popover
        open={open}
        anchorEl={anchorEl}
        onClose={() => setAnchorEl(null)}
        anchorOrigin={{
          vertical: "bottom",
          horizontal: "right",
        }}
        transformOrigin={{
          vertical: "top",
          horizontal: "right",
        }}
      >
        <DateCalendar
          value={dateValue}
          onChange={handleDateChange}
          view={calendarView}
          onViewChange={(newView) => setCalendarView(newView)}
        />
      </Popover>
    </LocalizationProvider>
  );
}

