import {
  useEffect,
  useRef,
  FunctionComponent,
  useState,
  useCallback,
} from "react";
import {
  Screen,
  ScreenHeader,
  useAxiosFactory,
  useStaticAppContext,
} from "@textile/common";
import {
  Box,
  SxProps,
  Collapse,
  IconButton,
  Skeleton,
  Typography,
  useTheme,
} from "@textile/mui";
import * as iframeUtils from "./iframe-utils";
import { useSelectedPortfolioId } from "../../hooks/selected-portfolio-id.hook";
import ExpandMore from "@mui/icons-material/ExpandMore";

const screenSx: SxProps = { display: "flex", flexDirection: "column" };
const hiddenBreadcrumbSx: SxProps = {
  "& .MuiBreadcrumbs-ol": { display: "none" },
};

declare const __IFRAME_DEBUG__: boolean;

const showDebugPanel =
  typeof __IFRAME_DEBUG__ !== "undefined" && __IFRAME_DEBUG__;

const ClassicPageSkeleton: FunctionComponent<{ url?: string | null }> = ({
  url,
}) => {
  const theme = useTheme();
  return (
    <Box
      sx={{
        flex: 1,
        display: "flex",
        flexDirection: "column",
        p: 2,
        gap: 1.5,
        bgcolor: theme.palette.background.default,
      }}
    >
      {/* Toolbar skeleton */}
      <Box display="flex" gap={1} alignItems="center">
        <Skeleton variant="rounded" width={90} height={32} />
        <Skeleton variant="rounded" width={90} height={32} />
        <Skeleton variant="rounded" width={90} height={32} />
        <Box flex={1} />
        <Skeleton variant="rounded" width={200} height={32} />
      </Box>
      {/* Grid header skeleton */}
      <Box display="flex" gap={0.5}>
        {[120, 180, 140, 160, 200, 120].map((w, i) => (
          <Skeleton key={i} variant="rounded" width={w} height={36} />
        ))}
      </Box>
      {/* Grid rows skeleton */}
      {Array.from({ length: 8 }).map((_, i) => (
        <Skeleton
          key={i}
          variant="rounded"
