type IFrameContainerProps = {
  targetClassicUrl: string;
  targetReactUrl: string;
  navigationId: string;
  detailsNavigationId?: string;
  interceptedFunctions?: iframeUtils.InterceptEntry[];
};

export const IFrameContainer: FunctionComponent<IFrameContainerProps> = ({
  targetClassicUrl,
  navigationId,
  interceptedFunctions,
}) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const axiosFactory = useAxiosFactory();
  const [selectedPortfolioId] = useSelectedPortfolioId();
  const [hashKey, setHashKey] = useState(0);
  const hash = window.location.hash;
  const query = hash.includes("?") ? hash.split("?")[1] : "";
  const searchParams = new URLSearchParams(query);
  const targetClassicUrlOverride = searchParams.get("targetClassicUrlOverride");
  const targetClassicUrlWithOverride = iframeUtils.resolveEffectiveUrl(
    targetClassicUrlOverride,
    targetClassicUrl
  );
  const [targetClassicUrlWithParams, setTargetClassicUrlWithParams] = useState<
    string | null
  >(null);

  const [contextIsSynced, setContextIsSynced] = useState(false);
  const [debugExpanded, setDebugExpanded] = useState(false);
  const { sharedAppContextManager, textileProps } = useStaticAppContext();
  const contextValues: Record<string, string | null> = {};
  for (const key of Array.from(sharedAppContextManager.descriptors.keys())) {
    const { state } = sharedAppContextManager.useContext<string | null>(key);
    contextValues[key] = state;
  }

  const [iframeLoaded, setIframeLoaded] = useState(false);

  const syncAccessTokenCookie = useCallback(() => {
    const token = textileProps?.keycloak?.token;
    if (token) {
      document.cookie = `FABRIC_ACCESS_TOKEN=${token}; path=/; Secure; SameSite=Strict`;
    }
  }, [textileProps?.keycloak?.token]);

  const reloadIframe = async () => {
    syncAccessTokenCookie();
    setIframeLoaded(false);
    await iframeUtils.setIframeContents(
      iframeRef,
      targetClassicUrl,
      targetClassicUrlOverride,
      axiosFactory.createAxiosInstance,
      contextValues,
      selectedPortfolioId,
      interceptedFunctions,
      setTargetClassicUrlWithParams
    );
  };

  const onIframeLoad = () => {
    setIframeLoaded(true);
  };

  const previousDependenciesRef = useRef<{
    targetClassicUrlWithOverride: string | null;
    selectedPortfolioId: string | null;
    hashKey: number;
  }>();

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const iFrameContext = async (data: any) => {
    await iframeUtils.processIFrameMessage(
      iframeRef,
      axiosFactory.createAxiosInstance,
      contextValues,
      targetClassicUrl,
      selectedPortfolioId,
      interceptedFunctions,
      data
    );
  };

  const logEffects = () => {
    const previousDependencies = previousDependenciesRef.current;

    const currentDependencies = {
      targetClassicUrlWithOverride,
      selectedPortfolioId,
      hashKey,
    };

    iframeUtils.logObjectDifferences(
      previousDependencies,
      currentDependencies,
      "🔁 iframe-container.component: useEffect fired due to"
    );
    previousDependenciesRef.current = currentDependencies;
  };

  useEffect(() => {
    return iframeUtils.listenForIFrameMessage(iFrameContext);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const onHashChange = () => setHashKey((prev) => (prev === 0 ? 1 : 0));
    window.addEventListener("hashchange", onHashChange);
    return () => window.removeEventListener("hashchange", onHashChange);
  }, []);

  useEffect(() => {
    const synced = iframeUtils.isContextSynced(contextValues, hash);
    setContextIsSynced(synced);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [contextValues, hashKey]);

  useEffect(() => {
    logEffects();

    if (!targetClassicUrlWithOverride) return;
    if (!contextIsSynced) return;

    (async () => {
      await reloadIframe();
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [targetClassicUrlWithOverride, selectedPortfolioId, contextIsSynced]);

  return (
    <Screen
      sx={{ ...screenSx, ...hiddenBreadcrumbSx }}
      navigationId={navigationId}
    >
      <ScreenHeader />
      {!iframeLoaded && (
        <ClassicPageSkeleton url={targetClassicUrlWithParams} />
      )}
      <iframe
        ref={iframeRef}
        title="Classic Application Frame"
        width="100%"
        height="100%"
        style={{
          border: "none",
          display: iframeLoaded ? "block" : "none",
        }}
        onLoad={onIframeLoad}
      />
      {showDebugPanel && (
        <Box bgcolor="#f9f9f9" borderBottom="1px solid #ccc">
          <Box display="flex" alignItems="center" px={2} py={1}>
            <IconButton
              size="small"
              onClick={() => setDebugExpanded(!debugExpanded)}
              sx={{
                transform: debugExpanded ? "rotate(180deg)" : "rotate(0deg)",
                transition: "0.3s",
              }}
            >
              <ExpandMore />
            </IconButton>
            <Box ml={1} fontSize="14px" fontWeight="bold">
              Debug Info
            </Box>
          </Box>
          <Collapse in={debugExpanded}>
            <Box px={2} pb={2} fontSize="14px">
              <div>
                <strong>Navigation ID:</strong> {navigationId}
              </div>
              <div>
                <strong>Classic URl from Routes.tsx:</strong> {targetClassicUrl}
              </div>
              <div>
                <strong>Classic URL With Override:</strong>{" "}
                {targetClassicUrlWithOverride}
              </div>
              {targetClassicUrlWithParams && (
                <div>
                  <strong>Classic URL Processed:</strong>{" "}
                  {targetClassicUrlWithParams}
                </div>
              )}
            </Box>
          </Collapse>
        </Box>
      )}
    </Screen>
  );
};

