/* eslint-disable @typescript-eslint/no-explicit-any */
import { contextParamMap } from "./url-context-sync.component";

type NavigationItem = {
  id: string;
  path: string;
  items?: NavigationItem[];
};

export type InterceptEntry = {
  functionName: string;
  targetReactUrl: string;
};

export async function loadHtmlIntoIframe(
  iframeRef: React.RefObject<HTMLIFrameElement>,
  axios: any,
  contextValues: Record<string, string | null>,
  targetClassicUrl: string,
  selectedPortfolioId: string | null,
  interceptedFunctions?: InterceptEntry[]
): Promise<{ targetClassicUrlWithParams: string } | void> {
  try {
    const iframe = iframeRef.current;

    if (iframe) {
      const targetClassicUrlBase = await getTargetClassicUrlBase(axios);
      const targetClassicUrlWithParams = appendContextParamsToUrl(
        targetClassicUrlBase + targetClassicUrl,
        contextValues
      );

      iframe.addEventListener(
        "load",
        () => {
          setupIframeClickHandling(
            iframeRef,
            axios,
            contextValues,
            targetClassicUrl,
            selectedPortfolioId,
            interceptedFunctions
          );
        },
        { once: true }
      );

      iframe.src = targetClassicUrlWithParams;

      return { targetClassicUrlWithParams };
    }
  } catch (err) {
    console.error("Failed to load iframe HTML:", err);
  }
}

export function listenForIFrameMessage(
  onReturnCallback?: (data: any) => void
): () => void {
  const handler = (e: MessageEvent) => {
    if (e.data?.type === "IFRAME_EVENT") {
      onReturnCallback?.(e.data);
    }
  };

  // #cycode_sast_ignore_here
  window.addEventListener("message", handler);

  return () => {
    window.removeEventListener("message", handler);
  };
}

export function processIFrameMessage(
  iframeRef: React.RefObject<HTMLIFrameElement>,
  axios: any,
  contextValues: Record<string, string | null>,
  targetClassicUrl: string,
  selectedPortfolioId: string | null,
  interceptedFunctions?: InterceptEntry[],
  data?: any
): void {
  // eslint-disable-next-line no-console
  console.log("🔁 iframe event " + data?.payload.type);
  if (data?.payload.type === "IFRAME_PAGE_LOADED") {
    setupIframeClickHandling(
      iframeRef,
      axios,
      contextValues,
      targetClassicUrl,
      selectedPortfolioId,
      interceptedFunctions
    );
  }
}

export function setupIframeClickHandling(
  iframeRef: React.RefObject<HTMLIFrameElement>,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  axios: any,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  contextValues: Record<string, string | null>,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  targetClassicUrl: string,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  selectedPortfolioId: string | null,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  interceptedFunctions?: InterceptEntry[]
): void {
  try {
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const iframeDoc =
      iframeRef.current?.contentDocument ||
      iframeRef.current?.contentWindow?.document;
  } catch (err) {
    console.warn(
      "Cannot access iframe content due to cross-origin restrictions:",
      err
    );
  }
}

function parseFunctionCall(
  raw: string
): { fnName: string; args: string[] } | null {
  const fnMatch = raw.match(/^([a-zA-Z_][a-zA-Z0-9_]*)\((.*)??\)$/);

  if (!fnMatch) return null;

  const fnName = fnMatch[1];
  const args = fnMatch[2]
    .split(",")
    .map((a) => a.trim().replace(/^["']|["']$/g, ""));

  return { fnName, args };
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars
async function handleFunctionCall(
  iframeRef: React.RefObject<HTMLIFrameElement>,
  axios: any,
  contextValues: Record<string, string | null>,
  raw: string,
  targetClassicUrl: string,
  selectedPortfolioId: string | null,
  interceptedFunctions?: InterceptEntry[],
  uiService?: string
): Promise<boolean> {
  const parsed = parseFunctionCall(raw);
  if (!parsed) return false;
  let { fnName, args } = parsed;

  const fnNameOrig = fnName;
  if (fnName.toLowerCase().startsWith("linkrec")) {
    fnName = "linkrec_all";
    args = [...args, targetClassicUrl];
  }

  const match = interceptedFunctions?.find(
    (entry) => entry.functionName.toLowerCase() === fnName.toLowerCase()
  );

  if (!match?.functionName) {
    return false;
  }

  const iframeWindow = iframeRef.current?.contentWindow;
  if (!iframeWindow) return false;

  const fn = iframeWindow[fnNameOrig as keyof typeof iframeWindow];
  if (typeof fn !== "function") return false;

  const targetClassicUrlFinal = fn(...args);
  const encodedArgs = encodeURIComponent(args.join(","));

  let targetReactUrlFinal = match.targetReactUrl;

  if (targetClassicUrlFinal.returnSource == "OpenWizardWindow") {
    const targetURL = decodeURIComponent(targetClassicUrlFinal.targetURL);
    const [baseUrl, queryString = ""] = targetURL.split("?");

    const urlParams1 = new URLSearchParams(queryString);
    const urlParams2 = new URLSearchParams(
      targetClassicUrlFinal.targetParameters
    );

    const mergedParams = new URLSearchParams();
    urlParams1.forEach((value, key) => mergedParams.set(key, value));
    urlParams2.forEach((value, key) => mergedParams.set(key, value));

    const targetClassicUrlBase = await getTargetClassicUrlBase(axios);

    const targetClassicUrlWithParams = appendContextParamsToUrl(
      `${targetClassicUrlBase}${baseUrl}?${mergedParams.toString()}`,
      contextValues
    );

    window.modalWindowOnClose = targetClassicUrlFinal.onWindowClose;
    window.modalWindowOnLoad = targetClassicUrlFinal.onWindowLoad;
    window.modalWindowSuccessURL = targetClassicUrlFinal.successURL;
    window.modalWindowSuccessParameters =
      targetClassicUrlFinal.successParameters;
    window.modalWindowReturnValue = null;
    window.modalWindowName = targetClassicUrlFinal.windowName;

    const width = Math.max(500, Math.min(1200, window.screen.availWidth * 0.9));
    const height = Math.max(
      500,
      Math.min(800, window.screen.availHeight * 0.9)
    );

    const left = (window.screen.availWidth - width) / 2;
    const top = (window.screen.availHeight - height) / 2;

    const windowProperties =
      targetClassicUrlFinal.windowsProperties ||
      `width=${width},height=${height},left=${left},top=${top},resizable=yes,scrollbars=yes`;

    window.open(targetClassicUrlWithParams, "_blank", windowProperties);

    return true;
  } else if (fnName == "linkrec_all") {
    const decodedFinalUrl = decodeURIComponent(targetClassicUrlFinal);
    const queryString = decodedFinalUrl.includes("?")
      ? decodedFinalUrl.split("?")[1]
      : "";
    const urlParams = new URLSearchParams(queryString);

    targetReactUrlFinal = match.targetReactUrl.replace(
      /\$query\[(.+?)\]/g,
      (_, key) => {
        return urlParams.get(key) ?? "";
      }
    );
  } else {
    targetReactUrlFinal = match.targetReactUrl.replace(
      /\$args\[(\d+)\]/g,
      (_, index) => {
        return args[Number(index)] ?? "";
      }
    );
  }

  const svc = uiService ?? "";
  const newHash = `#/${svc}${targetReactUrlFinal}?function=${fnName}&args=${encodedArgs}&targetClassicUrlOverride=${encodeURIComponent(
    targetClassicUrlFinal
  )}`;

  window.location.hash = newHash;
  return true;
}

export async function handleModalEditPage(
  iframeRef: React.RefObject<HTMLIFrameElement>,
  axios: any,
  contextValues: Record<string, string | null>,
  encodedUrl: string,
  targetClassicUrl: string,
  selectedPortfolioId: string | null,
  interceptedFunctions?: InterceptEntry[]
): Promise<boolean> {
  try {
    const targetClassicUrlDecoded = decodeURIComponent(encodedUrl);
    let targetClassicUrlFinal = targetClassicUrlDecoded;

    if (!targetClassicUrlDecoded.startsWith("/")) {
      const basePath = targetClassicUrl.substring(
        0,
        targetClassicUrl.lastIndexOf("/") + 1
      );
      targetClassicUrlFinal = basePath + targetClassicUrlDecoded;
    }

    await loadHtmlIntoIframe(
      iframeRef,
      axios,
      contextValues,
      targetClassicUrlFinal,
      selectedPortfolioId,
      interceptedFunctions
    );

    return true;
  } catch (err) {
    console.error("Modal request failed:", err);
    return false;
  }
}

function appendContextParamsToUrl(
  targetClassicUrl: string,
  context: Record<string, string | null>
): string {
  const [base, query = ""] = targetClassicUrl.split("?");
  const params = new URLSearchParams(query);

  const replacements: Record<string, string> = {
    Portfolio: "parm",
  };

  for (const [key, value] of Object.entries(context)) {
    if (!value) continue;

    const match = key.match(/^app\.selected(.*)/);
    if (!match) continue;

    const token = match[1];
    const paramKey =
      replacements[token] ||
      `${token.charAt(0).toLowerCase()}${token.slice(1)}_id`;

    if (!params.has(paramKey)) {
      params.set(paramKey, value);
    }
  }

  return `${base}?${params.toString()}`;
}

export function resolveEffectiveUrl(
  targetClassicUrlOverride: string | null,
  targetClassicUrl: string
): string {
  if (!targetClassicUrlOverride) return targetClassicUrl;

  const [partialPath, query] = targetClassicUrlOverride.split("?");
  const idx = targetClassicUrl.indexOf(partialPath);

  if (idx >= 0 && targetClassicUrl !== partialPath) {
    const prefix = targetClassicUrl.substring(0, idx);
    return prefix + partialPath + (query ? `?${query}` : "");
  }
  return targetClassicUrlOverride;
}

export function isInteger(value: string): boolean {
  return /^\d+$/.test(value);
}

export async function getTargetClassicUrlBase(
  axios: any
): Promise<string | null> {
  const cached = localStorage.getItem("app.classicURL");
  if (cached) return cached;

  try {
    const response = await axios.get("/solvasam-bff/v1/classicurl");
    const url = response.data;

    if (url) {
      localStorage.setItem("app.classicURL", url);
      return url;
    }

    return null;
  } catch (err) {
    console.error("Failed to fetch classic URL:", err);
    return null;
  }
}

export function listenForModalReturn(
  navigationItems: NavigationItem[],
  detailsNavigationId?: string,
  onReturnCallback?: () => void
): () => void {
  const handler = (e: MessageEvent) => {
    if (e.data?.type === "MODAL_RETURN_VALUE" && detailsNavigationId) {
      const detailsNav = findNavigationItemById(
        navigationItems,
        detailsNavigationId
      );
      if (!detailsNav) return;

      const id = extractIdFromReturnValue(detailsNav.path, e.data.value) ?? "";
      const returnPath = detailsNav.path.replace(/\$[a-zA-Z0-9_.]+/g, id);
      const newHash = `#${returnPath}`;

      const isSameHash = window.location.hash === newHash;

      if (!isSameHash) {
        window.location.hash = newHash;
      } else {
        onReturnCallback?.();
      }
    }
  };

  window.addEventListener("message", handler);

  return () => {
    window.removeEventListener("message", handler);
  };
}

export function listenForModalClose(onReturnCallback?: () => void): () => void {
  const handler = (e: MessageEvent) => {
    if (e.data?.type === "MODAL_CLOSE") {
      onReturnCallback?.();
    }
  };

  window.addEventListener("message", handler);

  return () => {
    window.removeEventListener("message", handler);
  };
}

export function findNavigationItemById(
  items: NavigationItem[],
  id: string
): NavigationItem | null {
  for (const item of items) {
    if (item.id === id) return item;
    if (item.items) {
      const found = findNavigationItemById(item.items, id);
      if (found) return found;
    }
  }
  return null;
}

export function extractIdFromReturnValue(
  path: string,
  returnValue: string
): string | undefined {
  const match = path.match(/\$app\.selected([A-Za-z0-9_]+)/);
  if (!match) return;

  const key = `${match[1].toLowerCase()}_id`;
  const parts = returnValue.split("|");

  for (const part of parts) {
    const [k, v] = part.split(";");
    if (k === key) return v;
  }
}

export async function setIframeContents(
  iframeRef: React.RefObject<HTMLIFrameElement>,
  targetClassicUrl: string,
  targetClassicUrlOverride: string | null,
  axiosFactory: () => Promise<any>,
  contextValues: Record<string, string | null>,
  selectedPortfolioId: string | null,
  interceptedFunctions?: InterceptEntry[],
  setTargetClassicUrlWithParams?: (v: string) => void
): Promise<void> {
  const axios = await axiosFactory();

  const resolvedUrl = resolveEffectiveUrl(
    targetClassicUrlOverride,
    targetClassicUrl
  );

  const result = await loadHtmlIntoIframe(
    iframeRef,
    axios,
    contextValues,
    resolvedUrl,
    selectedPortfolioId,
    interceptedFunctions
  );

  if (result?.targetClassicUrlWithParams && setTargetClassicUrlWithParams) {
    setTargetClassicUrlWithParams(result.targetClassicUrlWithParams);
  }
}

export function logObjectDifferences<T extends Record<string, any>>(
  prev: T | undefined,
  current: T,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  label = "Changed"
): void {
  if (!prev) {
    return;
  }

  Object.keys(current).filter((key) => prev[key] !== current[key]);
}

export function isContextSynced(
  contextValues: Record<string, string | null>,
  hash: string
): boolean {
  const query = hash.includes("?") ? hash.split("?")[1] : "";
  const searchParams = new URLSearchParams(query);

  return Array.from(searchParams.entries()).every(
    ([paramKey, expectedValue]) => {
      const contextKey = contextParamMap.get(paramKey);
      if (!contextKey) return true;
      return contextValues[contextKey] === expectedValue;
    }
  );
}

import { useStaticAppContext } from "@textile/common";
import { useEffect } from "react";
import { Outlet, useParams } from "react-router-dom";
import { isGuid } from "../helpers";

type ValidatorFunction = (value: string) => boolean;

type UrlContextSyncProps<TParam extends string> = {
  contextKey: string;
  paramKey: TParam;
  validator?: ValidatorFunction;
};

export const contextParamMap = new Map<string, string>();

export const UrlContextSync = <TParam extends string>({
  contextKey,
  paramKey,
  validator = isGuid,
}: UrlContextSyncProps<TParam>) => {
  const { sharedAppContextManager } = useStaticAppContext();
  const { state, setState } = sharedAppContextManager.useContext<string | null>(
    contextKey
  );
  const params = useParams();
  const value = params[paramKey];

  useEffect(() => {
    contextParamMap.set(paramKey, contextKey);
  }, [contextKey, paramKey]);

  useEffect(() => {
    if (value && value !== state && (!validator || validator(value))) {
      setState(value);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [value]);

  return <Outlet />;
};

