import { AgGridReactProps, PaginationChangedEvent } from "@textile/ag-grid";
import { DataGrid, DataGridProps } from "@textile/biz-components";
import { FunctionComponent, useState } from "react";
import { DataGridRowCountBar } from "./data-grid-row-count-bar.component";

interface CustomDataGridProps extends DataGridProps {
  showRowCount?: boolean;
}

export const CustomDataGrid: FunctionComponent<CustomDataGridProps> = ({
  showRowCount = false,
  agGridProps,
  ...props
}) => {
  const [rowCount, setRowCount] = useState<number>(0);

  const customAgGridProps: AgGridReactProps = {
    ...(agGridProps ?? {}),
