const shimBox: SxProps<Theme> = {
  flexGrow: 1,
};

interface ViewSourceDialogProps {
  url?: string;
  type?: ActionButtonTypes;
}

const ViewSourceActionDialog: FunctionComponent<ViewSourceDialogProps> = ({
  url,
}) => {
  const { open, closeDialog } = useActionDialog();
  const theme = useTheme();
  return (
    <Dialog
      open={open}
      onClose={closeDialog}
      fullWidth
      PaperProps={{
        sx: getDialogResizePaperPropsSx("md"),
      }}
      draggable={true}
    >
      <DialogTitle height={64} display={"flex"}>
        View Source
        <Box sx={shimBox} />
        <IconButton
          sx={{ color: "#fff" }}
          aria-label="close"
          onClick={closeDialog}
