                whiteSpace: "pre-wrap",
                wordBreak: "break-all",
              }}
              variant="body2"
            >
              {url ?? ""}
            </Typography>
          </fieldset>
        </Box>
      </DialogContent>
    </Dialog>
  );
};

const dataSourceToURL = (datasource: DataGridDataServiceSource) => {
  const pagingParams = datasource.paging
    ? {
        "paging.page_size": datasource.paging.pageSize,
        "paging.start": datasource.paging.start,
        ...(datasource.paging.orderBy
          ? { "paging.order_by": datasource.paging.orderBy }
          : {}),
      }
    : {};

  const queryString = new URLSearchParams({
    ...pagingParams,
    ...datasource.queryParams,
  }).toString();

  return decodeURIComponent(
    `${datasource.url}${queryString ? "?" : ""}${queryString}`.replace(
      /\+/g,
      " "
    )
  );
};
export const ViewCustomSourceActionDialog: FunctionComponent<
  ViewSourceDialogProps
> = ({ url, type = "icon" }) => {
  const isIconType = type === "icon";
