  return (
    <AsyncDialogAction
      dialog={<ViewSourceActionDialog url={url}></ViewSourceActionDialog>}
      actionCode="view_source"
      label="View Source"
      type={type}
      icon={icon}
      loadOnOpen={true}
    ></AsyncDialogAction>
  );
};

