import { useStaticAppContext } from "@textile/common";
import { useCallback, useEffect, useRef } from "react";
import { useParams } from "react-router-dom";

import { Portfolio } from "../components/portfolio-selector/portfolio.types";

export const useSelectedPortfolioId = () => {
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedPortfolio, setState: setSelectedPortfolio } =
    sharedAppContextManager.useContext<string | null>("app.selectedPortfolio");

  const { portfolioId } = useParams<"portfolioId">();
  const portfolioIdRef = useRef(selectedPortfolio);

  useEffect(() => {
    if (
      portfolioId &&
      portfolioId !== "null" &&
      portfolioId !== "undefined" &&
      portfolioId !== portfolioIdRef.current
    ) {
      portfolioIdRef.current = portfolioId;
      setSelectedPortfolio(portfolioId);
    }
  }, [portfolioId, setSelectedPortfolio]);

  const updateSelectedPortfolio = useCallback(
    (newPortfolio: string | Portfolio | null) => {
      const newId =
        typeof newPortfolio === "string" || newPortfolio === null
          ? newPortfolio
          : newPortfolio.id;
      if (newId !== portfolioIdRef.current) {
        portfolioIdRef.current = newId;
        setSelectedPortfolio(newId);
      }
    },
    [setSelectedPortfolio]
  );

  return [selectedPortfolio, updateSelectedPortfolio] as const;
};

import { Typography } from "@textile/mui";
