import { TextileThemeProvider, useStaticAppContext } from "@textile/common";
import { StyledEngineProvider } from "@textile/mui";
import { FunctionComponent } from "react";
import { Outlet } from "react-router-dom";
import { getTheme } from "./theming/theming";

export interface AppProps {
  name: string;
}
export const App: FunctionComponent<AppProps> = () => {
  const { sharedAppContextManager } = useStaticAppContext();

  // Get the current theme selection from the shared context.
  const { state: themeSelection } = sharedAppContextManager.useContext(
    "textile.visuals.theme"
  );

  // Get the current Textile theme using the current selection as key.
  const theme = getTheme(themeSelection);

  return (
    <StyledEngineProvider injectFirst>
      <TextileThemeProvider themeOptions={theme}>
        <Outlet></Outlet>
      </TextileThemeProvider>
    </StyledEngineProvider>
  );
};

